function esc(s) {
  if (typeof s !== 'string') return s;
  return s.replace(/\\/g, '\\\\').replace(/'/g, "\\'").replace(/`/g, '\\`').replace(/\n/g, '\\n').replace(/\r/g, '\\r').replace(/\t/g, '\\t');
}
function q(s) { return "'" + esc(s) + "'"; }
function arr(a) {
  if (!a || a.length === 0) return '[]';
  return '[' + a.map(function(x) { return typeof x === 'string' ? q(x) : JSON.stringify(x); }).join(', ') + ']';
}
var courses = [];
function course(id, title, icon, color, topics) {
  courses.push({ id: id, title: title, icon: icon, color: color, topics: topics });
}
function c(term, difficulty, definition, extras) {
  var obj = { term: term, difficulty: difficulty };
  if (definition) obj.definition = definition;
  if (extras) {
    if (extras.codeExample) obj.codeExample = extras.codeExample;
    if (extras.codeOutput) obj.codeOutput = extras.codeOutput;
    if (extras.keyPoints) obj.keyPoints = extras.keyPoints;
    if (extras.commonMistakes) obj.commonMistakes = extras.commonMistakes;
    if (extras.followUps) obj.followUps = extras.followUps;
    if (extras.compareWith) obj.compareWith = extras.compareWith;
    if (extras.scenario) obj.scenario = extras.scenario;
    if (extras.bugCode) obj.bugCode = extras.bugCode;
    if (extras.bugExplanation) obj.bugExplanation = extras.bugExplanation;
    if (extras.fixedCode) obj.fixedCode = extras.fixedCode;
    if (extras.fixedOutput) obj.fixedOutput = extras.fixedOutput;
    if (extras.realWorld) obj.realWorld = extras.realWorld;
    if (extras.codeExplanation) obj.codeExplanation = extras.codeExplanation;
    if (extras.practice) obj.practice = extras.practice;
    if (extras.systemDesign) obj.systemDesign = extras.systemDesign;
  }
  return obj;
}
var fs = require('fs');
var path = require('path');
var genData = require('./generate-data.cjs');
var courses = genData.courses;
function addC(courseId, topicName, term, difficulty, definition, extras) {
  for (var ci = 0; ci < courses.length; ci++) {
    if (courses[ci].id === courseId) {
      for (var ti = 0; ti < courses[ci].topics.length; ti++) {
        if (courses[ci].topics[ti].name === topicName) {
          courses[ci].topics[ti].concepts.push(c(term, difficulty, definition, extras));
          return;
        }
      }
    }
  }
}
// ========== PYTHON NEW CONCEPTS ==========
addC('python', 'Variables & Data Types', 'Walrus Operator', 'Intermediate', 'Assignment expression (:=) allows assigning values within larger expressions', { codeExample: "if (n := len(data)) > 10:\n    print(f'Large list with {n} items')\n\nwhile (line := file.readline()):\n    print(line)\n\nresults = [y for x in range(10) if (y := x * 2) > 10]", keyPoints: ['Operator := introduced in Python 3.8', 'Assigns and returns value', 'Useful in comprehensions and conditions', 'PEP 572'], commonMistakes: ['Confusing with == equality operator', 'Overusing in simple cases'] })
addC('python', 'Variables & Data Types', 'Type Hints', 'Intermediate', 'Optional type annotations that improve code readability and enable static checking', { codeExample: "def greet(name: str, age: int = 18) -> str:\n    return f'{name} is {age} years old'\n\nfrom typing import List, Optional, Dict, Union\n\ndef process(items: List[int]) -> Dict[str, Optional[int]]:\n    return {'max': max(items) if items else None, 'min': min(items) if items else None}\n\n# Use mypy for static type checking", keyPoints: ['Optional static typing (not enforced at runtime)', 'mypy and pyright for type checking', 'typing module for complex types', 'PEP 484 standard'] })
addC('python', 'Control Flow', 'else in Loops', 'Beginner', 'else block executes when loop completes normally without break', { codeExample: "for n in range(2, 10):\n    for x in range(2, n):\n        if n % x == 0:\n            print(f'{n} equals {x} * {n//x}')\n            break\n    else:\n        print(f'{n} is prime')", keyPoints: ['else runs if no break occurred', 'Works with both for and while loops', 'Useful for search patterns'] })
addC('python', 'Control Flow', 'Ternary Expression', 'Beginner', 'Inline conditional expression for simple if-else logic', { codeExample: "age = 20\nstatus = 'adult' if age >= 18 else 'minor'\n\nx = 10\nresult = 'positive' if x > 0 else 'negative' if x < 0 else 'zero'", keyPoints: ['x if cond else y syntax', 'Can be nested (though less readable)', 'Short-circuits evaluation'] })
addC('python', 'Functions & Scope', 'Positional-Only Parameters', 'Intermediate', 'Parameters that can only be passed positionally, not as keyword arguments', { codeExample: "def divide(a, b, /):\n    return a / b\n\n# divide(10, b=2)  # TypeError!\ndivide(10, 2)  # OK\n\ndef greet(name, /, greeting='Hello', *):\n    print(f'{greeting}, {name}')\n\n# * separates positional-only from keyword-only", keyPoints: ['/ separates positional-only from regular params', 'PEP 570 introduced in Python 3.8', 'Improves API clarity'] })
addC('python', 'Functions & Scope', 'Keyword-Only Arguments', 'Intermediate', 'Arguments that must be specified by keyword, enforced by * separator', { codeExample: "def create_user(name, *, age=None, email=None):\n    return {'name': name, 'age': age, 'email': email}\n\n# create_user('Alice', 30, 'a@b.com')  # TypeError!\ncreate_user('Alice', age=30)  # OK", keyPoints: ['* forces following params to be keyword-only', 'Improves code clarity', 'Prevents positional argument errors'] })
addC('python', 'Data Structures', 'DefaultDict', 'Intermediate', 'Dictionary subclass that calls factory function for missing keys', { codeExample: "from collections import defaultdict\n\n# Group items\nwords = ['apple', 'banana', 'apple', 'cherry', 'banana']\ngroups = defaultdict(list)\nfor w in words:\n    groups[w[0]].append(w)\nprint(dict(groups))  # {'a': ['apple', 'apple'], 'b': ['banana', 'banana'], 'c': ['cherry']}\n\n# Counting\ncounter = defaultdict(int)\nfor c in 'hello world':\n    counter[c] += 1", keyPoints: ['Avoids KeyError for missing keys', 'Takes factory function as argument', 'Common patterns: list, int, set, custom'] })
addC('python', 'Data Structures', 'NamedTuple', 'Intermediate', 'Lightweight immutable data containers with named fields', { codeExample: "from collections import namedtuple\n\nPoint = namedtuple('Point', ['x', 'y'])\np = Point(10, y=20)\nprint(p.x, p.y)  # 10 20\nx, y = p  # unpacking\n\n# Type-annotated variant (Python 3.6+)\nfrom typing import NamedTuple\n\nclass Employee(NamedTuple):\n    name: str\n    id: int\n    salary: float = 50000.0", keyPoints: ['Immutable like tuples', 'Field access by name or index', 'More memory efficient than dict', 'Type annotations with typing.NamedTuple'] })
addC('python', 'OOP in Python', 'Dataclasses', 'Intermediate', 'Decorator that auto-generates __init__, __repr__, __eq__, and more', { codeExample: "from dataclasses import dataclass, field\n\n@dataclass\nclass Person:\n    name: str\n    age: int = 0\n    hobbies: list = field(default_factory=list)\n\np = Person('Alice', 30)\nprint(p)  # Person(name='Alice', age=30, hobbies=[])\n\n# Frozen (immutable) dataclass\n@dataclass(frozen=True)\nclass Config:\n    host: str\n    port: int", keyPoints: ['Reduces boilerplate code', 'Generates __init__, __repr__, __eq__', 'field() for mutable defaults', 'Supports inheritance and nesting'] })
addC('python', 'OOP in Python', 'Slots', 'Advanced', '__slots__ declaration reduces memory by preventing __dict__ creation', { codeExample: "class Point:\n    __slots__ = ('x', 'y')\n    def __init__(self, x, y):\n        self.x = x\n        self.y = y\n\np = Point(1, 2)\n# p.z = 3  # AttributeError!\nprint(p.__slots__)  # ('x', 'y')", keyPoints: ['Reduces memory usage per instance', 'Faster attribute access', 'Prevents adding new attributes', 'Useful for many small objects'] })
addC('python', 'Advanced Python', 'Functools (lru_cache, partial)', 'Intermediate', 'Higher-order functions for caching, partial application, and composition', { codeExample: "from functools import lru_cache, partial, wraps\n\n@lru_cache(maxsize=128)\ndef fib(n):\n    if n <= 1: return n\n    return fib(n-1) + fib(n-2)\n\n# Partial application\ndef power(base, exp):\n    return base ** exp\n\nsquare = partial(power, exp=2)\ncube = partial(power, exp=3)\nprint(square(5))  # 25", keyPoints: ['lru_cache memoizes function results', 'partial creates functions with preset args', 'wraps preserves function metadata'] })
addC('python', 'Advanced Python', 'Enum Classes', 'Intermediate', 'Symbolic enumeration constants with methods and custom values', { codeExample: "from enum import Enum, auto, IntEnum\n\nclass Status(Enum):\n    PENDING = auto()\n    ACTIVE = auto()\n    INACTIVE = auto()\n    DELETED = 'removed'\n\nprint(Status.ACTIVE.name, Status.ACTIVE.value)  # ACTIVE 2\n\nclass HttpStatus(IntEnum):\n    OK = 200\n    NOT_FOUND = 404\n    ERROR = 500", keyPoints: ['Enum with name/value pairs', 'auto() assigns sequential values', 'IntEnum for integer-compatible enums', 'Iterable and hashable'] })
addC('python', 'Advanced Python', 'Metaclasses', 'Advanced', 'Classes that create classes, controlling class creation and behavior', { codeExample: "class SingletonMeta(type):\n    _instances = {}\n    def __call__(cls, *args, **kwargs):\n        if cls not in cls._instances:\n            cls._instances[cls] = super().__call__(*args, **kwargs)\n        return cls._instances[cls]\n\nclass Database(metaclass=SingletonMeta):\n    def __init__(self):\n        print('Connecting...')\n\ndb1 = Database()\ndb2 = Database()\nprint(db1 is db2)  # True", keyPoints: ['Metaclasses are class factories', '__new__ and __init__ on metaclass', 'Common uses: ORMs, singleton, validation'] })
addC('python', 'Advanced Python', 'Pickle & Serialization', 'Intermediate', 'Serializing Python objects to bytes and back', { codeExample: "import pickle\n\ndata = {'users': ['Alice', 'Bob'], 'config': {'debug': True}}\n\n# Serialize\nwith open('data.pkl', 'wb') as f:\n    pickle.dump(data, f)\n\n# Deserialize\nwith open('data.pkl', 'rb') as f:\n    loaded = pickle.load(f)\nprint(loaded)\n\n# JSON alternative\nimport json\njson.dumps(data)", keyPoints: ['pickle handles any Python object', 'Not secure (don\'t unpickle untrusted data)', 'JSON for cross-language interop'] })
// ========== JAVASCRIPT NEW CONCEPTS ==========
addC('javascript', 'Core Concepts', 'IIFE (Immediately Invoked Function Expression)', 'Intermediate', 'Function that executes immediately after definition, creating private scope', { codeExample: '(function() {\n  var privateVar = "secret";\n  window.publicAPI = {\n    getSecret: function() { return privateVar; }\n  };\n})();\n\n// Arrow function IIFE\n(() => {\n  console.log("Runs immediately");\n})();\n\n// With parameters\n((msg) => {\n  console.log(msg);\n})("Hello IIFE");', keyPoints: ['Creates private scope before ES6 modules', 'Prevents global namespace pollution', 'Module pattern basis'] })
addC('javascript', 'Core Concepts', 'Shallow vs Deep Copy', 'Intermediate', 'Copying objects: shallow copies references, deep clones nested objects', { codeExample: 'const original = { a: 1, b: { c: 2 } };\n\n// Shallow copies\nconst spread = { ...original };\nconst assigned = Object.assign({}, original);\n\n// Deep copy (JSON method - loses functions/undefined)\nconst deepJson = JSON.parse(JSON.stringify(original));\n\n// Deep copy (structuredClone - modern)\nconst deepClone = structuredClone(original);\n\n// Custom deep clone\nfunction deepClone(obj) {\n  if (obj === null || typeof obj !== "object") return obj;\n  if (Array.isArray(obj)) return obj.map(deepClone);\n  return Object.fromEntries(\n    Object.entries(obj).map(([k, v]) => [k, deepClone(v)])\n  );\n}', keyPoints: ['Spread/assign are shallow', 'JSON.parse/stringify loses functions', 'structuredClone is native deep clone', 'Mutating nested objects affects shallow copies'] })
addC('javascript', 'Core Concepts', 'Nullish Coalescing (??)', 'Beginner', 'Operator returning right-hand value only when left is null or undefined', { codeExample: 'const value = null ?? "default";  // "default"\nconst zero = 0 ?? 42;  // 0 (not null/undefined)\nconst empty = "" ?? "fallback";  // "" (not null/undefined)\nconst falsey = false ?? true;  // false\n\n// Difference from || (OR)\nconst orResult = 0 || 42;  // 42 (coerces falsy)\nconst nullishResult = 0 ?? 42;  // 0 (only null/undefined)', keyPoints: ['?? only replaces null/undefined', '|| replaces all falsy values', 'Cannot chain with && or || without parens'] })
addC('javascript', 'Core Concepts', 'Optional Chaining (?.)', 'Beginner', 'Safe property access stopping at null/undefined without throwing', { codeExample: 'const user = { profile: { name: "Alice" } };\n\n// Without optional chaining\nconst city = user && user.address && user.address.city;\n\n// With optional chaining\nconst city2 = user?.address?.city;  // undefined\n\n// Dynamic property\nconst prop = "name";\nconst name = user?.profile?.[prop];\n\n// Optional call\nconst result = obj.method?.();  // undefined if method missing\n\n// With nullish coalescing\nconst city3 = user?.address?.city ?? "Unknown";', keyPoints: ['?. short-circuits on null/undefined', 'Works with property access, calls, dynamic', 'Combine with ?? for defaults'] })
addC('javascript', 'DOM & Browser APIs', 'MutationObserver', 'Intermediate', 'Watching DOM changes: child nodes, attributes, subtree mutations', { codeExample: 'const target = document.getElementById("container");\n\nconst observer = new MutationObserver((mutations) => {\n  mutations.forEach(mutation => {\n    if (mutation.type === "childList") {\n      console.log("Nodes added:", mutation.addedNodes.length);\n    }\n    if (mutation.type === "attributes") {\n      console.log("Attribute changed:", mutation.attributeName);\n    }\n  });\n});\n\nobserver.observe(target, {\n  childList: true,\n  attributes: true,\n  subtree: true\n});\n\nobserver.disconnect();', keyPoints: ['Efficient DOM change detection', 'Alternatives: DOMSubtreeModified (deprecated)', 'Performance: debounce handler'] })
addC('javascript', 'DOM & Browser APIs', 'ResizeObserver', 'Intermediate', 'Observing element size changes for responsive components', { codeExample: 'const element = document.querySelector(".resizable");\n\nconst observer = new ResizeObserver((entries) => {\n  for (const entry of entries) {\n    const { width, height } = entry.contentBoxSize[0];\n    console.log(Element is now px x px);\n  }\n});\n\nobserver.observe(element);\n\n// Clean up\nobserver.disconnect();', keyPoints: ['Better than window.resize for elements', 'Reports content box / border box sizes', 'Useful for custom responsive components'] })
addC('javascript', 'Async JavaScript', 'AbortController', 'Intermediate', 'Canceling fetch requests and event listeners when no longer needed', { codeExample: 'const controller = new AbortController();\nconst signal = controller.signal;\n\nasync function fetchWithTimeout(url, timeoutMs = 5000) {\n  const timeoutId = setTimeout(() => controller.abort(), timeoutMs);\n  try {\n    const response = await fetch(url, { signal });\n    return await response.json();\n  } catch (err) {\n    if (err.name === "AbortError") {\n      console.log("Request was aborted");\n    } else {\n      throw err;\n    }\n  } finally {\n    clearTimeout(timeoutId);\n  }\n}\n\n// Abort multiple requests with same signal\nconst urls = ["/api/a", "/api/b", "/api/c"];\nconst requests = urls.map(url => fetch(url, { signal }));\nsetTimeout(() => controller.abort(), 2000);', keyPoints: ['AbortController pairs with AbortSignal', 'Works with fetch, event listeners, streams', 'aborted property to check state'] })
addC('javascript', 'ES6+ Features', 'Map & Set', 'Intermediate', 'ES6 collection types: ordered key-value map and unique value set', { codeExample: 'const map = new Map();\nmap.set("key", "value");\nmap.set(42, "number key");\nmap.set({}, "object key");\nconsole.log(map.get("key"));\nconsole.log(map.has(42));\nconsole.log(map.size);\n\nconst set = new Set([1, 2, 2, 3, 3, 4]);\nconsole.log([...set]);  // [1, 2, 3, 4]\nset.add(5);\nset.delete(1);\nconsole.log(set.has(2));\n\n// WeakMap/WeakSet (no memory leaks)\nconst wm = new WeakMap();\nlet obj = {};\nwm.set(obj, "private data");\nobj = null;  // entry can be GC\'d', keyPoints: ['Map preserves insertion order', 'Set stores unique values', 'WeakMap/WeakSet: keys are objects, no prevent GC', 'Map/Set have O(1) access'] })
addC('javascript', 'ES6+ Features', 'Promise Combinators', 'Intermediate', 'Methods for coordinating multiple promises: all, race, allSettled, any', { codeExample: 'const p1 = fetch("/api/a").then(r => r.json());\nconst p2 = fetch("/api/b").then(r => r.json());\nconst p3 = fetch("/api/c").then(r => r.json());\n\n// All (fail fast)\nconst all = await Promise.all([p1, p2, p3]);\n\n// All Settled (wait for all, get status)\nconst settled = await Promise.allSettled([p1, p2, p3]);\n// [{status:"fulfilled", value:...}, {status:"rejected", reason:...}]\n\n// Race (first to settle)\nconst first = await Promise.race([p1, p2, p3]);\n\n// Any (first fulfilled, ignore rejections)\nconst any = await Promise.any([p1, p2, p3]);\n// AggregateError if all reject', keyPoints: ['Promise.all: fail fast', 'Promise.allSettled: no fail', 'Promise.race: first settle wins', 'Promise.any: first fulfill wins'] })
addC('javascript', 'Advanced JavaScript', 'WeakRef & FinalizationRegistry', 'Advanced', 'Holding weak references to objects and cleanup callbacks after GC', { codeExample: '// WeakRef - hold reference without preventing GC\nlet target = { data: "important" };\nconst ref = new WeakRef(target);\n\n// Later\nconst obj = ref.deref();\nif (obj) {\n  console.log(obj.data);\n} else {\n  console.log("Target was garbage collected");\n}\n\n// FinalizationRegistry - cleanup after GC\nconst registry = new FinalizationRegistry((heldValue) => {\n  console.log("Cleanup for:", heldValue);\n});\n\nlet resource = { name: "resource" };\nregistry.register(resource, "resource-key");\nresource = null;  // May trigger cleanup when GC runs', keyPoints: ['WeakRef.deref() returns target or undefined', 'FinalizationRegistry for resource cleanup', 'Use sparingly - GC timing is unpredictable'] })
addC('javascript', 'Advanced JavaScript', 'Atomics & SharedArrayBuffer', 'Advanced', 'Shared memory between workers with atomic operations', { codeExample: '// main.js\nconst buffer = new SharedArrayBuffer(4);\nconst view = new Int32Array(buffer);\nAtomics.store(view, 0, 0);\n\nconst worker = new Worker("worker.js");\nworker.postMessage(buffer);\n\nworker.onmessage = () => {\n  console.log(Atomics.load(view, 0));  // 42\n};\n\n// worker.js (self.onmessage)\nself.onmessage = (e) => {\n  const view = new Int32Array(e.data);\n  Atomics.store(view, 0, 42);\n  Atomics.notify(view, 0);  // wake main thread\n  self.postMessage("done");\n};', keyPoints: ['SharedArrayBuffer for shared memory', 'Atomics for thread-safe operations', 'Requires cross-origin isolation headers', 'Low-level, use with caution'] })
addC('javascript', 'Node.js Basics', 'Cluster Module', 'Intermediate', 'Creating child processes that share server ports for multi-core usage', { codeExample: 'const cluster = require("cluster");\nconst http = require("http");\nconst os = require("os");\n\nif (cluster.isMaster) {\n  const numCPUs = os.cpus().length;\n  console.log(Master  forking  workers);\n\n  for (let i = 0; i < numCPUs; i++) {\n    cluster.fork();\n  }\n\n  cluster.on("exit", (worker) => {\n    console.log(Worker  died, restarting);\n    cluster.fork();\n  });\n} else {\n  http.createServer((req, res) => {\n    res.writeHead(200);\n    res.end(Handled by \\n);\n  }).listen(8000);\n}', keyPoints: ['Round-robin load balancing on Windows', 'Master-worker architecture', 'Zero-downtime restarts', 'IPC between master and workers'] })
addC('javascript', 'Node.js Basics', 'Environment Variables & dotenv', 'Beginner', 'Managing configuration via environment variables', { codeExample: '// .env file\nPORT=3000\nDB_URL=mongodb://localhost:27017\nNODE_ENV=development\n\n// Using dotenv\nrequire("dotenv").config();\n\nconst express = require("express");\nconst app = express();\nconst port = process.env.PORT || 3000;\n\n// Validation\nconst requiredEnvVars = ["DB_URL", "JWT_SECRET"];\nrequiredEnvVars.forEach(name => {\n  if (!process.env[name]) {\n    console.error(Missing required env var: );\n    process.exit(1);\n  }\n});\n\napp.listen(port, () => {\n  console.log(Server running in  on port );\n});', keyPoints: ['process.env for runtime access', '.env files for development', 'Never commit .env to git', 'Validate required vars at startup'] })
