addC('java', 'Core Java', 'Annotations', 'Intermediate', 'Metadata added to code processed at compile-time or runtime via reflection', { codeExample: '@Override\n@SuppressWarnings("unchecked")\n@Deprecated(since = "2.0", forRemoval = true)\n\n// Custom annotation\n@Retention(RetentionPolicy.RUNTIME)\n@Target(ElementType.METHOD)\npublic @interface LogExecution {\n    String value() default "";\n}\n\npublic class Service {\n    @LogExecution("fetchUser")\n    public User getUser(int id) { return new User(id); }\n}', keyPoints: ['@Override, @Deprecated, @SuppressWarnings', 'Custom annotations with @interface', 'Retention: SOURCE, CLASS, RUNTIME', 'Processed via reflection or annotation processors'] })
addC('java', 'Core Java', 'Generics & Type Erasure', 'Intermediate', 'Type parameters for compile-time safety, erased at runtime', { codeExample: 'public class Box<T> {\n    private T item;\n    public void set(T item) { this.item = item; }\n    public T get() { return item; }\n}\n\n// Bounded type parameters\npublic <T extends Comparable<T>> T max(T a, T b) {\n    return a.compareTo(b) > 0 ? a : b;\n}\n\n// Wildcards\nList<? extends Number> numbers;  // read-only\nList<? super Integer> integers;  // write-only\n\n// Type erasure: Box<String> becomes Box at runtime\n// Bridge methods generated for polymorphism', keyPoints: ['Compile-time safety, runtime Object', '? extends for covariance, ? super for contravariance', 'Type erasure removes parameterized types', 'Reifiable types vs non-reifiable'] })
addC('java', 'Collections Framework', 'PriorityQueue & Deque', 'Intermediate', 'PriorityQueue orders by natural/comparator order; Deque supports both ends', { codeExample: '// Min-heap (natural order)\nPriorityQueue<Integer> pq = new PriorityQueue<>();\npq.add(30); pq.add(10); pq.add(20);\nSystem.out.println(pq.poll());  // 10\n\n// Max-heap with Comparator\nPriorityQueue<Integer> maxHeap = new PriorityQueue<>(Comparator.reverseOrder());\n\n// Deque (ArrayDeque preferred over Stack)\nDeque<String> stack = new ArrayDeque<>();\nstack.push("first"); stack.push("second");\nSystem.out.println(stack.pop());  // second\n\nDeque<String> queue = new ArrayDeque<>();\nqueue.addLast("first"); queue.addLast("second");\nSystem.out.println(queue.removeFirst());  // first', keyPoints: ['PriorityQueue: heap-based, O(log n) insert/poll', 'ArrayDeque: faster than Stack and LinkedList', 'Deque supports LIFO and FIFO operations'] })
addC('java', 'Concurrency', 'ForkJoinPool', 'Advanced', 'Work-stealing thread pool for divide-and-conquer parallel tasks', { codeExample: 'public class SumTask extends RecursiveTask<Long> {\n    private final long[] arr; private final int lo, hi;\n    private static final int THRESHOLD = 1000;\n\n    public SumTask(long[] arr, int lo, int hi) {\n        this.arr = arr; this.lo = lo; this.hi = hi;\n    }\n\n    @Override\n    protected Long compute() {\n        if (hi - lo <= THRESHOLD) {\n            long sum = 0;\n            for (int i = lo; i < hi; i++) sum += arr[i];\n            return sum;\n        }\n        int mid = (lo + hi) / 2;\n        SumTask left = new SumTask(arr, lo, mid);\n        SumTask right = new SumTask(arr, mid, hi);\n        left.fork();\n        return right.compute() + left.join();\n    }\n}\n\nForkJoinPool pool = ForkJoinPool.commonPool();\nlong sum = pool.invoke(new SumTask(arr, 0, arr.length));', keyPoints: ['RecursiveTask (returns result) and RecursiveAction (void)', 'Work-stealing: idle threads steal from busy ones', 'Common pool available by default', 'Best for CPU-intensive recursive tasks'] })
addC('java', 'JVM & Memory', 'Performance Tuning Flags', 'Advanced', 'Common JVM flags for GC tuning, heap sizing, and diagnostics', { codeExample: '// Heap sizing\n-Xms4g -Xmx4g  // initial and max heap\n-Xss1m         // stack size per thread\n-XX:MaxMetaspaceSize=256m\n\n// GC selection\n-XX:+UseG1GC              // default since Java 9\n-XX:+UseZGC               // low-latency (Java 15+)\n-XX:+UseShenandoahGC      // concurrent compaction\n\n// GC tuning\n-XX:MaxGCPauseMillis=100\n-XX:G1HeapRegionSize=4m\n-XX:ConcGCThreads=4\n\n// Diagnostics\n-XX:+PrintGCDetails -Xlog:gc*\n-XX:+HeapDumpOnOutOfMemoryError\n-XX:HeapDumpPath=/tmp/dump.hprof', keyPoints: ['Xms=Xmx prevents resizing overhead', 'G1GC is default, ZGC for sub-ms pauses', 'GC logs essential for tuning', 'Heap dump for OOM analysis'] })
addC('java', 'Modern Java (8+)', 'CompletableFuture', 'Intermediate', 'Asynchronous programming with composable futures and non-blocking operations', { codeExample: 'CompletableFuture<User> userFuture = CompletableFuture\n    .supplyAsync(() -> fetchUser(id))\n    .thenApply(user -> {\n        user.setLastAccess(LocalDateTime.now());\n        return user;\n    })\n    .exceptionally(ex -> {\n        log.error("Failed", ex);\n        return User.DEFAULT;\n    });\n\n// Combine multiple futures\nCompletableFuture<User> user = getUser(id);\nCompletableFuture<Address> address = getAddress(id);\n\nCompletableFuture<UserProfile> profile = user\n    .thenCombine(address, (u, a) -> new UserProfile(u, a));\n\n// Wait for all\nCompletableFuture.allOf(f1, f2, f3).join();\n\n// Custom thread pool\nExecutor pool = Executors.newFixedThreadPool(10);\nCompletableFuture.supplyAsync(() -> task(), pool);', keyPoints: ['supplyAsync/runAsync for async execution', 'thenApply/thenCompose for chaining', 'thenCombine for merging results', 'exceptionally/handle for error handling'] })
addC('java', 'I/O & NIO', 'Serialization', 'Intermediate', 'Converting objects to byte streams for persistence or network transfer', { codeExample: '// Serializable marker interface\npublic class User implements Serializable {\n    private static final long serialVersionUID = 1L;\n    private String name;\n    private transient String password;  // not serialized\n    private int age;\n}\n\n// Serialize\nObjectOutputStream oos = new ObjectOutputStream(new FileOutputStream("user.ser"));\noos.writeObject(user);\noos.close();\n\n// Deserialize\nObjectInputStream ois = new ObjectInputStream(new FileInputStream("user.ser"));\nUser loaded = (User) ois.readObject();\nois.close();\n\n// Externalizable for custom serialization\npublic class CustomUser implements Externalizable {\n    public void writeExternal(ObjectOutput out) { }\n    public void readExternal(ObjectInput in) { }\n}', keyPoints: ['serialVersionUID for version control', 'transient skips serialization', 'Externalizable for custom format', 'JSON/XML alternatives are human-readable'] })
// ========== REACT NEW CONCEPTS ==========
addC('react', 'Core React', 'Error Boundaries', 'Intermediate', 'Class components that catch JavaScript errors in their child tree', { codeExample: 'class ErrorBoundary extends React.Component {\n  constructor(props) {\n    super(props);\n    this.state = { hasError: false, error: null };\n  }\n\n  static getDerivedStateFromError(error) {\n    return { hasError: true, error };\n  }\n\n  componentDidCatch(error, errorInfo) {\n    logErrorToService(error, errorInfo);\n  }\n\n  render() {\n    if (this.state.hasError) {\n      return <h1>Something went wrong</h1>;\n    }\n    return this.props.children;\n  }\n}\n\n// Usage\n<ErrorBoundary>\n  <MyComponent />\n</ErrorBoundary>', keyPoints: ['Only class components can be boundaries', 'Catches render, lifecycle, constructor errors', 'Does not catch event handler errors', 'Place strategically in component tree'] })
addC('react', 'Core React', 'Portals', 'Intermediate', 'Rendering children into a different DOM subtree outside parent component', { codeExample: 'import { createPortal } from "react-dom";\n\nfunction Modal({ isOpen, onClose, children }) {\n  if (!isOpen) return null;\n\n  return createPortal(\n    <div className="modal-overlay">\n      <div className="modal-content">\n        <button onClick={onClose}>Close</button>\n        {children}\n      </div>\n    </div>,\n    document.getElementById("modal-root")\n  );\n}\n\nfunction App() {\n  const [open, setOpen] = useState(false);\n  return (\n    <div>\n      <button onClick={() => setOpen(true)}>Open Modal</button>\n      <Modal isOpen={open} onClose={() => setOpen(false)}>\n        <p>This renders in a portal</p>\n      </Modal>\n    </div>\n  );\n}', keyPoints: ['Portal children maintain React context', 'Useful for modals, tooltips, dropdowns', 'Events bubble through React tree, not DOM tree'] })
addC('react', 'Hooks', 'useImperativeHandle', 'Advanced', 'Customizing the instance value exposed to parent components via ref', { codeExample: 'import { forwardRef, useImperativeHandle, useRef } from "react";\n\nconst FancyInput = forwardRef((props, ref) => {\n  const inputRef = useRef(null);\n\n  useImperativeHandle(ref, () => ({\n    focus: () => {\n      inputRef.current.focus();\n    },\n    scrollTo: (x, y) => {\n      inputRef.current.scrollTo(x, y);\n    },\n    getValue: () => {\n      return inputRef.current.value;\n    }\n  }));\n\n  return <input ref={inputRef} {...props} />;\n});\n\n// Parent usage\nfunction Parent() {\n  const ref = useRef(null);\n\n  useEffect(() => {\n    ref.current?.focus();\n  }, []);\n\n  return <FancyInput ref={ref} />;\n}', keyPoints: ['Limits what parent can access via ref', 'Common for library component APIs', 'Works with forwardRef'] })
addC('react', 'Hooks', 'useDebugValue', 'Advanced', 'Displaying custom label for custom hooks in React DevTools', { codeExample: 'import { useDebugValue, useState } from "react";\n\nfunction useOnlineStatus() {\n  const [isOnline, setIsOnline] = useState(navigator.onLine);\n\n  useDebugValue(isOnline ? "Online" : "Offline");\n\n  useEffect(() => {\n    const handleOnline = () => setIsOnline(true);\n    const handleOffline = () => setIsOnline(false);\n    window.addEventListener("online", handleOnline);\n    window.addEventListener("offline", handleOffline);\n    return () => {\n      window.removeEventListener("online", handleOnline);\n      window.removeEventListener("offline", handleOffline);\n    };\n  }, []);\n\n  return isOnline;\n}', keyPoints: ['Shows in React DevTools hook inspector', 'Only called when DevTools is active', 'Can accept formatting function'] })
addC('react', 'State Management', 'Context Performance Patterns', 'Advanced', 'Avoiding unnecessary re-renders with context splitting and memoization', { codeExample: '// Split context to avoid re-renders\nconst ThemeContext = createContext("light");\nconst UserContext = createContext({ name: "" });\n\nfunction App() {\n  const [theme, setTheme] = useState("light");\n  const [user, setUser] = useState({ name: "Alice" });\n\n  return (\n    <ThemeContext.Provider value={theme}>\n      <UserContext.Provider value={user}>\n        <MainContent />\n      </UserContext.Provider>\n    </ThemeContext.Provider>\n  );\n}\n\n// Or: memoize context value\nfunction App() {\n  const [count, setCount] = useState(0);\n  const theme = useMemo(() => ({ mode: count > 10 ? "dark" : "light" }), [count > 10]);\n\n  return (\n    <ThemeContext.Provider value={theme}>\n      <ExpensiveChild />\n    </ThemeContext.Provider>\n  );\n}', keyPoints: ['Split large contexts into smaller ones', 'Memoize context values to prevent re-renders', 'Consider state management libraries for complex state'] })
addC('react', 'Performance', 'Windowing with react-window', 'Advanced', 'Virtualization library for efficiently rendering large lists', { codeExample: 'import { FixedSizeList as List } from "react-window";\n\nfunction VirtualList({ items }) {\n  const Row = ({ index, style }) => (\n    <div style={style}>\n      {items[index].name} - {items[index].description}\n    </div>\n  );\n\n  return (\n    <List\n      height={600}\n      itemCount={items.length}\n      itemSize={50}\n      width="100%"\n    >\n      {Row}\n    </List>\n  );\n}\n\n// Variable size items\nimport { VariableSizeList } from "react-window";\n\nfunction VariableList({ items }) {\n  const getSize = (index) => items[index].lines * 20;\n  return (\n    <VariableSizeList height={600} itemCount={items.length} itemSize={getSize}>\n      {Row}\n    </VariableSizeList>\n  );\n}', keyPoints: ['FixedSizeList for uniform items', 'VariableSizeList for dynamic sizes', 'AutoSizer for responsive width/height', '100,000+ items at 60fps'] })
addC('react', 'Performance', 'Server Components (RSC)', 'Advanced', 'React components that run on the server, reducing client bundle size', { codeExample: '// Server Component (runs on server, no client JS)\n// NoteList.server.js\nimport db from "db.server";\n\nexport default async function NoteList() {\n  const notes = await db.notes.findMany();\n\n  return (\n    <ul>\n      {notes.map(note => (\n        <li key={note.id}>\n          <h2>{note.title}</h2>\n          <p>{note.body.slice(0, 100)}...</p>\n        </li>\n      ))}\n    </ul>\n  );\n}\n\n// Client Component (interactive, \"use client\")\n// LikeButton.client.js\n"use client";\nimport { useState } from "react";\n\nexport default function LikeButton({ id }) {\n  const [liked, setLiked] = useState(false);\n  return <button onClick={() => setLiked(!liked)}>{liked ? "Unlike" : "Like"}</button>;\n}', keyPoints: ['Zero client JS for server components', 'Can access databases/files directly', 'Cannot use hooks or browser APIs', 'Compose with client components for interactivity'] })
// ========== SQL NEW CONCEPTS ==========
addC('sql', 'Query Fundamentals', 'DISTINCT & LIMIT', 'Beginner', 'Remove duplicates with DISTINCT and restrict rows with LIMIT', { codeExample: 'SELECT DISTINCT department_id FROM employees;\n\nSELECT DISTINCT city, state FROM customers;\n\nSELECT * FROM orders ORDER BY total DESC LIMIT 10;\n\nSELECT * FROM products LIMIT 5 OFFSET 10;  -- pagination', keyPoints: ['DISTINCT applies to all selected columns', 'LIMIT with OFFSET for pagination', 'ORDER BY required for consistent pagination'] })
addC('sql', 'Query Fundamentals', 'CASE Expressions', 'Intermediate', 'Conditional logic in SQL queries similar to if-else', { codeExample: "SELECT name, salary,\n    CASE\n        WHEN salary < 30000 THEN 'Low'\n        WHEN salary BETWEEN 30000 AND 80000 THEN 'Medium'\n        WHEN salary > 80000 THEN 'High'\n        ELSE 'Unknown'\n    END AS salary_level\nFROM employees;\n\n-- Simple CASE\nSELECT name,\n    CASE department\n        WHEN 'Engineering' THEN 'Tech'\n        WHEN 'Sales' THEN 'Revenue'\n        ELSE 'Other'\n    END AS category\nFROM employees;", keyPoints: ['Searched CASE with boolean conditions', 'Simple CASE with exact match', 'Can be used in SELECT, WHERE, ORDER BY', 'First matching WHEN wins'] })
addC('sql', 'Advanced Queries', 'EXISTS vs IN', 'Intermediate', 'Subquery existence check vs membership test with performance implications', { codeExample: '-- EXISTS (often faster for large subquery)\nSELECT d.name\nFROM departments d\nWHERE EXISTS (\n    SELECT 1 FROM employees e\n    WHERE e.dept_id = d.id AND e.salary > 100000\n);\n\n-- IN (may be slower for large subquery)\nSELECT name FROM employees\nWHERE department_id IN (\n    SELECT id FROM departments WHERE active = 1\n);\n\n-- NOT EXISTS vs NOT IN (NULL handling!)\n-- NOT IN returns empty if subquery has NULL\nSELECT name FROM employees\nWHERE department_id NOT IN (\n    SELECT id FROM departments WHERE id IS NOT NULL\n);\n-- Better:\nSELECT name FROM employees e\nWHERE NOT EXISTS (\n    SELECT 1 FROM departments d WHERE d.id = e.department_id\n);', keyPoints: ['EXISTS short-circuits on first match', 'IN subquery evaluated fully', 'NOT IN has NULL pitfall', 'EXISTS often faster for correlated subqueries'] })
addC('sql', 'Optimization & Indexing', 'Covering Index', 'Advanced', 'Index that contains all columns needed by a query, avoiding table lookups', { codeExample: '-- Query:\nSELECT email, name FROM users WHERE status = "active" ORDER BY created_at DESC;\n\n-- Without covering index: index lookup + table access\n-- With covering index: only index access\nCREATE INDEX idx_covering ON users(status, created_at DESC, email, name);\n\n-- Check with EXPLAIN: "Using index" means covering\nEXPLAIN SELECT email, name FROM users WHERE status = "active";\n\n-- INCLUDE columns (PostgreSQL, SQL Server 2012+)\nCREATE INDEX idx_cover ON users(status) INCLUDE (email, name);\n-- Non-key columns stored in leaf but not in b-tree', keyPoints: ['All query columns in index = no table access', 'INCLUDE adds non-key columns', 'Trade-off: more index storage for faster reads', 'EXPLAIN shows "Using index" for covering'] })
addC('sql', 'Administration', 'VACUUM & ANALYZE', 'Advanced', 'PostgreSQL maintenance: VACUUM reclaims space, ANALYZE updates statistics', { codeExample: '-- VACUUM: reclaim storage, prevent transaction ID wraparound\nVACUUM;  -- standard (doesn\'t lock)\nVACUUM FULL;  -- reclaims space to OS (locks table)\nVACUUM ANALYZE;  -- vacuum + update statistics\n\n-- ANALYZE: update query planner statistics\nANALYZE;\nANALYZE users;\n\n-- Auto-vacuum (PostgreSQL)\n-- Configured in postgresql.conf\n-- autovacuum = on\n-- autovacuum_vacuum_threshold = 50\n-- autovacuum_vacuum_scale_factor = 0.2\n\n-- Check table bloat\nSELECT schemaname, tablename, n_dead_tup\nFROM pg_stat_user_tables\nWHERE n_dead_tup > 1000\nORDER BY n_dead_tup DESC;', keyPoints: ['VACUUM marks dead space as reusable', 'VACUUM FULL rewrites entire table', 'ANALYZE helps optimizer choose good plans', 'Auto-vacuum handles routine maintenance'] })
// ========== HTML NEW CONCEPTS ==========
addC('html', 'HTML Basics', 'Data Attributes', 'Beginner', 'Custom data-* attributes for storing extra information on HTML elements', { codeExample: '<article\n  id="post-123"\n  data-id="123"\n  data-author="alice"\n  data-published="2024-01-15"\n  data-tags=\'["javascript","html"]\'>\n  <h2>Article Title</h2>\n</article>\n\n<script>\n  const article = document.getElementById("post-123");\n  console.log(article.dataset.id);  // "123"\n  console.log(article.dataset.author);  // "alice"\n  console.log(JSON.parse(article.dataset.tags));  // ["javascript","html"]\n</script>', keyPoints: ['dataset property accesses data-* attributes', 'camelCase in JS maps to kebab-case in HTML', 'Values are strings (parse if needed)', 'Useful for attaching data to DOM elements'] })
addC('html', 'Accessibility & SEO', 'Keyboard Navigation', 'Intermediate', 'Ensuring all interactive elements are keyboard accessible', { codeExample: '<nav aria-label="Main navigation">\n  <ul>\n    <li><a href="/">Home</a></li>\n    <li><a href="/about">About</a></li>\n  </ul>\n</nav>\n\n<!-- tabindex for custom ordering -->\n<button tabindex="1">First</button>\n<button tabindex="2">Second</button>\n\n<!-- tabindex="0" makes element focusable in natural order -->\n<div tabindex="0" role="button" @keydown.enter="activate">\n  Custom Button\n</div>\n\n<!-- Skip navigation link -->\n<a href="#main-content" class="skip-link">Skip to main content</a>\n\n<main id="main-content">\n  <!-- main content -->\n</main>\n\n<style>\n  .skip-link { position: absolute; left: -9999px; }\n  .skip-link:focus { position: static; }\n</style>', keyPoints: ['All interactive elements must be reachable via Tab', 'Visible focus indicators required', 'Skip links for efficient navigation', 'tabindex values: -1 (programmatic), 0 (natural), positive (custom)'] })
addC('html', 'Modern HTML Features', 'Template & Slot', 'Advanced', 'HTML template element with slots for reusable, customizable components', { codeExample: '<template id="user-card-template">\n  <style>\n    .card { border: 1px solid #ddd; padding: 1rem; border-radius: 8px; }\n    .name { font-size: 1.2em; font-weight: bold; }\n  </style>\n  <div class="card">\n    <div class="name"><slot name="username">User</slot></div>\n    <div class="email"><slot name="email">Email not provided</slot></div>\n    <slot></slot>\n  </div>\n</template>\n\n<!-- Usage -->\n<user-card>\n  <span slot="username">Alice Johnson</span>\n  <span slot="email">alice@example.com</span>\n  <p>Additional content in default slot</p>\n</user-card>\n\n<script>\n  customElements.define("user-card", class extends HTMLElement {\n    constructor() {\n      super();\n      const template = document.getElementById("user-card-template");\n      this.attachShadow({ mode: "open" })\n        .appendChild(template.content.cloneNode(true));\n    }\n  });\n</script>', keyPoints: ['<template> holds inert markup', '<slot> provides customization points', 'Named slots for specific content placement', 'Default slot for fallback content'] })
// ========== CSS NEW CONCEPTS ==========
addC('css', 'Layout', 'Multi-Column Layout', 'Intermediate', 'Splitting content into multiple columns like newspaper layout', { codeExample: '.article {\n  column-count: 3;\n  column-gap: 2rem;\n  column-rule: 1px solid #ccc;\n  column-width: 300px;  /* responsive */\n}\n\n/* Span across columns */\nh1 {\n  column-span: all;\n}\n\n/* Prevent break inside */\n.card {\n  break-inside: avoid;\n}\n\n/* Shorthand */\n.container {\n  columns: 3 300px;\n}', keyPoints: ['column-count for fixed number', 'column-width for responsive columns', 'column-span for headings', 'break-inside to control breaks'] })
addC('css', 'Layout', 'Aspect Ratio Boxes', 'Beginner', 'Maintaining consistent aspect ratio for responsive elements', { codeExample: '.aspect-ratio-16-9 {\n  aspect-ratio: 16 / 9;\n}\n\n.aspect-ratio-1-1 {\n  aspect-ratio: 1;\n}\n\n/* Responsive image */\nimg {\n  width: 100%;\n  aspect-ratio: 4 / 3;\n  object-fit: cover;\n}\n\n/* Fallback (padding hack) */\n.video-wrapper {\n  position: relative;\n  padding-top: 56.25%;  /* 9/16 * 100 */\n}\n.video-wrapper iframe {\n  position: absolute;\n  top: 0; left: 0; width: 100%; height: 100%;\n}', keyPoints: ['aspect-ratio property native support', 'object-fit for image sizing within ratio', 'Padding hack for legacy browsers', 'Common ratios: 16:9, 4:3, 1:1'] })
addC('css', 'Styling & Effects', 'Filter & Backdrop-Filter', 'Intermediate', 'Applying visual effects like blur, grayscale, and brightness to elements', { codeExample: '.blurred {\n  filter: blur(5px);\n}\n\n.grayscale {\n  filter: grayscale(100%);\n  transition: filter 0.3s;\n}\n.grayscale:hover {\n  filter: grayscale(0%);\n}\n\n/* Backdrop filter (glassmorphism) */\n.glass {\n  background: rgba(255, 255, 255, 0.1);\n  backdrop-filter: blur(10px);\n  -webkit-backdrop-filter: blur(10px);\n  border-radius: 16px;\n  box-shadow: 0 4px 30px rgba(0, 0, 0, 0.1);\n}\n\n/* Multiple filters */\n.image {\n  filter: brightness(1.2) contrast(1.1) saturate(1.3);\n}', keyPoints: ['filter affects entire element', 'backdrop-filter affects background behind element', 'GPU accelerated', 'Support varies for backdrop-filter'] })
addC('css', 'Advanced CSS', 'Scroll Snap', 'Intermediate', 'Controlling scroll behavior to snap to specific positions', { codeExample: '.scroll-container {\n  scroll-snap-type: y mandatory;\n  overflow-y: scroll;\n  height: 100vh;\n}\n\n.section {\n  scroll-snap-align: start;\n  height: 100vh;\n  scroll-snap-stop: always;\n}\n\n/* Horizontal snap */\n.horizontal-scroll {\n  display: flex;\n  overflow-x: auto;\n  scroll-snap-type: x proximity;\n}\n\n.horizontal-scroll > .item {\n  scroll-snap-align: center;\n  flex: 0 0 80vw;\n}', keyPoints: ['scroll-snap-type: x/y/both', 'scroll-snap-align: start/center/end', 'mandatory vs proximity', 'scroll-snap-stop for forced stops'] })
// ========== GIT NEW CONCEPTS ==========
addC('git', 'Version Control', '.gitignore', 'Beginner', 'Specifies intentionally untracked files to ignore in Git', { codeExample: '# Dependencies\nnode_modules/\nvendor/\n\n# Build output\ndist/\n*.js.map\n\n# Environment files\n.env\n.env.local\n*.env\n\n# OS files\n.DS_Store\nThumbs.db\n\n# Logs\n*.log\n\n# IDE\n.idea/\n.vscode/\n*.swp\n\n# Use patterns\n!important.log  # unignore specific file\nlog/*.log       # only log directory\n**/build/       # nested directories', keyPoints: ['Pattern matching with glob', 'Prevents accidental commits of generated files', 'Can have nested .gitignore files', 'Use git rm --cached to stop tracking already-tracked files'] })
addC('git', 'Advanced Git', 'Bisect', 'Advanced', 'Binary search through commit history to find which commit introduced a bug', { codeExample: '# Start bisect\ngit bisect start\ngit bisect bad        # current commit is bad\ngit bisect good v1.0  # known good version\n\n# Git checks out middle commit\n# Test if current commit has the bug\n# Mark:\ngit bisect good       # if no bug\ngit bisect bad        # if bug present\n\n# Git narrows down until first bad commit found\n# Output: abc1234 is the first bad commit\n\n# Automation\n# git bisect run npm test\n# Runs the command, uses exit code to determine good/bad\n\n# Visualize\n# git bisect log\n# git bisect visualize\n\n# Reset when done\ngit bisect reset', keyPoints: ['Binary search O(log n) steps', 'Automate with git bisect run', 'Useful for regression hunting', 'Can also find fix with good/bad reversed'] })
addC('git', 'Collaboration', 'Forking Workflow', 'Beginner', 'Contributing to projects by forking, cloning, and submitting PRs', { codeExample: '# 1. Fork on GitHub (click Fork button)\n\n# 2. Clone your fork\ngit clone https://github.com/YOUR_USER/project.git\ncd project\ngit remote add upstream https://github.com/ORIGINAL_OWNER/project.git\n\n# 3. Keep fork in sync\ngit checkout main\ngit pull upstream main\ngit push origin main\n\n# 4. Create feature branch\ngit checkout -b feature/amazing\n\n# 5. Make changes, commit, push\ngit push -u origin feature/amazing\n\n# 6. Open PR from your fork to upstream\n\n# 7. Update PR with upstream changes\ngit fetch upstream\ngit rebase upstream/main\ngit push --force-with-lease', keyPoints: ['Fork creates personal copy on GitHub', 'upstream remote tracks original repo', 'Rebase to keep PR up to date', 'Force-with-lease for safety'] })
// ========== DOCKER NEW CONCEPTS ==========
addC('docker', 'Containerization', 'Multi-stage Builds', 'Intermediate', 'Using multiple FROM statements to create smaller production images', { codeExample: '# Build stage\nFROM node:18-alpine AS builder\nWORKDIR /app\nCOPY package*.json ./\nRUN npm ci\nCOPY . .\nRUN npm run build\n\n# Production stage\nFROM node:18-alpine\nWORKDIR /app\nCOPY --from=builder /app/dist ./dist\nCOPY --from=builder /app/node_modules ./node_modules\nCOPY package.json ./\nEXPOSE 3000\nCMD ["node", "dist/server.js"]\n\n# Result: production image contains only runtime deps\n# Much smaller than including build tools', keyPoints: ['Reduces final image size', 'Separates build and runtime dependencies', 'Each FROM starts new stage', 'COPY --from=stage_name copies between stages'] })
addC('docker', 'Containerization', 'Dockerfile Instructions (ADD vs COPY, HEALTHCHECK)', 'Intermediate', 'Key Dockerfile instructions for efficient and secure builds', { codeExample: '# COPY vs ADD\nCOPY . /app           # preferred for local files\nADD https://example/file.tar.gz /tmp/  # ADD supports URLs and tar auto-extract\n\n# HEALTHCHECK\nHEALTHCHECK --interval=30s --timeout=5s --retries=3 \\\n  CMD wget --no-verbose --tries=1 http://localhost:8080/health || exit 1\n\n# USER (security)\nRUN addgroup -g 1001 -S appgroup && adduser -S appuser -u 1001 -G appgroup\nUSER appuser\n\n# ARG vs ENV\nARG BUILD_VERSION  # build-time only\nENV APP_VERSION=  # runtime\n\n# EXPOSE (documentation only)\nEXPOSE 3000', keyPoints: ['COPY preferred over ADD for local files', 'HEALTHCHECK enables container monitoring', 'USER for non-root execution', 'ARG for build-time, ENV for runtime'] })
addC('docker', 'Networking', 'Docker Compose Networks', 'Intermediate', 'Configuring networks between services in Docker Compose', { codeExample: 'version: "3.8"\nservices:\n  api:\n    build: .\n    networks:\n      - frontend\n      - backend\n    depends_on:\n      - redis\n      - postgres\n\n  redis:\n    image: redis:alpine\n    networks:\n      - backend\n\n  postgres:\n    image: postgres:15\n    networks:\n      - backend\n    volumes:\n      - pgdata:/var/lib/postgresql/data\n\n  nginx:\n    image: nginx:alpine\n    ports:\n      - "80:80"\n    networks:\n      - frontend\n\nnetworks:\n  frontend:\n  backend:\n    driver: bridge\n\nvolumes:\n  pgdata:', keyPoints: ['Networks isolate groups of services', 'Services on same network can resolve by name', 'Multiple networks per service for API gateway pattern', 'Default network created if unspecified'] })
addC('docker', 'Orchestration & Production', 'Container Resource Limits', 'Intermediate', 'Limiting CPU and memory usage for containers', { codeExample: '# Docker run\n# Memory\ndocker run -m 512m --memory-reservation=256m --memory-swap=1g myapp\ndocker run --memory="512m" --oom-kill-disable=true myapp\n\n# CPU\ndocker run --cpus="1.5" myapp\ndocker run --cpu-quota=50000 --cpu-period=100000 myapp  # 0.5 CPU\n\n# Docker Compose\nversion: "3.8"\nservices:\n  app:\n    image: myapp\n    deploy:\n      resources:\n        limits:\n          cpus: "0.5"\n          memory: 256M\n        reservations:\n          cpus: "0.25"\n          memory: 128M\n\n# Kubernetes\n# resources:\n#   limits:\n#     cpu: "500m"\n#     memory: "256Mi"\n#   requests:\n#     cpu: "250m"\n#     memory: "128Mi"', keyPoints: ['Prevents resource exhaustion of host', 'OOM killer kills container when over limit', 'CPU limits use CFS scheduler', 'Separate limits and requests in orchestration'] })
// ========== DSA NEW CONCEPTS ==========
addC('dsa', 'Data Structures', 'Hash Set & Hash Map Patterns', 'Intermediate', 'Using hash-based data structures for efficient lookup and deduplication', { codeExample: '// Contains Duplicate\nfunction hasDuplicates(nums) {\n  return new Set(nums).size !== nums.length;\n}\n\n// Intersection of Two Arrays\nfunction intersection(nums1, nums2) {\n  const set1 = new Set(nums1);\n  return [...new Set(nums2.filter(n => set1.has(n)))];\n}\n\n// First Non-Repeating Character\nfunction firstUniqChar(s) {\n  const count = {};\n  for (const c of s) count[c] = (count[c] || 0) + 1;\n  for (let i = 0; i < s.length; i++) {\n    if (count[s[i]] === 1) return i;\n  }\n  return -1;\n}', keyPoints: ['O(1) average lookup/insert', 'Set for uniqueness checks', 'Map/dict for frequency counting', 'Common interview pattern'] })
addC('dsa', 'Algorithms', 'Depth-First Search (DFS)', 'Intermediate', 'Graph traversal exploring as far as possible before backtracking', { codeExample: '// Binary Tree DFS (Inorder)\nfunction inorderTraversal(root) {\n  const result = [];\n  function dfs(node) {\n    if (!node) return;\n    dfs(node.left);\n    result.push(node.val);\n    dfs(node.right);\n  }\n  dfs(root);\n  return result;\n}\n\n// Graph DFS (iterative)\nfunction graphDFS(graph, start) {\n  const visited = new Set();\n  const stack = [start];\n\n  while (stack.length) {\n    const node = stack.pop();\n    if (visited.has(node)) continue;\n    visited.add(node);\n    console.log(node);\n    for (const neighbor of graph[node]) {\n      if (!visited.has(neighbor)) {\n        stack.push(neighbor);\n      }\n    }\n  }\n  return visited;\n}', keyPoints: ['Recursive or iterative (stack)', 'Preorder, inorder, postorder for trees', 'O(V + E) time complexity', 'Applications: topological sort, connected components'] })
addC('dsa', 'Complexity Analysis', 'Amortized Analysis', 'Advanced', 'Average time per operation over a sequence of operations', { codeExample: '// Dynamic Array (ArrayList) push_back:\n// Most inserts: O(1)\n// When full: resize O(n), but doubles size\n// Amortized: O(1) per insert\n\nclass DynamicArray {\n  constructor() {\n    this.data = new Array(1);\n    this.size = 0;\n  }\n\n  push(val) {\n    if (this.size === this.data.length) {\n      // Double capacity (O(n) but rare)\n      const newData = new Array(this.data.length * 2);\n      for (let i = 0; i < this.size; i++) {\n        newData[i] = this.data[i];\n      }\n      this.data = newData;\n    }\n    this.data[this.size++] = val;\n  }\n}\n\n// Aggregate method: sum costs / n\n// Accounting method: credit for cheap ops\n// Potential method: energy function', keyPoints: ['Not average case - it\'s worst-case over sequence', 'Key examples: dynamic arrays, splay trees', 'Each resize doubles capacity = O(1) amortized'] })
addC('dsa', 'Problem Solving Strategies', 'Breadth-First Search (BFS)', 'Intermediate', 'Level-by-level graph traversal using a queue, optimal for shortest path in unweighted graphs', { codeExample: '// Binary tree level order\nfunction levelOrder(root) {\n  if (!root) return [];\n  const result = [];\n  const queue = [root];\n\n  while (queue.length) {\n    const levelSize = queue.length;\n    const currentLevel = [];\n    for (let i = 0; i < levelSize; i++) {\n      const node = queue.shift();\n      currentLevel.push(node.val);\n      if (node.left) queue.push(node.left);\n      if (node.right) queue.push(node.right);\n    }\n    result.push(currentLevel);\n  }\n  return result;\n}\n\n// Shortest path in grid (maze)\nfunction shortestPath(grid, start, end) {\n  const rows = grid.length, cols = grid[0].length;\n  const queue = [[start[0], start[1], 0]];\n  const visited = new Set();\n  visited.add(${start[0]},);\n\n  while (queue.length) {\n    const [r, c, dist] = queue.shift();\n    if (r === end[0] && c === end[1]) return dist;\n\n    for (const [dr, dc] of [[0,1],[0,-1],[1,0],[-1,0]]) {\n      const nr = r + dr, nc = c + dc;\n      if (nr >= 0 && nr < rows && nc >= 0 && nc < cols\n          && grid[nr][nc] === 0 && !visited.has(${nr},)) {\n        visited.add(${nr},);\n        queue.push([nr, nc, dist + 1]);\n      }\n    }\n  }\n  return -1;\n}', keyPoints: ['Uses queue (FIFO)', 'Finds shortest path in unweighted graph', 'O(V + E) time complexity', 'Applications: level-order, shortest path, word ladder'] })
// ========== C++ NEW CONCEPTS ==========
addC('cpp', 'Core C++', 'Rule of Five', 'Advanced', 'If custom destructor/copy/move is needed, define all five special member functions', { codeExample: 'class StringBuffer {\n    char* data;\n    size_t size;\npublic:\n    StringBuffer(size_t n) : size(n), data(new char[n]) { }\n\n    // Destructor\n    ~StringBuffer() { delete[] data; }\n\n    // Copy constructor\n    StringBuffer(const StringBuffer& other)\n        : size(other.size), data(new char[other.size]) {\n        std::copy(other.data, other.data + size, data);\n    }\n\n    // Copy assignment\n    StringBuffer& operator=(const StringBuffer& other) {\n        if (this != &other) {\n            delete[] data;\n            size = other.size;\n            data = new char[size];\n            std::copy(other.data, other.data + size, data);\n        }\n        return *this;\n    }\n\n    // Move constructor\n    StringBuffer(StringBuffer&& other) noexcept\n        : data(other.data), size(other.size) {\n        other.data = nullptr;\n        other.size = 0;\n    }\n\n    // Move assignment\n    StringBuffer& operator=(StringBuffer&& other) noexcept {\n        if (this != &other) {\n            delete[] data;\n            data = other.data;\n            size = other.size;\n            other.data = nullptr;\n            other.size = 0;\n        }\n        return *this;\n    }\n};', keyPoints: ['Rule of 5: destructor, copy ctor/assign, move ctor/assign', 'Rule of 0: let compiler generate when possible', 'Move operations should be noexcept', 'Use std::unique_ptr to avoid manual management'] })
addC('cpp', 'Core C++', 'Noexcept & Exception Safety', 'Intermediate', 'Exception safety guarantees and noexcept specifier for optimization', { codeExample: '// Noexcept guarantees\nvoid safe_func() noexcept;  // promises not to throw\n\n// Conditional noexcept\ntemplate<typename T>\nvoid swap(T& a, T& b) noexcept(std::is_nothrow_swappable_v<T>);\n\n// Exception safety levels (strong guarantee):\nclass Account {\n    int balance;\npublic:\n    void withdraw(int amount) {\n        if (amount > balance) throw std::runtime_error("Insufficient");\n        // Commit point: won\'t throw after here\n        balance -= amount;\n    }\n\n    // Copy-and-swap idiom for strong guarantee\n    void setBalance(int newBalance) {\n        auto temp = newBalance;  // can throw\n        std::swap(balance, temp);  // noexcept\n    }\n};\n\n// Move operations should be noexcept\n// Containers use noexcept moves for reallocation', keyPoints: ['noexcept enables compiler optimizations', 'Move ops should be noexcept for containers', 'Basic, strong, nothrow exception safety levels', 'Copy-and-swap idiom provides strong guarantee'] })
addC('cpp', 'Standard Library (STL)', 'Lambda Expressions & Algorithms', 'Intermediate', 'Anonymous functions used with STL algorithms for concise code', { codeExample: '#include <algorithm>\n#include <vector>\n#include <string>\n\nstd::vector<int> v = {1, 2, 3, 4, 5, 6};\n\n// Basic lambda\nauto isEven = [](int x) { return x % 2 == 0; };\nint count = std::count_if(v.begin(), v.end(), isEven);\n\n// Capture by reference\nint sum = 0;\nstd::for_each(v.begin(), v.end(), [&sum](int x) { sum += x; });\n\n// Capture by value (mutable for modification)\nstd::for_each(v.begin(), v.end(), [=](int x) mutable {\n    // copy of sum, not affecting original\n});\n\n// Generic lambda (C++14)\nauto print = [](const auto& x) { std::cout << x << " "; };\n\n// Sorting with custom comparator\nstd::vector<std::string> names = {\"Alice\", \"bob\", \"Charlie\"};\nstd::sort(names.begin(), names.end(), [](const std::string& a, const std::string& b) {\n    return a.size() < b.size();\n});', keyPoints: ['[...](params) -> ret { body } syntax', 'Capture: [=] by value, [&] by reference', 'Generic lambdas with auto parameters', 'constexpr lambdas in C++17'] })
addC('cpp', 'Memory & Performance', 'Placement New & Custom Allocators', 'Advanced', 'Constructing objects at specific memory locations or with custom allocation', { codeExample: '#include <new>\n#include <cstdlib>\n\n// Placement new\nvoid* buffer = std::malloc(sizeof(MyClass));\nMyClass* obj = new (buffer) MyClass(42);\nobj->~MyClass();  // explicit destructor\nstd::free(buffer);\n\n// Custom allocator example\ntemplate<typename T>\nstruct LoggingAllocator {\n    using value_type = T;\n\n    T* allocate(std::size_t n) {\n        auto ptr = static_cast<T*>(std::malloc(n * sizeof(T)));\n        std::cout << \"Allocated \" << n * sizeof(T) << \" bytes\\n\";\n        return ptr;\n    }\n\n    void deallocate(T* ptr, std::size_t n) {\n        std::cout << \"Deallocated \" << n * sizeof(T) << \" bytes\\n\";\n        std::free(ptr);\n    }\n\n    template<typename U>\n    bool operator==(const LoggingAllocator<U>&) { return true; }\n};\n\n// Usage with vector\nstd::vector<int, LoggingAllocator<int>> vec;', keyPoints: ['Placement new separates allocation from construction', 'Custom allocators for memory pooling/debugging', 'PMR allocators (C++17) for polymorphic allocation'] })
// ========== TYPESCRIPT NEW CONCEPTS ==========
addC('typescript', 'Type System', 'Type Guards & Narrowing', 'Intermediate', 'Runtime checks that narrow types within conditional blocks', { codeExample: '// typeof type guard\nfunction process(value: string | number) {\n  if (typeof value === "string") {\n    return value.toUpperCase();  // string methods available\n  }\n  return value.toFixed(2);  // number methods available\n}\n\n// instanceof type guard\nclass Dog { bark() {} }\nclass Cat { meow() {} }\nfunction handle(pet: Dog | Cat) {\n  if (pet instanceof Dog) {\n    pet.bark();\n  }\n}\n\n// Custom type guard\ninterface Fish { swim(): void }\ninterface Bird { fly(): void }\nfunction isFish(pet: Fish | Bird): pet is Fish {\n  return (pet as Fish).swim !== undefined;\n}\n\n// Discriminated union\ntype Shape =\n  | { kind: "circle"; radius: number }\n  | { kind: "rectangle"; width: number; height: number };\n\nfunction area(shape: Shape) {\n  switch (shape.kind) {\n    case "circle": return Math.PI * shape.radius ** 2;\n    case "rectangle": return shape.width * shape.height;\n  }\n}', keyPoints: ['typeof for primitives', 'instanceof for classes', 'Custom guards with "is" return type', 'Discriminated unions with literal kind field'] })
addC('typescript', 'Advanced Types', 'Branded Types & Nominal Typing', 'Advanced', 'Simulating nominal typing with intersection types for type safety', { codeExample: '// Branded types\ntype Brand<T, B> = T & { __brand: B };\ntype UserId = Brand<string, "UserId">;\ntype OrderId = Brand<string, "OrderId">;\n\nfunction getUser(id: UserId) { }\nfunction getOrder(id: OrderId) { }\n\nconst uid = "abc" as UserId;\nconst oid = "xyz" as OrderId;\n\ngetUser(uid);  // OK\ngetUser(oid);  // Error! (brand mismatch)\n\n// Flavoring (weaker than branding)\ntype Flavor<T, F> = T & { __flavor?: F };\n\n// Opaque types\n// Only creator can construct (module exports creators)\nfunction createUserId(s: string): UserId { return s as UserId; }\n\n// Branded types at runtime\n// const userId = Symbol("UserId");\n// type UserId = string & { [userId]: true };', keyPoints: ['Branded types prevent accidental mixing of IDs', 'No runtime overhead (compile-time only)', 'Type branding enforces semantic types'] })
addC('typescript', 'Tooling & Configuration', 'Project References', 'Intermediate', 'Structuring large TypeScript projects with multiple related tsconfig files', { codeExample: '// Root tsconfig.json\n{\n  "compilerOptions": {\n    "composite": true,\n    "declaration": true,\n    "declarationMap": true\n  },\n  "references": [\n    { "path": "./packages/core" },\n    { "path": "./packages/utils" },\n    { "path": "./packages/app" }\n  ]\n}\n\n// packages/core/tsconfig.json\n{\n  "compilerOptions": {\n    "composite": true,\n    "outDir": "./dist",\n    "rootDir": "./src"\n  },\n  "include": ["src"]\n}\n\n// packages/app/tsconfig.json\n{\n  "compilerOptions": {\n    "composite": true,\n    "outDir": "./dist",\n    "rootDir": "./src"\n  },\n  "include": ["src"],\n  "references": [\n    { "path": "../core" },\n    { "path": "../utils" }\n  ]\n}\n// Build: tsc --build (builds all references)', keyPoints: ['composite: true enables project references', 'Build references in dependency order', 'Faster incremental builds', 'Cleaner separation of concerns'] })
// ========== GO NEW CONCEPTS ==========
addC('go', 'Concurrency', 'Worker Pool Pattern', 'Intermediate', 'Fixed number of goroutines processing tasks from a channel', { codeExample: 'func worker(id int, jobs <-chan int, results chan<- int) {\n    for job := range jobs {\n        fmt.Printf("Worker %d processing job %d\\n", id, job)\n        time.Sleep(time.Second)\n        results <- job * 2\n    }\n}\n\nfunc main() {\n    const numJobs = 10\n    const numWorkers = 3\n\n    jobs := make(chan int, numJobs)\n    results := make(chan int, numJobs)\n\n    // Start workers\n    for w := 1; w <= numWorkers; w++ {\n        go worker(w, jobs, results)\n    }\n\n    // Send jobs\n    for j := 1; j <= numJobs; j++ {\n        jobs <- j\n    }\n    close(jobs)\n\n    // Collect results\n    for r := 1; r <= numJobs; r++ {\n        <-results\n    }\n}', keyPoints: ['Fixed pool of goroutines', 'Buffered channels for flow control', 'Processes N workers per M jobs pattern', 'Common for rate-limited operations'] })
addC('go', 'Concurrency', 'Context WithCancel & WithTimeout', 'Intermediate', 'Cancellation propagation and deadlines across goroutines', { codeExample: 'func slowOperation(ctx context.Context) (string, error) {\n    select {\n    case <-time.After(2 * time.Second):\n        return "Done", nil\n    case <-ctx.Done():\n        return "", ctx.Err()\n    }\n}\n\nfunc handler(w http.ResponseWriter, r *http.Request) {\n    ctx, cancel := context.WithTimeout(r.Context(), 1*time.Second)\n    defer cancel()\n\n    result, err := slowOperation(ctx)\n    if err != nil {\n        if errors.Is(err, context.DeadlineExceeded) {\n            http.Error(w, "Timeout", http.StatusGatewayTimeout)\n            return\n        }\n        http.Error(w, err.Error(), http.StatusInternalServerError)\n        return\n    }\n    fmt.Fprint(w, result)\n}\n\n// WithCancel\nctx, cancel := context.WithCancel(parentCtx)\ngo func() {\n    time.Sleep(5 * time.Second)\n    cancel()  // cancels all derived contexts\n}()', keyPoints: ['context.WithTimeout and WithDeadline', 'context.WithCancel for manual cancel', 'ctx.Done() returns channel for select', 'Always defer cancel() to prevent leaks'] })
addC('go', 'Language Features', 'Struct Tags & Reflection', 'Intermediate', 'Metadata on struct fields used for serialization, validation, and ORM', { codeExample: 'type User struct {\n    ID        int    `json:"id" xml:"id"`\n    Name      string `json:"name" validate:"required,min=3"`\n    Email     string `json:"email" validate:"required,email"`\n    Password  string `json:"-"`  // never exported\n    CreatedAt time.Time `json:"created_at"`\n}\n\n// Using tags with encoding/json\nuser := User{ID: 1, Name: "Alice", Email: "alice@test.com"}\ndata, _ := json.Marshal(user)\nfmt.Println(string(data))\n// {"id":1,"name":"Alice","email":"alice@test.com"}\n\n// Reading tags with reflect\nfunc readTags(v interface{}) {\n    t := reflect.TypeOf(v)\n    for i := 0; i < t.NumField(); i++ {\n        field := t.Field(i)\n        fmt.Printf("%s: json=%s validate=%s\\n",\n            field.Name,\n            field.Tag.Get("json"),\n            field.Tag.Get("validate"))\n    }\n}', keyPoints: ['Tags are string literals after field type', 'encoding/json, xml, yaml use tags', 'validator library uses validate tag', 'Custom tags accessible via reflect'] })
addC('go', 'Language Features', 'Generics (Go 1.18+)', 'Intermediate', 'Type parameters for reusable functions and data structures', { codeExample: '// Generic function\nfunc Map[T, U any](slice []T, fn func(T) U) []U {\n    result := make([]U, len(slice))\n    for i, v := range slice {\n        result[i] = fn(v)\n    }\n    return result\n}\n\n// Usage\nnums := []int{1, 2, 3}\nstrs := Map(nums, strconv.Itoa)  // []string{"1","2","3"}\n\n// Generic struct with constraint\ntype Number interface {\n    int | int64 | float64\n}\n\ntype Stack[T any] struct {\n    items []T\n}\n\nfunc (s *Stack[T]) Push(item T) {\n    s.items = append(s.items, item)\n}\n\nfunc (s *Stack[T]) Pop() (T, bool) {\n    if len(s.items) == 0 {\n        var zero T\n        return zero, false\n    }\n    item := s.items[len(s.items)-1]\n    s.items = s.items[:len(s.items)-1]\n    return item, true\n}\n\n// Constraint with ~ for underlying type\nfunc Print[T ~int | ~string](v T) { fmt.Println(v) }', keyPoints: ['Type parameters in brackets [T any]', 'Interfaces as type constraints', '~ allows underlying types', 'No method on type parameters'] })
addC('go', 'Standard Library', 'JSON Encoding & Decoding', 'Intermediate', 'Marshaling/unmarshaling JSON with custom marshalers', { codeExample: 'type User struct {\n    ID   int    `json:"id"`\n    Name string `json:"name"`\n}\n\n// Marshal (encode)\nusers := []User{{1, "Alice"}, {2, "Bob"}}\ndata, err := json.MarshalIndent(users, "", "  ")\n\n// Unmarshal (decode)\nvar loaded []User\njson.Unmarshal(data, &loaded)\n\n// Custom marshaler\ntype CustomTime struct {\n    time.Time\n}\n\nfunc (ct CustomTime) MarshalJSON() ([]byte, error) {\n    return json.Marshal(ct.Format("2006-01-02"))\n}\n\nfunc (ct *CustomTime) UnmarshalJSON(data []byte) error {\n    var s string\n    if err := json.Unmarshal(data, &s); err != nil {\n        return err\n    }\n    t, err := time.Parse("2006-01-02", s)\n    if err != nil {\n        return err\n    }\n    ct.Time = t\n    return nil\n}\n\n// Streaming JSON\n// json.NewDecoder(r).Decode(&v)\n// json.NewEncoder(w).Encode(v)', keyPoints: ['Tags control field names/options', 'MarshalJSON/UnmarshalJSON for custom', 'Streaming with Decoder/Encoder for large data', 'json.RawMessage for deferred decoding'] })
// ========== RUST NEW CONCEPTS ==========
addC('rust', 'Ownership & Borrowing', 'Cow (Clone-on-Write)', 'Advanced', 'Smart pointer that provides borrowed or owned data with copy-on-write', { codeExample: 'use std::borrow::Cow;\n\nfn process(input: &str) -> Cow<str> {\n    if input.contains("bad") {\n        // Modified version: owns the data\n        Cow::Owned(input.replace("bad", "good"))\n    } else {\n        // No modification: borrows the input\n        Cow::Borrowed(input)\n    }\n}\n\nlet s1 = "hello world";\nlet result1 = process(s1);  // Cow::Borrowed (no allocation)\n\nlet s2 = "bad word";\nlet result2 = process(s2);  // Cow::Owned (allocates)\n\n// to_mut() for mutation\nlet mut cow: Cow<str> = Cow::Borrowed("hello");\ncow.to_mut().push_str(" world");  // clones only on mutation\nprintln!("{}", cow);  // "hello world"', keyPoints: ['Avoids allocation when no modification needed', 'Borrowed: &T, Owned: T', 'to_mut() clones on first write', 'Useful in APIs that may need modification'] })
addC('rust', 'Language Features', 'Macros (declarative & procedural)', 'Advanced', 'Metaprogramming: macro_rules! and proc macros for code generation', { codeExample: '// Declarative macro (macro_rules!)\nmacro_rules! vec_strings {\n    ($($x:expr),* $(,)?) => {\n        {\n            let mut v = Vec::new();\n            $(\n                v.push(String::from($x));\n            )*\n            v\n        }\n    };\n}\n\nlet v = vec_strings!["a", "b", "c"];\n\n// println! macro - format with arguments\nprintln!("Hello {name}, age {age}", name = "Alice", age = 30);\n\n// Derive macros\n#[derive(Debug, Clone, PartialEq, Default)]\nstruct Point { x: i32, y: i32 }\n\n// Attribute macros\n#[tokio::main]\nasync fn main() {\n    println!("Hello async");\n}\n\n// Custom derive macro (procedural - in separate crate)\n// #[derive(MyTrait)]\n// fn my_macro_impl(input: TokenStream) -> TokenStream { }', keyPoints: ['macro_rules! for pattern matching', 'Procedural macros: custom derive, attribute, function-like', 'Metaprogramming at compile time', 'Hygienic macros prevent name collisions'] })
addC('rust', 'Memory Safety', 'Pin & Unpin', 'Advanced', 'Pinning ensures data is never moved, required for self-referential structs', { codeExample: 'use std::pin::Pin;\nuse std::marker::PhantomPinned;\n\n// Self-referential struct\n#[derive(Debug)]\nstruct SelfReferential {\n    data: String,\n    ptr: *const String,  // raw pointer to self.data\n    _pin: PhantomPinned,  // makes !Unpin\n}\n\nimpl SelfReferential {\n    fn new(data: String) -> Pin<Box<Self>> {\n        let mut boxed = Box::pin(SelfReferential {\n            ptr: std::ptr::null(),\n            data,\n            _pin: PhantomPinned,\n        });\n        // SAFETY: Box ensures data won\'t move\n        let ptr = &boxed.data as *const String;\n        unsafe { boxed.as_mut().get_unchecked_mut().ptr = ptr; }\n        boxed\n    }\n\n    fn get_data(self: Pin<&Self>) -> &String {\n        unsafe { &*self.ptr }\n    }\n}\n\n// Async blocks create self-referential futures\n// Pin ensures the future doesn\'t move between awaits\nasync fn example() {\n    let x = String::from("hello");\n    // compiler generates struct with self-references\n    std::future::ready(()).await;\n    println!("{}", x);\n}', keyPoints: ['Pin<Pointer<T>> ensures T won\'t move', '!Unpin types cannot be moved after pinned', 'Required for async and self-referential structs', 'Pin<Box<T>> and Pin<&mut T> common forms'] })
addC('rust', 'Memory Safety', 'FFI (Foreign Function Interface)', 'Advanced', 'Calling C functions from Rust and exposing Rust functions to C', { codeExample: 'use std::ffi::{CStr, CString};\nuse std::os::raw::c_char;\n\n// Calling C function\nextern "C" {\n    fn strlen(s: *const c_char) -> usize;\n}\n\nfn rust_strlen(s: &str) -> usize {\n    let c_str = CString::new(s).unwrap();\n    unsafe { strlen(c_str.as_ptr()) }\n}\n\n// Exposing Rust to C\n#[no_mangle]\npub extern "C" fn add_numbers(a: i32, b: i32) -> i32 {\n    a + b\n}\n\n// Safe wrapper\nuse std::ffi::OsStr;\nuse std::os::unix::ffi::OsStrExt;\n\nstruct FileHandle {\n    fd: std::os::raw::c_int,\n}\n\nimpl FileHandle {\n    fn open(path: &OsStr) -> Result<Self, std::io::Error> {\n        let cpath = CString::new(path.as_bytes())?;\n        let fd = unsafe { libc::open(cpath.as_ptr(), libc::O_RDONLY) };\n        if fd < 0 {\n            Err(std::io::Error::last_os_error())\n        } else {\n            Ok(FileHandle { fd })\n        }\n    }\n}\n\nimpl Drop for FileHandle {\n    fn drop(&mut self) {\n        unsafe { libc::close(self.fd); }\n    }\n}', keyPoints: ['extern "C" block for FFI declarations', '#[no_mangle] prevents name mangling', 'CString/CStr for C string interop', 'Safe wrappers prevent unsafety from leaking'] })
// ========== MYSQL NEW CONCEPTS ==========
addC('mysql', 'Database Design', 'Views', 'Intermediate', 'Virtual tables based on SELECT query, providing abstraction and security', { codeExample: '-- Create a view\nCREATE VIEW active_customers AS\nSELECT c.id, c.name, c.email, COUNT(o.id) as order_count\nFROM customers c\nLEFT JOIN orders o ON c.id = o.customer_id\nWHERE c.status = "active"\nGROUP BY c.id, c.name, c.email;\n\n-- Use view like a table\nSELECT * FROM active_customers WHERE order_count > 5;\n\n-- Updatable views (simple views only)\nCREATE OR REPLACE VIEW user_contacts AS\nSELECT id, name, email, phone FROM users;\n\nINSERT INTO user_contacts (name, email) VALUES ("New", "new@test.com");\n\n-- Check view info\nSHOW CREATE VIEW active_customers;\n\n-- Drop\nDROP VIEW IF EXISTS active_customers;\n\n-- WITH CHECK OPTION (prevents inserts/updates that would hide row)\nCREATE VIEW high_value AS\nSELECT * FROM products WHERE price > 100\nWITH CHECK OPTION;', keyPoints: ['Simplifies complex queries', 'Adds security layer (hide columns/rows)', 'Can be indexed with materialized views', 'Performance depends on underlying query'] })
addC('mysql', 'Querying', 'Full-Text Search', 'Intermediate', 'Natural language full-text search with indexes', { codeExample: '-- Create full-text index\nALTER TABLE articles ADD FULLTEXT INDEX ft_title_body (title, body);\n\n-- Natural language mode\nSELECT title, MATCH(title, body) AGAINST("database optimization" IN NATURAL LANGUAGE MODE) AS relevance\nFROM articles\nWHERE MATCH(title, body) AGAINST("database optimization" IN NATURAL LANGUAGE MODE)\nORDER BY relevance DESC;\n\n-- Boolean mode (operators: +, -, *, >, <)\nSELECT * FROM articles\nWHERE MATCH(title, body) AGAINST("+mysql -oracle *optimiz*" IN BOOLEAN MODE);\n\n-- Query expansion (finds related content)\nSELECT * FROM articles\nWHERE MATCH(title, body) AGAINST("database" WITH QUERY EXPANSION);\n\n-- Minimum word length\n-- innodb_ft_min_token_size = 3 (InnoDB)\n-- ft_min_word_len = 4 (MyISAM)', keyPoints: ['FULLTEXT index for text columns', 'Natural language and boolean modes', 'Stopwords and minimum length', 'Better than LIKE "%word%" for large text'] })
addC('mysql', 'Administration', 'Performance Schema & sys Schema', 'Advanced', 'Instrumentation for monitoring MySQL performance', { codeExample: '-- Enable performance schema\n[mysqld]\nperformance_schema = ON\nperformance-schema-instrument = \'stage/%=ON\'\n\n-- Query performance metrics\nSELECT * FROM performance_schema.events_statements_summary_by_digest\nWHERE digest_text LIKE "%SELECT%" \nORDER BY sum_timer_wait DESC\nLIMIT 10;\n\n-- Table I/O summary\nSELECT * FROM sys.io_global_by_file_by_bytes\nWHERE file LIKE "%mydb/%"\nORDER BY total DESC;\n\n-- Slow queries\nSELECT * FROM sys.statement_analysis\nWHERE last_seen > NOW() - INTERVAL 1 DAY\nORDER BY avg_latency DESC;\n\n-- Index usage\nSELECT * FROM sys.schema_unused_indexes;\n\n-- InnoDB locks\nSELECT * FROM sys.innodb_lock_waits;\n\n-- Memory usage by user\nSELECT * FROM sys.memory_by_user_by_current_bytes;', keyPoints: ['performance_schema for detailed metrics', 'sys schema provides user-friendly views', 'Enabled by default in MySQL 8+', 'Low overhead (usually < 10%)'] })
// ========== LINUX NEW CONCEPTS ==========
addC('linux', 'System Administration', 'Cron & Scheduled Tasks', 'Beginner', 'Scheduling recurring tasks with cron and systemd timers', { codeExample: '# Crontab format: minute hour day month weekday command\n# every day at 2:30 AM\n30 2 * * * /usr/bin/backup.sh\n\n# every hour\n0 * * * * /usr/bin/cleanup.sh\n\n# every Monday at 3 AM\n0 3 * * 1 /usr/bin/weekly-report.sh\n\n# every 15 minutes\n*/15 * * * * /usr/bin/poll.sh\n\n# View/edit crontab\ncrontab -l  # list\ncrontab -e  # edit\n\n# systemd timer (modern alternative)\n# /etc/systemd/system/mytask.timer\n[Unit]\nDescription=Run mytask daily\n[Timer]\nOnCalendar=daily\nPersistent=true\n[Install]\nWantedBy=timers.target', keyPoints: ['Five-field crontab syntax', 'User crontabs with crontab -e', 'System crontab in /etc/crontab', 'systemd timers replace cron on modern systems'] })
addC('linux', 'Networking', 'Network Namespaces', 'Advanced', 'Isolated network stacks for containers and advanced networking', { codeExample: '# Create network namespace\nip netns add blue\nip netns add red\n\n# List namespaces\nip netns list\n\n# Create virtual Ethernet (veth) pair\nip link add veth-blue type veth peer name veth-red\n\n# Move veth ends to namespaces\nip link set veth-blue netns blue\nip link set veth-red netns red\n\n# Configure IP in blue namespace\nip netns exec blue ip addr add 10.0.0.1/24 dev veth-blue\nip netns exec blue ip link set veth-blue up\n\n# Configure IP in red namespace\nip netns exec red ip addr add 10.0.0.2/24 dev veth-red\nip netns exec red ip link set veth-red up\n\n# Test connectivity\nip netns exec blue ping 10.0.0.2\n\n# Execute command in namespace\nip netns exec blue bash\n\n# Docker uses network namespaces internally', keyPoints: ['Each namespace has own interfaces, routes, iptables', 'veth pairs connect namespaces', 'Bridge connects multiple namespaces', 'Foundation of container networking'] })
addC('linux', 'Shell Scripting', 'Here Documents & Process Substitution', 'Intermediate', 'Advanced shell features for I/O redirection and command substitution', { codeExample: '# Process substitution (diff command output)\ndiff <(ls dir1) <(ls dir2)\n\n# Read from process substitution\nwhile IFS= read -r line; do\n    echo "Processing: $line"\ndone < <(grep "error" /var/log/syslog)\n\n# Here document (multi-line input)\ncat <<EOF > config.txt\nserver {\n    listen 80;\n    server_name example.com;\n}\nEOF\n\n# Here string\ngrep "pattern" <<< "This is a test string"\n\n# Brace expansion\necho {1..10}\necho {a..z}\necho file{1,2,3}.txt\n\n# Arithmetic expansion\necho $(( 5 + 3 ))', keyPoints: ['<(command) feeds output as file', '<<EOF for multi-line input', '<<< for string input', '{x..y} for brace expansion'] })
// ========== MONGODB NEW CONCEPTS ==========
addC('mongodb', 'NoSQL Concepts', 'Index Types (Single, Compound, Multikey)', 'Intermediate', 'Different index types for optimizing MongoDB queries', { codeExample: '// Single field index\ndb.users.createIndex({ email: 1 })\n\n// Compound index (ESR: Equality, Sort, Range)\ndb.orders.createIndex({ userId: 1, createdAt: -1, total: 1 })\n\n// Multikey index (for arrays)\ndb.posts.createIndex({ tags: 1 })\n\n// Text index\ndb.articles.createIndex({ title: "text", body: "text" }, { weights: { title: 10, body: 5 } })\n\n// Hashed index (for sharding)\ndb.users.createIndex({ email: "hashed" })\n\n// Sparse index (only indexes documents with the field)\ndb.users.createIndex({ phone: 1 }, { sparse: true })\n\n// TTL index (auto-expire documents)\ndb.sessions.createIndex({ createdAt: 1 }, { expireAfterSeconds: 3600 })\n\n// Wildcard index\ndb.products.createIndex({ "attributes.$**": 1 })', keyPoints: ['Single: basic field query', 'Compound: multi-field queries (ESR order)', 'Multikey: array fields', 'Text: full-text search', 'TTL: auto-expire data'] })
addC('mongodb', 'Schema Design', 'Two-Phase Commit Pattern', 'Advanced', 'Implementing transactions in MongoDB before 4.0 using two-phase commit', { codeExample: '// Two-phase commit for transfers\n// Phase 1: Initialize transaction\ndb.transactions.insertOne({\n  _id: ObjectId(),\n  source: "accountA",\n  destination: "accountB",\n  amount: 100,\n  status: "pending",\n  createdAt: new Date()\n})\n\n// Phase 2a: Apply to source\nconst sourceResult = db.accounts.updateOne(\n  { _id: "accountA", balance: { $gte: 100 } },\n  { $inc: { balance: -100 } }\n)\n\n// Phase 2b: Apply to destination\nif (sourceResult.modifiedCount === 1) {\n  const destResult = db.accounts.updateOne(\n    { _id: "accountB" },\n    { $inc: { balance: 100 } }\n  )\n\n  // Phase 3: Mark transaction complete\n  if (destResult.modifiedCount === 1) {\n    db.transactions.updateOne(\n      { _id: transactionId },\n      { $set: { status: "completed", completedAt: new Date() } }\n    )\n  }\n}\n\n// Modern: use transactions (MongoDB 4.0+)\nconst session = client.startSession()\nsession.startTransaction()\ntry {\n  await accounts.updateOne({ _id: "a" }, { $inc: { balance: -100 } }, { session })\n  await accounts.updateOne({ _id: "b" }, { $inc: { balance: 100 } }, { session })\n  await session.commitTransaction()\n} catch { session.abortTransaction() }', keyPoints: ['Two-phase commit for atomicity before 4.0', 'MongoDB 4.0+ supports multi-document transactions', 'Use transaction for financial operations', 'Handle rollback scenarios carefully'] })
addC('mongodb', 'Operations', 'Backup & Restore', 'Intermediate', 'Methods for backing up and restoring MongoDB data', { codeExample: '# mongodump (logical backup)\nmongodump --uri="mongodb://localhost:27017/mydb" --out=/backup/mydb_$(date +%Y%m%d)\n\n# mongorestore\nmongorestore --uri="mongodb://localhost:27017/mydb" /backup/mydb_20240101/mydb\n\n# mongodump specific collections\nmongodump --db=mydb --collection=users --out=/backup\n\n# mongorestore with drop (replace existing)\nmongorestore --drop --db=mydb /backup/mydb/\n\n# BSON dump (for single collection)\nmongoexport --db=mydb --collection=users --out=users.json\nmongoimport --db=mydb --collection=users --file=users.json\n\n# File system snapshot (physical backup)\n# - LVM snapshot\n# - EBS snapshot\n\n# Ops Manager / Atlas (automated)\n# - Continuous backups\n# - Point-in-time recovery\n\n# Replica set backup best practices:\n# - Backup from secondary\n# - Use --oplog for point-in-time', keyPoints: ['mongodump for logical backup', 'File system snapshots for physical backup', 'Always backup from secondary', 'Test restores regularly'] })
// ========== C NEW CONCEPTS ==========
addC('c', 'Memory Management', 'VLA (Variable Length Arrays)', 'Intermediate', 'Arrays whose length is determined at runtime (C99 feature)', { codeExample: '#include <stdio.h>\n\nvoid process(int n) {\n    // VLA - size determined at runtime\n    int arr[n];\n\n    for (int i = 0; i < n; i++) {\n        arr[i] = i * i;\n    }\n\n    for (int i = 0; i < n; i++) {\n        printf("%d ", arr[i]);\n    }\n    printf("\\n");\n}\n\nint main() {\n    process(5);  // arr has 5 elements\n    process(10); // arr has 10 elements\n    return 0;\n}\n\n// Multi-dimensional VLA\nvoid matrix(int rows, int cols, int data[rows][cols]) {\n    for (int i = 0; i < rows; i++) {\n        for (int j = 0; j < cols; j++) {\n            printf("%d ", data[i][j]);\n        }\n        printf("\\n");\n    }\n}\n\n// Note: VLAs are optional in C11 (implementation-defined)', keyPoints: ['Size determined at runtime', 'Allocated on stack (risk of stack overflow)', 'Not supported in C++', 'Optional in C11 and later'] })
addC('c', 'Memory Management', 'Compound Literals & Designated Initializers', 'Intermediate', 'C99 features for inline struct/array creation and named field initialization', { codeExample: '#include <stdio.h>\n\nstruct Point {\n    int x, y;\n};\n\nstruct Rectangle {\n    struct Point topLeft;\n    struct Point bottomRight;\n};\n\nint main() {\n    // Compound literal (creates unnamed object)\n    struct Point p = (struct Point){ .x = 10, .y = 20 };\n\n    // Designated initializers\n    struct Point q = { .y = 5, .x = 3 };  // order doesn\'t matter\n\n    // Nested designated initializers\n    struct Rectangle rect = {\n        .topLeft = { .x = 0, .y = 10 },\n        .bottomRight = { .x = 100, .y = 0 }\n    };\n\n    // Array with designated initializer\n    int arr[10] = { [0] = 1, [5] = 2, [9] = 3 };\n\n    // Compound literal as function argument\n    printf("Area: %d\\n", area((struct Rectangle){\n        .topLeft = {0, 0},\n        .bottomRight = {10, 10}\n    }));\n\n    return 0;\n}\n\nint area(struct Rectangle r) {\n    return (r.bottomRight.x - r.topLeft.x) * (r.bottomRight.y - r.topLeft.y);\n}', keyPoints: ['Compound literals: (type){init}', 'Designated init: .field = value', 'Combined for inline struct creation', 'C99 features widely supported'] })
addC('c', 'Pointer & Function Concepts', 'Variadic Functions (stdarg.h)', 'Intermediate', 'Functions that accept variable number of arguments', { codeExample: '#include <stdio.h>\n#include <stdarg.h>\n\ndouble average(int count, ...) {\n    va_list args;\n    double sum = 0;\n\n    va_start(args, count);\n\n    for (int i = 0; i < count; i++) {\n        sum += va_arg(args, double);\n    }\n\n    va_end(args);\n    return sum / count;\n}\n\nint printfWrapper(const char *format, ...) {\n    va_list args;\n    va_start(args, format);\n    int result = vprintf(format, args);\n    va_end(args);\n    return result;\n}\n\nint main() {\n    double avg = average(4, 10.0, 20.0, 30.0, 40.0);\n    printf("Average: %.2f\\n", avg);\n\n    // using vprintf\n    printfWrapper("Values: %d, %s, %.1f\\n", 42, "hello", 3.14);\n\n    return 0;\n}\n\n// Required: at least one fixed parameter before ...\n// va_list, va_start, va_arg, va_end macros\n// vprintf, vfprintf, vsprintf for format forwarding', keyPoints: ['va_list, va_start, va_arg, va_end', 'At least one fixed parameter required', 'No type safety (C variadics)', 'Used by printf family'] })
addC('c', 'Preprocessor & Compilation', 'Inline Functions vs Macros', 'Intermediate', 'Comparing inline functions and function-like macros for performance', { codeExample: '#include <stdio.h>\n\n// Macro (text substitution)\n#define SQUARE_MACRO(x) ((x) * (x))\n#define MAX_MACRO(a, b) ((a) > (b) ? (a) : (b))\n\n// Inline function (C99)\nstatic inline int square_inline(int x) {\n    return x * x;\n}\n\nstatic inline double max_inline(double a, double b) {\n    return a > b ? a : b;\n}\n\nint main() {\n    int a = 5;\n\n    // Macro pitfall: argument evaluated twice\n    printf("%d\\n", SQUARE_MACRO(++a));  // a incremented twice!\n\n    // Inline: safe (arguments evaluated once)\n    a = 5;\n    printf("%d\\n", square_inline(++a));  // a incremented once\n\n    // Another macro issue: type unsafety\n    printf("%s\\n", MAX_MACRO("hello", "world"));  // compiles but wrong!\n\n    // Inline: type-safe\n    // printf("%s\\n", max_inline("hello", "world"));  // compiler warning\n\n    return 0;\n}\n\n// When to use:\n// - Macros: conditional compilation (#ifdef), stringification\n// - Inline: type-safe function replacement, debugging', keyPoints: ['Macros: text substitution, no type check', 'Macro arguments evaluated each time (double eval!)', 'Inline functions: type-safe, single evaluation', 'Static inline for internal linkage'] })
// ========== C# NEW CONCEPTS ==========
addC('csharp', '.NET Framework', 'Dependency Injection in .NET', 'Intermediate', 'Built-in DI container for managing service lifetimes and dependencies', { codeExample: 'var builder = WebApplication.CreateBuilder(args);\n\n// Register services with lifetimes\nbuilder.Services.AddScoped<IUserRepository, UserRepository>();  // per request\nbuilder.Services.AddTransient<IEmailService, EmailService>();  // every time\nbuilder.Services.AddSingleton<ICacheService, RedisCacheService>();  // once\n\n// Register with factory\nbuilder.Services.AddScoped<DbContext>(sp => {\n    var config = sp.GetRequiredService<IConfiguration>();\n    return new AppDbContext(config.GetConnectionString("Default"));\n});\n\n// Register multiple implementations\nbuilder.Services.AddKeyedScoped<IPaymentProcessor, StripeProcessor>("stripe");\nbuilder.Services.AddKeyedScoped<IPaymentProcessor, PayPalProcessor>("paypal");\n\n// Usage in controller\npublic class UserController {\n    private readonly IUserRepository _repo;\n\n    public UserController(IUserRepository repo) {\n        _repo = repo;\n    }\n}\n\n// Manually resolve\nvar service = serviceProvider.GetRequiredService<IUserRepository>();', keyPoints: ['AddScoped: one instance per HTTP request', 'AddTransient: new instance every injection', 'AddSingleton: single instance for app lifetime', 'Keyed services for multiple implementations'] })
addC('csharp', 'C# Language Features', 'Async Streams (IAsyncEnumerable)', 'Intermediate', 'Asynchronous enumeration for streaming data with await foreach', { codeExample: 'async IAsyncEnumerable<int> GenerateNumbersAsync() {\n    for (int i = 0; i < 10; i++) {\n        await Task.Delay(100);  // simulate async work\n        yield return i;\n    }\n}\n\nasync Task ProcessAsync() {\n    await foreach (var number in GenerateNumbersAsync()) {\n        Console.WriteLine($"Received: {number}");\n    }\n}\n\n// With CancellationToken\nasync IAsyncEnumerable<int> GetPagedDataAsync(\n    [EnumeratorCancellation] CancellationToken ct = default)\n{\n    int page = 0;\n    while (!ct.IsCancellationRequested) {\n        var pageData = await FetchPageAsync(page++, ct);\n        if (pageData.Count == 0) yield break;\n\n        foreach (var item in pageData) {\n            yield return item;\n        }\n    }\n}', keyPoints: ['yield return in async method', 'await foreach for consumption', 'Supports CancellationToken', 'Useful for paginated API data, large file processing'] })
addC('csharp', '.NET Ecosystem', 'Blazor & Razor Components', 'Intermediate', 'Building interactive web UIs with C# instead of JavaScript', { codeExample: '@page "/counter"\n<h3>Counter</h3>\n\n<p>Current count: @currentCount</p>\n<button @onclick="IncrementCount">Click me</button>\n\n@code {\n    private int currentCount = 0;\n\n    private void IncrementCount() {\n        currentCount++;\n    }\n}\n\n// Component with parameters\n@* Greeting.razor *@\n<h3>Hello, @Name!</h3>\n\n@code {\n    [Parameter]\n    public string Name { get; set; }\n\n    [Parameter]\n    public EventCallback<string> OnNameChanged { get; set; }\n}\n\n// Usage\n<Greeting Name="@userName" OnNameChanged=\"@HandleNameChange\" />\n\n// Blazor WebAssembly vs Server\n// WASM: runs in browser via WebAssembly\n// Server: runs on server, SignalR for UI updates', keyPoints: ['Razor components with @code blocks', 'Parameters via [Parameter] attribute', 'Event handling with @onclick', 'Two hosting models: WASM and Server'] })
