addC('kotlin', 'Kotlin Features', 'Inline & Value Classes', 'Advanced', 'Inline classes avoid object overhead for wrappers; value classes for primitives', { codeExample: '// Inline class (wraps value without allocation)\ninline class Password(val value: String) {\n    fun masked() = "***"\n}\n\nfun login(password: Password) { }\n// No Password object created at runtime\n\n// Value class (JVM, Kotlin 1.5+)\n@JvmInline\nvalue class UserId(val id: Int) {\n    init {\n        require(id > 0) { "ID must be positive" }\n    }\n}\n\n// Usage with no runtime overhead\nfun getUser(id: UserId) { }\ngetUser(UserId(42))  // passes primitive int\n\n// Multiple inline class parameters\nfun process(uid: UserId, pid: ProductId) { }', keyPoints: ['Inline classes: wrapper without allocation', 'Value classes: type-safe primitives', '@JvmInline for JVM interop', 'Single property requirement'] })
addC('kotlin', 'Interop & Tooling', 'kotlinx.serialization', 'Intermediate', 'Kotlin multiplatform serialization library replacing Gson/Jackson', { codeExample: 'import kotlinx.serialization.*\nimport kotlinx.serialization.json.*\n\n@Serializable\ndata class User(\n    val name: String,\n    @SerialName("email_addr")\n    val email: String,\n    @Transient\n    val internalId: String = "",\n    val roles: List<String> = emptyList()\n)\n\n// Serialize\nval user = User("Alice", "alice@test.com", roles = listOf("admin"))\nval json = Json.encodeToString(user)\n// {"name":"Alice","email_addr":"alice@test.com","roles":["admin"]}\n\n// Deserialize\nval decoded = Json.decodeFromString<User>(json)\n\n// Custom configuration\nval prettyJson = Json {\n    prettyPrint = true\n    ignoreUnknownKeys = true\n    coerceInputValues = true\n}\n\n// Polymorphic serialization\n@Serializable\nsealed class Response {\n    @Serializable data class Success(val data: String) : Response()\n    @Serializable data class Error(val message: String) : Response()\n}', keyPoints: ['@Serializable annotation for auto-generation', '@SerialName for custom field names', 'JSON configuration options', 'Supports polymorphism, nulls, defaults'] })
addC('kotlin', 'Standard Library', 'Result & runCatching', 'Intermediate', 'Functional error handling with Result type', { codeExample: 'fun riskyOperation(): Result<String> {\n    return runCatching {\n        // May throw\n        "Success: ${someApi.call()}"\n    }\n}\n\n// Usage\nval result = riskyOperation()\n\nresult.onSuccess { value ->\n    println("Got: $value")\n}.onFailure { error ->\n    println("Failed: ${error.message}")\n}\n\n// Get with default\nval value = result.getOrDefault("default")\n\n// Transform\nval transformed = result.map { it.uppercase() }\nval flatMapped = result.mapCatching { anotherRiskyOp(it) }\n\n// Recover from failure\nval safe = result.recover { "Fallback value" }\n\n// Throw on failure\nval forced = result.getOrThrow()', keyPoints: ['runCatching wraps try-catch in Result', 'onSuccess/onFailure for handling', 'map/mapCatching for transformation', 'getOrDefault/recover for fallbacks'] })
// ========== SWIFT NEW CONCEPTS ==========
addC('swift', 'Swift Features', 'Property Wrappers', 'Advanced', 'Reusable property behavior: validation, transformation, storage', { codeExample: '@propertyWrapper\nstruct Clamped<T: Comparable> {\n    private var value: T\n    private let range: ClosedRange<T>\n\n    init(wrappedValue: T, _ range: ClosedRange<T>) {\n        self.range = range\n        self.value = min(max(wrappedValue, range.lowerBound), range.upperBound)\n    }\n\n    var wrappedValue: T {\n        get { value }\n        set { value = min(max(newValue, range.lowerBound), range.upperBound) }\n    }\n\n    var projectedValue: Self { self }\n}\n\nstruct Settings {\n    @Clamped(0...100) var volume: Int = 50\n    @Clamped(0.0...1.0) var brightness: Double = 0.8\n}\n\nvar s = Settings()\ns.volume = 150\nprint(s.volume)  // 100 (clamped)\nprint(s.$volume) // projectedValue\n\n// Built-in property wrappers\n// @State, @Binding, @ObservedObject (SwiftUI)\n// @Published (Combine)\n// @AppStorage (UserDefaults)\n// @ScaledMetric (dynamic type)', keyPoints: ['@propertyWrapper annotation', 'wrappedValue for get/set', 'projectedValue ($ prefix)', 'Built-in: @State, @Published, @AppStorage'] })
addC('swift', 'iOS Development Basics', 'Core Data', 'Intermediate', 'Apple\'s object graph and persistence framework', { codeExample: 'import CoreData\n\n// Data model definition (in .xcdatamodeld)\n// Entity: User\n// Attributes: id (UUID), name (String), age (Int32)\n\n// Managed object subclass\nclass User: NSManagedObject {\n    @NSManaged var id: UUID\n    @NSManaged var name: String\n    @NSManaged var age: Int32\n}\n\n// CRUD operations\nlet context = persistentContainer.viewContext\n\n// Create\nlet user = User(context: context)\nuser.id = UUID()\nuser.name = "Alice"\nuser.age = 30\ntry context.save()\n\n// Fetch\nlet request: NSFetchRequest<User> = User.fetchRequest() as! NSFetchRequest<User>\nrequest.predicate = NSPredicate(format: "age > %d", 18)\nrequest.sortDescriptors = [NSSortDescriptor(key: "name", ascending: true)]\nlet results = try context.fetch(request)\n\n// Update\nuser.age = 31\ntry context.save()\n\n// Delete\ncontext.delete(user)\ntry context.save()\n\n// Background context for heavy operations\nlet backgroundContext = persistentContainer.newBackgroundContext()', keyPoints: ['Object graph with NSManagedObject', 'NSPredicate for queries', 'Background contexts for performance', 'Migrations for schema changes'] })
addC('swift', 'Concurrency & Memory', 'Combine Framework', 'Advanced', 'Reactive programming framework for handling asynchronous events', { codeExample: 'import Combine\n\nclass UserViewModel: ObservableObject {\n    @Published var users: [User] = []\n    @Published var searchText = ""\n    @Published var isLoading = false\n\n    private var cancellables = Set<AnyCancellable>()\n\n    init() {\n        // Debounced search\n        $searchText\n            .debounce(for: .milliseconds(300), scheduler: RunLoop.main)\n            .removeDuplicates()\n            .sink { [weak self] text in\n                Task { await self?.searchUsers(text) }\n            }\n            .store(in: &cancellables)\n    }\n\n    func loadUsers() {\n        isLoading = true\n        api.fetchUsers()\n            .receive(on: DispatchQueue.main)\n            .sink(receiveCompletion: { [weak self] completion in\n                self?.isLoading = false\n                if case .failure(let error) = completion {\n                    print("Error: \\(error)")\n                }\n            }, receiveValue: { [weak self] users in\n                self?.users = users\n            })\n            .store(in: &cancellables)\n    }\n}\n\n// Publisher types\n// Just, Future, PassthroughSubject, CurrentValueSubject\n// @Published property wrapper\n// URLSession.dataTaskPublisher\n// NotificationCenter.Publisher', keyPoints: ['Publisher/Subscriber pattern', 'Operators: map, filter, debounce, combineLatest', '@Published for observable properties', 'Cancellable for lifecycle management'] })
// ========== PANDAS NEW CONCEPTS ==========
addC('pandas', 'Data Manipulation', 'MultiIndex (Hierarchical Indexing)', 'Advanced', 'Working with multiple index levels for complex data', { codeExample: 'import pandas as pd\nimport numpy as np\n\n# Create MultiIndex\narrays = [[2023, 2023, 2024, 2024], ["Q1", "Q2", "Q1", "Q2"]]\nindex = pd.MultiIndex.from_arrays(arrays, names=["year", "quarter"])\ndf = pd.DataFrame({"revenue": [100, 120, 110, 130], "cost": [60, 70, 65, 75]}, index=index)\n\nprint(df)\n#              revenue  cost\n# year quarter\n# 2023 Q1         100    60\n#      Q2         120    70\n# 2024 Q1         110    65\n#      Q2         130    75\n\n# Indexing\nprint(df.loc[2023])  # all 2023 data\nprint(df.loc[(2023, "Q1")])  # specific cell\nprint(df.xs("Q1", level="quarter"))  # all Q1 across years\n\n# Stack/Unstack\ndf2 = df.unstack(level="quarter")  # pivot quarter to columns\nprint(df2)\n#      revenue       cost\n# quarter    Q1  Q2   Q1  Q2\n# year\n# 2023     100 120   60  70\n\n# Reset index\ndf_reset = df.reset_index()', keyPoints: ['MultiIndex for multi-dimensional data', '.xs() for cross-section', '.unstack() pivots index level to columns', '.stack() pivots columns to index'] })
addC('pandas', 'Analysis & Visualization', 'Pandas Plotting', 'Beginner', 'Quick visualization directly from DataFrames using matplotlib backend', { codeExample: 'import pandas as pd\nimport matplotlib.pyplot as plt\n\ndf = pd.DataFrame({\n    "date": pd.date_range("2024-01-01", periods=100, freq="D"),\n    "sales": np.random.randn(100).cumsum() + 100,\n    "category": np.random.choice(["A", "B", "C"], 100)\n})\n\n# Line plot\ndf.plot(x="date", y="sales", title="Sales Over Time")\n\n# Bar plot\ndf.groupby("category")["sales"].sum().plot(kind="bar")\n\n# Histogram\ndf["sales"].plot(kind="hist", bins=30)\n\n# Box plot\ndf.boxplot(column="sales", by="category")\n\n# Scatter plot\ndf.plot.scatter(x="date", y="sales", alpha=0.5)\n\n# Area plot\ndf.groupby("category")["sales"].sum().plot(kind="area")\n\n# Subplots\ndf.plot(subplots=True, figsize=(10, 8))\n\nplt.tight_layout()\nplt.show()\n\n# Customization\ndf.plot(color="red", linestyle="--", linewidth=2, grid=True)', keyPoints: ['Line, bar, histogram, box, scatter, area', 'Built-in matplotlib integration', 'Groupby + plot for aggregated views', 'Customize with kwargs passed to matplotlib'] })
addC('pandas', 'Performance & Best Practices', 'Method Chaining & Pipe', 'Intermediate', 'Writing readable data pipelines with method chaining and pipe()', { codeExample: 'import pandas as pd\nimport numpy as np\n\n# Method chaining\ndf = (\n    pd.read_csv("data.csv")\n    .query("age > 25")\n    .assign(\n        age_group=lambda x: pd.cut(x["age"], bins=[0, 30, 50, 100], labels=["Young", "Middle", "Senior"]),\n        income_category=lambda x: np.where(x["income"] > 50000, "High", "Low")\n    )\n    .groupby(["age_group", "income_category"])\n    .agg(avg_income=("income", "mean"), count=("name", "count"))\n    .reset_index()\n    .sort_values("avg_income", ascending=False)\n)\n\n# Custom function with .pipe()\ndef add_features(df):\n    return df.assign(\n        income_per_age=df["income"] / df["age"],\n        log_income=np.log1p(df["income"])\n    )\n\ndef filter_outliers(df, column, std_thresh=3):\n    mean = df[column].mean()\n    std = df[column].std()\n    return df[abs(df[column] - mean) <= std_thresh * std]\n\nresult = (\n    pd.read_csv("data.csv")\n    .pipe(add_features)\n    .pipe(filter_outliers, "income", 3)\n    .pipe(lambda x: x[x["age"] > 18])\n)', keyPoints: ['Method chaining for readability', '.pipe() for custom functions', 'Chain maintains intermediate scope', 'Easier debugging with .pipe'] })
// ========== SECURITY NEW CONCEPTS ==========
addC('security', 'Authentication & Authorization', 'RBAC vs ABAC', 'Intermediate', 'Role-Based vs Attribute-Based Access Control models', { codeExample: '// RBAC (Role-Based Access Control)\n// Users have roles, roles have permissions\nconst roles = {\n  admin: ["read", "write", "delete", "manage_users"],\n  editor: ["read", "write"],\n  viewer: ["read"]\n};\n\nfunction checkPermission(user, action) {\n  return roles[user.role]?.includes(action) ?? false;\n}\n\n// ABAC (Attribute-Based Access Control)\n// Access decisions based on user/resource/environment attributes\nconst abacPolicies = [\n  {\n    effect: "allow",\n    condition: {\n      user_role: "manager",\n      resource_department: { eq: "$user.department" },\n      action: { in: ["read", "update"] }\n    }\n  },\n  {\n    effect: "deny",\n    condition: {\n      action: "delete",\n      resource_owner: { neq: "$user.id" }\n    }\n  }\n];\n\nfunction evaluateABAC(user, resource, action, context) {\n  // Evaluate all policies against attributes\n  // More flexible but complex to implement\n  return true; // simplified\n}\n\n// Comparison:\n// RBAC: simpler, fewer permissions, role explosion\n// ABAC: fine-grained, policy-based, complex to manage', keyPoints: ['RBAC: role->permission mapping', 'ABAC: attribute-based rules', 'RBAC simpler for basic needs', 'ABAC for complex, context-aware access'] })
addC('security', 'Web Security', 'Content Security Policy (CSP)', 'Intermediate', 'Browser security mechanism to prevent XSS and data injection attacks', { codeExample: '// CSP Header - strict policy\n// Content-Security-Policy:\n//   default-src \'self\';\n//   script-src \'self\' https://cdn.example.com;\n//   style-src \'self\' \'unsafe-inline\';\n//   img-src \'self\' data: https:;\n//   font-src \'self\' https://fonts.gstatic.com;\n//   connect-src \'self\' https://api.example.com;\n//   frame-ancestors \'none\';\n//   form-action \'self\';\n//   base-uri \'self\';\n//   object-src \'none\';\n\n// Via meta tag (less secure than header)\n// <meta http-equiv="Content-Security-Policy"\n//   content="default-src \'self\'; script-src \'self\'">\n\n// Nonce-based CSP (for inline scripts)\n// const nonce = crypto.randomBytes(16).toString("base64");\n// res.setHeader("Content-Security-Policy",\n//   `script-src \'self\' \'nonce-${nonce}\'`);\n\n// Reporting\n// Content-Security-Policy-Report-Only:\n//   default-src \'self\'; report-uri /csp-report;\n\n// Strict CSP (recommended)\n// script-src \'strict-dynamic\' \'nonce-{random}\' https: \'unsafe-inline\';\n// object-src \'none\';\n// base-uri \'none\';', keyPoints: ['CSP prevents XSS even if injection occurs', 'Avoid unsafe-inline for scripts', 'Use nonce or hash for inline scripts', 'Report-Only mode for testing'] })
addC('security', 'Cryptography & Network Security', 'TLS 1.3 Handshake', 'Intermediate', 'Secure connection establishment with 1-RTT or 0-RTT', { codeExample: '// TLS 1.3 Handshake (1-RTT):\n// ClientHello\n//   - Key share (public key)\n//   - Supported versions, ciphersuites\n// ServerHello\n//   - Key share\n//   - Certificate + signature\n// Client -> Server: Finished\n// Server -> Client: Finished\n// -> Encrypted application data\n\n// 0-RTT (early data):\n// Client sends data in first flight (requires prior session)\n// Risk: replay attacks\n\n// Key differences from TLS 1.2:\n// - 1 round trip vs 2 (faster)\n// - Removed insecure cipher suites\n// - Modern key exchange only (ECDHE, DHE)\n// - 0-RTT for returning visitors\n\n// Perfect Forward Secrecy\n// - Ephemeral Diffie-Hellman keys per session\n// - Compromised private key can\'t decrypt past sessions\n\n// Supported ciphersuites in TLS 1.3:\n// TLS_AES_256_GCM_SHA384\n// TLS_CHACHA20_POLY1305_SHA256\n// TLS_AES_128_GCM_SHA256\n\n// Node.js TLS config\nconst tls = require("tls");\nconst options = {\n  minVersion: "TLSv1.2",\n  ciphers: [\n    "TLS_AES_256_GCM_SHA384",\n    "TLS_CHACHA20_POLY1305_SHA256"\n  ].join(":"),\n  honorCipherOrder: true\n};', keyPoints: ['1-RTT handshake (vs 2 in TLS 1.2)', '0-RTT for fast resumption', 'Perfect Forward Secrecy by default', 'Removed weak ciphers and algorithms'] })
// ========== DBMS NEW CONCEPTS ==========
addC('dbms', 'Database Design & Modeling', 'ER-to-Relational Mapping', 'Intermediate', 'Converting Entity-Relationship diagrams to relational database schema', { codeExample: '// Mapping rules:\n// 1. Regular entity -> Table\n// 2. Weak entity -> Table with FK to owner\n// 3. Binary 1:N -> Add FK in N-side\n// 4. Binary M:N -> Junction table\n// 5. Multivalued attribute -> Separate table\n// 6. Composite attribute -> Flatten into columns\n\n// Example: Student-Course ER to Relational\n// Entity: Student(student_id, name, address)\n// Entity: Course(course_id, title, credits)\n// Relationship: Enrolls(M:N) with grade attribute\n\nCREATE TABLE Student (\n    student_id INT PRIMARY KEY,\n    name VARCHAR(100),\n    street VARCHAR(100),\n    city VARCHAR(50),\n    zip VARCHAR(10)\n);\n\nCREATE TABLE Course (\n    course_id INT PRIMARY KEY,\n    title VARCHAR(200),\n    credits INT\n);\n\nCREATE TABLE Enrolls (\n    student_id INT,\n    course_id INT,\n    grade CHAR(2),\n    semester VARCHAR(20),\n    PRIMARY KEY (student_id, course_id),\n    FOREIGN KEY (student_id) REFERENCES Student(student_id),\n    FOREIGN KEY (course_id) REFERENCES Course(course_id)\n);\n\n// Specialization/Generalization:\n// Option A: All in one table with type discriminator\n// Option B: Separate tables for each subclass\n// Option C: Base table + subclass tables (shared key)', keyPoints: ['Regular entities become tables', 'Relationships become FKs or junction tables', 'M:N always needs junction table', 'Multi-valued attributes get separate table'] })
addC('dbms', 'Transaction Management', 'Logging (WAL, Redo, Undo)', 'Advanced', 'Write-ahead logging for crash recovery: redo and undo operations', { codeExample: '// Write-Ahead Logging (WAL) Protocol:\n// 1. Log record written before data page\n// 2. Each log record has LSN (Log Sequence Number)\n// 3. Dirty page table tracks unflushed pages\n// 4. Transaction table tracks active transactions\n\n// Log record structure:\n// <LSN, TransID, PageID, Redo, Undo, PrevLSN>\n\n// ARIES Recovery Algorithm (3 phases):\n\n// Phase 1: Analysis\n// - Scan log from last checkpoint forward\n// - Build dirty page table\n// - Find active transactions\n\n// Phase 2: Redo (roll forward)\n// - Reapply all changes from last checkpoint\n// - Even uncommitted transactions (will undo later)\n// - Idempotent: safe to redo\n\n// Phase 3: Undo (roll back)\n// - Undo active transactions (oldest first)\n// - Generate compensation log records (CLR)\n// - CLRs logged for durability\n\n// Checkpointing:\n// - Periodic: write dirty pages + active transactions\n// - Fuzzy checkpoint: no need to stop everything\n\n// Steal/Force policies:\n// STEAL: dirty pages can be flushed before commit\n// NO-STEAL: dirty pages stay until commit\n// FORCE: all dirty pages flushed at commit\n// NO-FORCE: dirty pages flushed later (need REDO)\n\n// ARIES uses STEAL/NO-FORCE (best performance)', keyPoints: ['WAL: log before data write', 'ARIES: Analysis, Redo, Undo', 'STEAL/NO-FORCE for performance', 'CLRs ensure undo is durable'] })
addC('dbms', 'NoSQL & Distributed Databases', 'ACID vs BASE', 'Intermediate', 'Comparing consistency models: ACID (traditional) vs BASE (NoSQL)', { codeExample: '// ACID (SQL databases)\n// A: Atomicity - all or nothing\n// C: Consistency - valid state\n// I: Isolation - transactions don\'t interfere\n// D: Durability - committed data persists\n\n// BASE (NoSQL databases)\n// BA: Basically Available - system stays operational\n// S: Soft State - state changes over time\n// E: Eventual Consistency - converges eventually\n\n// Trade-off comparison:\n\n// ACID strengths:\n// - Strong consistency guarantees\n// - Easy to reason about (programmer-friendly)\n// - Complex joins and transactions\n\n// BASE strengths:\n// - High availability and partition tolerance\n// - Horizontal scalability\n// - Better performance under partition\n\n// When to use ACID:\n// - Financial transactions\n// - Inventory management\n// - Systems requiring strong consistency\n\n// When to use BASE:\n// - Social media feeds\n// - Product catalogues\n// - Analytics systems\n\n// CAP theorem perspective:\n// ACID -> CP (consistency over availability)\n// BASE -> AP (availability over consistency)\n\n// Some systems blur the line:\n// - NewSQL (CockroachDB, Spanner): ACID with scale\n// - MongoDB 4.0+: multi-document transactions', keyPoints: ['ACID: strong consistency, lower availability', 'BASE: high availability, eventual consistency', 'CAP theorem drives the choice', 'Modern DBs blur the boundary (NewSQL)'] })
// ========== OOP NEW CONCEPTS ==========
addC('oop', 'Principles & Design', 'Encapsulation (Deep Dive)', 'Beginner', 'Data hiding with controlled access: private fields, public methods, properties', { codeExample: '// Proper encapsulation example (C#)\npublic class BankAccount\n{\n    private decimal _balance;\n    private readonly string _accountNumber;\n    private readonly List<string> _transactions = new();\n\n    public decimal Balance\n    {\n        get { return _balance; }\n        private set { _balance = value; }\n    }\n\n    public string AccountNumber => _accountNumber;\n\n    public bool Deposit(decimal amount)\n    {\n        if (amount <= 0) return false;\n        Balance += amount;\n        _transactions.Add($"Deposit: {amount:C}");\n        return true;\n    }\n\n    public bool Withdraw(decimal amount)\n    {\n        if (amount <= 0 || amount > _balance) return false;\n        Balance -= amount;\n        _transactions.Add($"Withdrawal: {amount:C}");\n        return true;\n    }\n\n    public IReadOnlyList<string> GetTransactionHistory()\n    {\n        return _transactions.AsReadOnly();\n    }\n}\n\n// Benefits:\n// - Internal state protected from invalid changes\n// - Validation maintained in one place\n// - Implementation can change without breaking callers\n// - Clear public interface contract', keyPoints: ['Private/protected fields with public accessors', 'Validation in setters prevents invalid state', 'Read-only exposure for internal data', 'Separating interface from implementation'] })
addC('oop', 'Principles & Design', 'Dependency Injection & Inversion', 'Intermediate', 'Decoupling high-level modules from low-level implementations via injection', { codeExample: '// Without DI (tight coupling)\nclass EmailService {\n    void Send(string to, string msg) {\n        // Direct SMTP implementation\n    }\n}\nclass Notification {\n    private EmailService _email = new();  // hard dependency\n    public void Notify(string user, string msg) => _email.Send(user, msg);\n}\n\n// With DI (loose coupling)\ninterface IMessageService {\n    void Send(string to, string message);\n}\nclass EmailService : IMessageService {\n    public void Send(string to, string msg) => /* SMTP */;\n}\nclass SmsService : IMessageService {\n    public void Send(string to, string msg) => /* Twilio */;\n}\nclass Notification {\n    private readonly IMessageService _svc;\n    public Notification(IMessageService svc) => _svc = svc;\n    public void Notify(string user, string msg) => _svc.Send(user, msg);\n}\n\n// Usage with DI container\n// services.AddTransient<IMessageService, EmailService>();\n// var notification = new Notification(new EmailService());\n// notification.Notify("user@test.com", "Hello from DI!");\n\n// Benefits:\n// - Easier unit testing (mock interfaces)\n// - Swap implementations without changing consumers\n// - Dependencies visible and explicit', keyPoints: ['Constructor injection most common', 'DIP: depend on abstractions, not concretions', 'DI container manages wiring', 'Improves testability with mocks'] })
addC('oop', 'Principles & Design', 'GRASP Patterns', 'Intermediate', 'General Responsibility Assignment Software Patterns for OO design', { codeExample: '// GRASP patterns:\n\n// 1. Information Expert\n// Assign responsibility to class with needed information\nclass Order {\n    private List<OrderItem> _items;\n    public double GetTotal() =>  // Order is expert\n        _items.Sum(i => i.Price * i.Quantity);\n}\n\n// 2. Creator\n// Create objects when a class contains/composes them\nclass ShoppingCart {\n    // Cart "contains" items, so create them\n    public OrderItem AddItem(Product p, int qty) =>\n        new OrderItem(p, qty);\n}\n\n// 3. Controller\n// Mediates between UI and domain logic\nclass OrderController {\n    private readonly OrderService _svc;\n    public ActionResult Checkout(CartDto dto) =>\n        _svc.ProcessOrder(dto);\n}\n\n// 4. Low Coupling / High Cohesion\n// - Low Coupling: minimal dependencies between classes\n// - High Cohesion: related responsibilities grouped together\n\n// 5. Polymorphism\n// Use polymorphic behavior instead of conditionals\ninterface IPaymentProcessor {\n    bool Process(decimal amount);\n}\nclass CreditCardProcessor : IPaymentProcessor { ... }\nclass PayPalProcessor : IPaymentProcessor { ... }\n\n// 6. Indirection\n// Use intermediate to decouple components (e.g., Repository pattern)\n\n// 7. Pure Fabrication\n// Create class for low coupling even if not real-world concept\n// (e.g., Repository, Service, Factory classes)', keyPoints: ['Expert: assign to class with data', 'Creator: composition implies creation', 'Controller: mediates UI/domain', 'High Cohesion + Low Coupling ideal'] })
// ========== OS NEW CONCEPTS ==========
addC('os', 'Process & Thread Management', 'Process Scheduling (MLFQ)', 'Advanced', 'Multi-Level Feedback Queue: dynamic priority scheduling for general-purpose systems', { codeExample: '// MLFQ Scheduling Algorithm\n// Goals:\n// - Minimize response time for interactive jobs\n// - Maximize CPU utilization for batch jobs\n// - No a priori knowledge of job length needed\n\n// Rules:\n// Rule 1: Priority = queue number (lower = higher priority)\n// Rule 2: Round-robin within each queue (time quantum varies)\n// Rule 3: Job starts in highest priority queue\n// Rule 4: If job uses full quantum, move down one level\n// Rule 5: After time slice (periodic), move all jobs back to top\n\n// Example: 3 queues, time quantum Q1=5ms, Q2=10ms, Q3=20ms\n// Queue 0 (highest): Quantum = 5ms\n// Queue 1: Quantum = 10ms\n// Queue 2 (lowest): FCFS\n\n// Process schedule:\n// P1: CPU burst 30ms\n// Queue 0 -> runs 5ms (full quantum) -> Queue 1\n// Queue 1 -> runs 10ms (full quantum) -> Queue 2\n// Queue 2 -> runs 15ms (completes)\n\n// Priority boost (Rule 5):\n// Every 100ms, move all jobs to Queue 0\n// Prevents starvation of long-running processes\n\n// Variations:\n// - Solaris: 60 queues with configurable quantum\n// - Linux: MLFQ + nice values (CFS is primary)\n// - Windows: 32 priority levels with dynamic boosting', keyPoints: ['MLFQ balances interactive and batch jobs', 'Priority boost prevents starvation', 'Shorter quantum for higher priority queues', 'Used in most general-purpose OS kernels'] })
addC('os', 'Memory Management', 'TLB (Translation Lookaside Buffer)', 'Intermediate', 'Hardware cache for virtual-to-physical address translation', { codeExample: '// TLB Operation\n// CPU generates virtual address ->\n// Check TLB (hardware, < 1ns):\n//   - TLB hit: immediate physical address\n//   - TLB miss: walk page tables (100-200ns)\n// -> Access memory\n\n// TLB Miss handling:\n// Hardware-managed (x86): CPU walks page tables\n// Software-managed (MIPS/RISC): OS handles miss\n\n// TLB structure:\n// Valid | Tag (VPN) | PPN | ASID | Protection\n// -------------------------------------------------\n//  1   |  0x1A3   | 0x4F |  42  |  R/W\n//  0   |   ---    | --- | ---  |  ---\n//  1   |  0x200   | 0x80 |  15  |  R\n\n// ASID (Address Space ID):\n// - TLBs don\'t flush on context switch\n// - ASID identifies process (64-4096 entries)\n// - Eliminates TLB flush overhead\n\n// TLB Reach = TLB_entries * Page_size\n// For 64 entries * 4KB = 256KB\n// Too small for modern workloads -> large pages (2MB/1GB)\n\n// TLB Performance:\n// Effective Access Time = HitRate * HitTime + MissRate * MissPenalty\n// With 99% hit rate, 1ns hit, 200ns miss:\n// EAT = 0.99 * 1 + 0.01 * 200 = 2.99ns\n\n// Multi-level TLBs:\n// L1 TLB: small, fast (8-64 entries, <0.5ns)\n// L2 TLB: larger, slower (512-2048 entries, ~5ns)', keyPoints: ['TLB caches page translations', 'ASID avoids flush on context switch', 'Large pages increase TLB reach', 'Multi-level TLBs for performance'] })
addC('os', 'File Systems & I/O', 'Inode & VFS Architecture', 'Intermediate', 'Inode-based file systems and Virtual File System abstraction layer', { codeExample: '// Inode structure (ext4 example)\n// struct ext4_inode {\n//   __le16  i_mode;       // File type + permissions\n//   __le16  i_uid;        // Owner UID\n//   __le32  i_size;       // Size in bytes\n//   __le32  i_atime;      // Access time\n//   __le32  i_ctime;      // Change time\n//   __le32  i_mtime;      // Modify time\n//   __le32  i_dtime;      // Delete time\n//   __le16  i_links_count; // Hard link count\n//   __le32  i_blocks;     // Number of 512B blocks\n//   __le32  i_block[15];  // Direct/Indirect block pointers\n//   ...\n// };\n\n// Inode data block pointers (ext4):\n// Block 0-11:  Direct pointers (12 * 4KB = 48KB)\n// Block 12:    Single indirect (1024 * 4KB = 4MB)\n// Block 13:    Double indirect (1024^2 * 4KB = 4GB)\n// Block 14:    Triple indirect (1024^3 * 4KB = 4TB)\n// Max file size: ~4TB (with 4KB blocks)\n\n// VFS (Virtual File System):\n// - Abstract layer between user and real file systems\n// - Common operations: open, read, write, close, etc.\n// - Supports ext4, NTFS, XFS, Btrfs, NFS, etc.\n\n// VFS objects:\n// - super_block: file system info\n// - inode: file metadata\n// - dentry: directory entry (path component)\n// - file: open file descriptor\n\n// Linux VFS operation table:\n// struct file_operations {\n//     read, write, mmap, open, release,\n//     fsync, lock, flush, ...\n// };', keyPoints: ['Inode stores metadata, not filename', 'Multi-level indexing handles large files', 'VFS enables multiple FS under one interface', 'dentry cache speeds path lookups'] })
addC('os', 'Process & Thread Management', 'Context Switch Overhead', 'Intermediate', 'Cost of switching between processes context', { codeExample: '// Context switch steps:\n// 1. Trap/interrupt/exception -> kernel mode\n// 2. Save CPU registers (PC, SP, FP, GPRs)\n// 3. Save kernel stack pointer\n// 4. Change MMU page table / TLB flush\n// 5. Update scheduler data structures\n// 6. Load new process state\n// 7. Restore registers + kernel stack\n// 8. Return to user mode\n\n// Costs:\n// Direct costs:\n// - Register save/restore: ~0.5-1us\n// - TLB flush: ~10-100us\n// - Cache pollution (working set lost)\n// - Branch predictor state lost\n\n// Indirect costs:\n// - Cold cache restart (hundreds of us)\n// - TLB refill for new process\n\n// Performance impact:\n// Context switch: ~1-12us (direct)\n// + Cache warmup: ~100-1000us\n\n// Thread vs Process switch:\n// Process switch: TLB + address space switch\n// Thread switch: registers only (same address space)\n// (10-50x faster for threads)\n\n// Reducing context switch overhead:\n// - Larger time slices (but worse response time)\n// - Use threads instead of processes\n// - Async I/O (avoid blocking)\n// - CPU affinity (keep on same core)\n// - Lock-free data structures\n\n// Linux context switch in numbers:\n// 1000 context switches/second: <1% CPU overhead\n// 100,000 context switches/second: ~10-30% overhead\n// >1,000,000 context switches/second: severe degradation', keyPoints: ['Direct cost: register save, TLB flush', 'Indirect cost: cache warmup dominates', 'Threads cheaper than processes', 'CPU affinity reduces migration cost'] })
// ========== NETWORKS NEW CONCEPTS ==========
addC('networks', 'Application Layer', 'REST vs gRPC', 'Intermediate', 'Comparing two dominant API communication paradigms', { codeExample: '// REST (Representational State Transfer)\n// - HTTP/1.1 or HTTP/2\n// - Text-based (JSON/XML)\n// - Resource-oriented (CRUD on resources)\n// - Client-driven (pull model)\n\nGET /api/users/42 HTTP/1.1\nAccept: application/json\n\nHTTP/1.1 200 OK\nContent-Type: application/json\n\n{\n  "id": 42,\n  "name": "Alice",\n  "email": "alice@example.com"\n}\n\n// gRPC (Google Remote Procedure Call)\n// - HTTP/2 (multiplexed, streaming)\n// - Binary (Protocol Buffers)\n// - Service-oriented (defined RPC methods)\n// - Bidirectional streaming\n\n// .proto definition\nservice UserService {\n  rpc GetUser (GetUserRequest) returns (User);\n  rpc ListUsers (ListUsersRequest) returns (stream User);\n  rpc UpdateUser (stream UpdateRequest) returns (User);\n  rpc Chat (stream ChatMessage) returns (stream ChatMessage);\n}\n\nmessage User {\n  int32 id = 1;\n  string name = 2;\n  string email = 3;\n}\n\n// Advantages:\n// REST: simple, cacheable, universal, browser-native\n// gRPC: efficient (binary, streaming), typed, code-gen\n\n// When to use:\n// REST: public APIs, web apps, simple CRUD\n// gRPC: microservices, real-time streaming, high perf', keyPoints: ['REST: text, cacheable, HTTP/1.1+', 'gRPC: binary, streams, HTTP/2', 'gRPC uses Protocol Buffers for serialization', 'gRPC supports 4 call types (unary, server stream, client stream, bidirectional)'] })
addC('networks', 'Transport Layer', 'TCP Congestion Control (CUBIC)', 'Advanced', 'Modern TCP congestion control for high-bandwidth networks', { codeExample: '// CUBIC congestion control (default in Linux since 2006)\n// Replaces TCP Reno\'s AIMD\n\n// Key insight: congestion window grows as cubic function\n// W(t) = C * (t - K)^3 + Wmax\n// Where:\n//   Wmax = window size when loss detected\n//   t = time since last loss event\n//   K = cbrt(Wmax * beta / C)\n//   C = scaling constant\n//   beta = multiplicative decrease factor (0.3 default)\n\n// Phases:\n// 1. Slow start (exponential, until first loss)\n// 2. Congestion avoidance (cubic growth)\n//   - After loss: W = Wmax * beta\n//   - Fast growth away from Wmax (concave)\n//   - Slower growth near Wmax (convex)\n//   - Plateau around Wmax (probing)\n// 3. Max probing (if no loss, keep growing)\n\n// Advantages over Reno:\n// - Independent of RTT (fair to different RTTs)\n// - Better link utilization on high-BW paths\n// - Stable with varying RTT\n\n// Linux TCP variants:\n// - TCP CUBIC: default, high-BDP links\n// - TCP BBR: model-based (not loss-based)\n// - TCP Reno: original AIMD\n\n// BBR (Bottleneck Bandwidth and Round-trip)\n// - Google\'s model-based approach\n// - Measures bandwidth and RTT directly\n// - Less packet loss, higher throughput', keyPoints: ['CUBIC uses cubic function for window growth', 'Independent of RTT for fairness', 'Better for high-bandwidth links', 'BBR is model-based alternative'] })
addC('networks', 'Network Layer', 'CIDR & Subnetting', 'Intermediate', 'Classless Inter-Domain Routing for efficient IP address allocation', { codeExample: '// CIDR notation: IP/prefix_length\n// 192.168.1.0/24 means:\n//   Network bits: 24 (first 3 octets)\n//   Host bits: 8 (last octet)\n//   Netmask: 255.255.255.0\n\n// Subnetting example:\n// Given: 10.0.0.0/16 (65,536 addresses)\n// Need: 4 subnets with at least 1000 hosts each\n\n// Step 1: Determine host bits needed\n// 2^10 = 1024 >= 1000 -> 10 host bits\n// Prefix = 32 - 10 = 22\n\n// Step 2: Subnets\n// 10.0.0.0/22   (10.0.0.0 - 10.0.3.255)\n// 10.0.4.0/22   (10.0.4.0 - 10.0.7.255)\n// 10.0.8.0/22   (10.0.8.0 - 10.0.11.255)\n// 10.0.12.0/22  (10.0.12.0 - 10.0.15.255)\n\n// Step 3: Subnet mask = 255.255.252.0\n// 11111111.11111111.11111100.00000000\n\n// VLSM (Variable Length Subnet Masking)\n// Different subnets can have different sizes\n// 10.0.0.0/24 (254 hosts) for servers\n// 10.0.1.0/25 (126 hosts) for workstations\n// 10.0.1.128/26 (62 hosts) for printers\n\n// Supernetting (route aggregation)\n// 192.168.0.0/24 + 192.168.1.0/24 -> 192.168.0.0/23\n// Reduces routing table size', keyPoints: ['CIDR: IP/prefix notation', '2^(32-prefix) - 2 = usable hosts', 'VLSM: variable subnet sizes', 'Supernetting aggregates routes'] })
addC('networks', 'Application Layer', 'HTTP/2 & HTTP/3', 'Intermediate', 'Evolution of HTTP protocol for performance', { codeExample: '// HTTP/1.1 (1997)\n// - Text-based, request-response\n// - Head-of-line blocking (one request at a time per connection)\n// - 6-8 parallel connections per domain (workaround)\n// - Header compression: none\n// - Server push: none\n\nGET /style.css HTTP/1.1\nHost: example.com\n// Wait for response -> then next request\n\n// HTTP/2 (2015)\n// - Binary framing layer\n// - Multiplexed streams over one TCP connection\n// - Header compression (HPACK)\n// - Server push\n// - Stream prioritization\n\n// Stream 1: HEADERS frame (GET /index.html)\n// Stream 3: HEADERS frame (GET /style.css)\n// Stream 5: HEADERS frame (GET /app.js)\n// All frames interleaved over single TCP connection\n\n// HTTP/3 (2022)\n// - QUIC over UDP (not TCP)\n// - 0-RTT connection establishment\n// - No TCP head-of-line blocking\n// - Connection migration (IP changes)\n// - Built-in encryption (no TLS over TCP)\n\n// Performance comparison:\n// HTTP/1.1: 1 request/response per connection\n// HTTP/2: multiplexed, but TCP HOL blocking\n// HTTP/3: no HOL blocking, faster connection setup\n\n// HTTP/2 HOL blocking example:\n// TCP packet lost on stream 1 -> all streams blocked\n// HTTP/3 (QUIC) fixes this: loss on stream 1 doesn\'t affect others', keyPoints: ['HTTP/2: binary, multiplexed, HPACK', 'HTTP/3: QUIC (UDP), no HOL blocking', 'HTTP/2 still has TCP-level HOL blocking', 'HTTP/3 supports connection migration'] })
// ========== SYSTEM DESIGN NEW CONCEPTS ==========
addC('system-design', 'Core Concepts & Trade-offs', 'Latency vs Throughput', 'Beginner', 'Understanding and balancing latency (response time) and throughput (requests/sec)', { codeExample: '// Latency vs Throughput trade-off\n\n// Scenario: Web server handling requests\n// Single-threaded (one request at a time)\n// Latency: 10ms per request\n// Throughput: 100 requests/sec (1000ms / 10ms)\n\n// Multi-threaded (10 concurrent threads)\n// Latency: 10ms + scheduling overhead (~1ms) = 11ms\n// Throughput: ~900 requests/sec\n// (1000ms / 11ms * 10 threads)\n\n// Factors affecting trade-off:\n// - Queueing: increased throughput -> longer queues -> higher latency\n// - Batching: collect requests, process together\n//   (higher throughput, but individual latency increases)\n// - Compression: longer time to compress, less data to transfer\n\n// Little\'s Law: L = lambda * W\n// L = average number in system\n// lambda = arrival rate\n// W = average time in system\n\n// Example: 1000 req/sec arrival, 50ms average latency\n// L = 1000 req/s * 0.05s = 50 requests in system\n\n// Load shedding:\n// When queue > threshold, reject requests (drop for throughput)\n\n// Techniques to improve both:\n// - Caching (reduce processing time)\n// - CDN (reduce network latency)\n// - Connection pooling (reduce setup time)\n// - Async processing (non-blocking I/O)', keyPoints: ['Latency: time per request (optimize for UX)', 'Throughput: requests/sec (optimize for cost)', 'Often in tension: higher throughput can increase latency', 'Little\'s Law relates queue, arrival rate, latency'] })
addC('system-design', 'Storage & Data', 'Caching Strategies (Read/Write)', 'Intermediate', 'Cache patterns: cache-aside, read-through, write-through, write-back', { codeExample: '// 1. Cache-Aside (Lazy Loading)\n// Application checks cache first, falls back to DB\nfunc getUser(id string) User {\n    user := cache.get("user:" + id)\n    if user == nil {\n        user = db.getUser(id)\n        cache.set("user:" + id, user, ttl=1h)\n    }\n    return user\n}\n\n// 2. Read-Through\n// Cache layer automatically fetches from DB on miss\n// Application just calls cache\nfunc getUser(id string) User {\n    return cache.get("user:" + id)\n    // cache internally: miss -> load from DB -> populate cache\n}\n\n// 3. Write-Through\n// Every write goes to cache first, cache writes to DB synchronously\nfunc updateUser(id string, data User) {\n    cache.set("user:" + id, data)\n    db.updateUser(id, data)\n    // High latency on writes, but cache always consistent\n}\n\n// 4. Write-Back (Write-Behind)\n// Write to cache, async write to DB later\nfunc updateUser(id string, data User) {\n    cache.set("user:" + id, data)\n    // Async: db.updateUser(id, data)  // batched, delayed\n}\n\n// 5. Write-Around\n// Write directly to DB, invalidate cache\nfunc updateUser(id string, data User) {\n    db.updateUser(id, data)\n    cache.del("user:" + id)\n}\n\n// Comparison:\n// | Strategy      | Read perf | Write perf | Consistency |\n// |--------------|-----------|------------|-------------|\n// | Cache-Aside  | Fast miss | Fast       | Eventually  |\n// | Read-Through | Fast miss | Fast       | Eventually  |\n// | Write-Through| Fast      | Slow       | Strong      |\n// | Write-Back   | Fast      | Very fast  | Eventually  |', keyPoints: ['Cache-aside: most common, app-managed', 'Write-through: strong consistency, slower writes', 'Write-back: fast writes, risk of data loss', 'TTL-based invalidation prevents stale data'] })
addC('system-design', 'Reliability & Consistency', 'Quorum & Consistency Levels', 'Advanced', 'W/R quorum for read/write consistency in distributed systems', { codeExample: '// Quorum definitions:\n// N = total replicas\n// W = write quorum (acks needed for write success)\n// R = read quorum (nodes to query for read)\n\n// Consistency guarantees:\n// W + R > N  -> Strong consistency (read sees latest write)\n// W + R <= N -> Eventual consistency\n// W = N      -> Slow writes, but guaranteed durability\n// R = 1      -> Fast reads, may return stale data\n\n// Example: N = 3 (3 replicas)\n\n// Strong consistency (W=2, R=2):\n// Write: must ack from 2/3 nodes\n// Read: must query 2/3 nodes, pick latest version\n// W+R = 4 > 3 => at least one overlapping node\n// |- Write -|----- Read -----|\n//  1,2,3     1,2,3\n//  ^^          ^^\n// W=2 ack     R=2 query => overlap guaranteed\n\n// Eventual consistency (W=1, R=1):\n// Fastest but might read stale data\n\n// Cassandra consistency levels:\n// Write: ONE, QUORUM, ALL, EACH_QUORUM, LOCAL_QUORUM\n// Read: ONE, QUORUM, ALL, LOCAL_QUORUM, SERIAL\n\n// DynamoDB consistency:\n// Eventual (eventually consistent read)\n// Strong (consistent read, costs more RCUs)\n\n// Sloppy quorum:\n// Accept writes even if not on assigned nodes\n// Hinted handoff sends to correct node later\n// Improves availability during partition\n\n// Vector clocks for causality tracking\n// {node: counter} pairs to detect concurrent updates', keyPoints: ['W+R > N guarantees strong consistency', 'Tuning W/R balances performance vs consistency', 'Sloppy quorum improves availability', 'Vector clocks resolve conflicting writes'] })
addC('system-design', 'Architecture & Patterns', 'Microservices Communication Patterns', 'Intermediate', 'Patterns for service-to-service communication in microservices', { codeExample: '// 1. Synchronous (Request-Response)\n//   - HTTP REST (simple, universal)\n//   - gRPC (efficient, typed, streaming)\n//   - GraphQL (flexible queries)\n//   Pros: simple, low latency\n//   Cons: tight coupling, cascading failures\n\n// 2. Asynchronous (Message Queue)\n//   - Kafka, RabbitMQ, SQS\n//   - Producer sends event, one consumer processes\n//   Pros: decoupling, buffering, fault tolerance\n//   Cons: complexity, eventual consistency\n\n// 3. Event-Driven (Pub/Sub)\n//   - Kafka, Redis Pub/Sub, EventBridge\n//   - One event, multiple subscribers\n//   - Event sourcing: store events as source of truth\n//   - CQRS: separate read/write models\n//   Pros: loose coupling, extensible, audit log\n//   Cons: debugging hard, eventual consistency\n\n// 4. Service Mesh\n//   - Sidecar proxy (Envoy, Linkerd)\n//   - Handles: retry, timeout, circuit breaker, tracing\n//   - Transparent to application code\n//   Pros: uniform infrastructure, observability\n//   Cons: additional latency, operational complexity\n\n// Patterns for reliability:\n// - Circuit Breaker: stop calling failing service\n// - Retry with backoff: exponential + jitter\n// - Bulkhead: isolate resources per service\n// - Saga: distributed transaction (orchestration/choreography)\n// - Health check + service discovery\n\n// Monitoring:\n// Distributed tracing (Jaeger, Zipkin)\n// Centralized logging (ELK stack)\n// Metrics (Prometheus + Grafana)', keyPoints: ['Sync: simple, tight coupling', 'Async: decoupled, eventual consistency', 'Event-driven: pub/sub, event sourcing', 'Service mesh: infrastructure layer for communication'] })
// ========== BUILD FUNCTION ==========
function build() {
  var L = [];
  L.push('var INTERVIEW_DATA = {');
  for (var ci = 0; ci < courses.length; ci++) {
    var cid = courses[ci].id, t = courses[ci].title, icon = courses[ci].icon, col = courses[ci].color, topics = courses[ci].topics;
    L.push('  ' + q(cid) + ': {');
    L.push("    title: " + q(t) + ", icon: " + q(icon) + ", color: " + q(col) + ",");
    L.push('    topics: [');
    for (var ti = 0; ti < topics.length; ti++) {
      var topic = topics[ti];
      L.push('      { name: ' + q(topic.name) + ', concepts: [');
      for (var xi = 0; xi < topic.concepts.length; xi++) {
        var con = topic.concepts[xi];
        var parts = [];
        parts.push('{ term: ' + q(con.term) + ', difficulty: ' + q(con.difficulty));
        if (con.definition) parts.push('definition: ' + q(con.definition));
        if (con.codeExample) parts.push('codeExample: ' + q(con.codeExample));
        if (con.codeOutput) parts.push('codeOutput: ' + q(con.codeOutput));
        if (con.keyPoints) parts.push('keyPoints: ' + arr(con.keyPoints));
        if (con.commonMistakes && con.commonMistakes.length > 0) parts.push('commonMistakes: ' + arr(con.commonMistakes));
        if (con.followUps && con.followUps.length > 0) parts.push('followUps: ' + arr(con.followUps));
        if (con.compareWith) parts.push('compareWith: ' + q(con.compareWith));
        if (con.scenario) parts.push('scenario: ' + q(con.scenario));
        if (con.bugCode) parts.push('bugCode: ' + q(con.bugCode));
        if (con.bugExplanation) parts.push('bugExplanation: ' + q(con.bugExplanation));
        if (con.fixedCode) parts.push('fixedCode: ' + q(con.fixedCode));
        if (con.fixedOutput) parts.push('fixedOutput: ' + q(con.fixedOutput));
        if (con.realWorld) parts.push('realWorld: ' + q(con.realWorld));
        if (con.codeExplanation) parts.push('codeExplanation: ' + q(con.codeExplanation));
        if (con.practice) parts.push('practice: ' + q(con.practice));
        if (con.systemDesign) parts.push('systemDesign: ' + q(con.systemDesign));
        L.push('        ' + parts.join(',\n            ') + ' }' + (xi < topic.concepts.length - 1 ? ',' : ''));
      }
      L.push('      ]}' + (ti < topics.length - 1 ? ',' : ''));
    }
    L.push('    ]');
    L.push('  }' + (ci < courses.length - 1 ? ',' : ''));
  }
  L.push('};');
  return L.join('\n');
}

