addC('python', 'OOP in Python', 'Property Decorators', 'Intermediate', '@property for computed attributes with getter/setter/deleter', { codeExample: "class Temperature:\n    def __init__(self, celsius):\n        self._celsius = celsius\n    @property\n    def fahrenheit(self):\n        return self._celsius * 9/5 + 32\n    @fahrenheit.setter\n    def fahrenheit(self, value):\n        self._celsius = (value - 32) * 5/9", keyPoints: ['@property makes method read-only attribute', 'setter/deleter for controlled access', 'Computed attributes without explicit method calls'] })
addC('python', 'Advanced Python', 'Generators & yield', 'Intermediate', 'Functions producing values lazily with yield, maintaining state', { codeExample: 'def fibonacci():\n    a, b = 0, 1\n    while True:\n        yield a\n        a, b = b, a + b\n\nfib = fibonacci()\nfirst_10 = [next(fib) for _ in range(10)]', keyPoints: ['yield suspends and resumes state', 'Generator functions return iterators', 'Memory efficient for large sequences'] })
addC('python', 'Advanced Python', 'Logging Module', 'Beginner', 'Built-in logging with levels, handlers, and formatters', { codeExample: 'import logging\nlogging.basicConfig(level=logging.INFO, format="%(asctime)s - %(levelname)s - %(message)s")\nlogging.debug("debug msg")\nlogging.info("info msg")\nlogging.warning("warning msg")\nlogger = logging.getLogger(__name__)', keyPoints: ['Levels: DEBUG, INFO, WARNING, ERROR', 'root logger with basicConfig', 'Handlers: FileHandler, StreamHandler', 'Formatter for output format'] })
addC('python', 'File I/O & Exceptions', 'Context Managers (contextlib)', 'Advanced', 'Creating context managers with contextlib utilities for resource management', { codeExample: 'from contextlib import contextmanager\n\n@contextmanager\ndef managed_file(name):\n    f = open(name, "w")\n    try:\n        yield f\n    finally:\n        f.close()\n\nwith managed_file("test.txt") as f:\n    f.write("hello")', keyPoints: ['@contextmanager decorator simplifies __enter__/__exit__', 'yield separates setup from teardown', 'contextlib.suppress, contextlib.redirect_stdout'] })
addC('python', 'Data Structures', 'Counter & OrderedDict', 'Intermediate', 'collections.Counter for counting, OrderedDict for ordered mapping', { codeExample: 'from collections import Counter, OrderedDict\n\nc = Counter("hello world")\nprint(c.most_common(3))\n\nod = OrderedDict()\nod["a"] = 1\nod["b"] = 2\nprint(od)', keyPoints: ['Counter: dict subclass for counting', 'most_common() for sorted results', 'OrderedDict remembers insertion order', 'Python 3.7+ dicts preserve order too'] })
addC('javascript', 'DOM & Browser APIs', 'IntersectionObserver', 'Intermediate', 'Detecting element visibility relative to viewport or ancestor', { codeExample: 'const observer = new IntersectionObserver((entries) => {\n  entries.forEach(entry => {\n    if (entry.isIntersecting) {\n      entry.target.src = entry.target.dataset.src;\n      observer.unobserve(entry.target);\n    }\n  });\n}, { rootMargin: "200px" });\ndocument.querySelectorAll("img[data-src]").forEach(img => observer.observe(img));', keyPoints: ['Lazy loading images', 'Infinite scroll detection', 'rootMargin for pre-loading', 'Better than scroll event listeners'] })
addC('javascript', 'Async JavaScript', 'Event Loop Phases', 'Advanced', 'Understanding microtasks, macrotasks, and execution order in JS', { codeExample: 'console.log("1");\nsetTimeout(() => console.log("2"), 0);\nPromise.resolve().then(() => console.log("3"));\nconsole.log("4");\n// Output: 1, 4, 3, 2', keyPoints: ['Microtasks (Promise.then) before macrotasks', 'setTimeout is macrotask', 'requestAnimationFrame before style/layout', 'Node.js has additional phases (poll, check)'] })
addC('javascript', 'ES6+ Features', 'Template Literals & Tagged Templates', 'Beginner', 'String interpolation with backticks and custom template processing', { codeExample: 'const name = "World";\nconsole.log(`Hello ${name}!`);\n\nfunction highlight(strings, ...values) {\n  return strings.reduce((result, str, i) => result + `<span>${values[i-1]}</span>` + str);\n}\nconst result = highlight`Hello ${name}, you have ${3} messages`;', keyPoints: ['${expr} for interpolation', 'Tagged templates for custom processing', 'Multi-line strings without \\n', 'Raw strings with String.raw'] })
addC('javascript', 'Advanced JavaScript', 'Decorators (Proposal)', 'Advanced', 'Decorators for modifying class members, currently TC39 stage 3', { codeExample: 'function logged(target, context) {\n  const method = target;\n  return function(...args) {\n    console.log(`Calling ${context.name} with`, args);\n    return method.apply(this, args);\n  };\n}\n\nclass Calculator {\n  @logged\n  add(a, b) { return a + b; }\n}', keyPoints: ['Stage 3 TC39 proposal', 'Replaces older Babel decorators', 'Receives target and context', 'Can wrap, replace, or access members'] })
addC('javascript', 'Node.js Basics', 'File System (fs) Module', 'Beginner', 'Working with files: reading, writing, watching, and streaming', { codeExample: 'const fs = require("fs");\n// Read file\nconst data = fs.readFileSync("file.txt", "utf8");\nconst data2 = await fs.promises.readFile("file.txt", "utf8");\n// Write file\nfs.writeFileSync("out.txt", "content");\nawait fs.promises.writeFile("out.txt", "content");\n// Watch file\nfs.watch("file.txt", (event, filename) => console.log(event, filename));', keyPoints: ['fs.readFileSync vs fs.promises.readFile', 'Streams for large files', 'fs.watch for file changes', 'fs.existsSync to check existence'] })
addC('java', 'Core Java', 'Reflection API', 'Advanced', 'Inspecting and manipulating classes at runtime', { codeExample: 'Class<?> clazz = Class.forName("com.example.User");\nMethod[] methods = clazz.getDeclaredMethods();\nField field = clazz.getDeclaredField("name");\nfield.setAccessible(true);\nfield.set(obj, "newName");\nConstructor<?> ctor = clazz.getDeclaredConstructor(String.class);\nObject instance = ctor.newInstance("test");', keyPoints: ['Class.forName() loads class dynamically', 'setAccessible bypasses visibility', 'Used in frameworks (Spring, Hibernate)', 'Performance overhead vs direct calls'] })
addC('java', 'Collections Framework', 'HashMap Internals', 'Intermediate', 'How HashMap works: buckets, collisions, treeification, resizing', { codeExample: '// Internal structure:\n// Array of Node<K,V>[] table (buckets)\n// Each bucket is linked list or red-black tree\n// Default capacity: 16, load factor: 0.75\n// Resize: doubles size when threshold exceeded\n\nMap<String, Integer> map = new HashMap<>();\nmap.put("key", 42);\n// Hash: hash = key.hashCode() ^ (h >>> 16)\n// Index: (n - 1) & hash\n// Collision: chain in linked list\n// Treeify: when list > 8 (Java 8+)\n\n// Initial capacity tuning\nMap<String, String> sized = new HashMap<>(1024, 0.75f);', keyPoints: ['O(1) average, O(log n) worst with trees', 'Load factor controls resizing', 'hashCode() quality affects performance', 'Not thread-safe (use ConcurrentHashMap)'] })
addC('java', 'Concurrency', 'java.util.concurrent Collections', 'Intermediate', 'Thread-safe collections for concurrent access without explicit synchronization', { codeExample: '// ConcurrentHashMap (segmented locking)\nConcurrentHashMap<String, Integer> map = new ConcurrentHashMap<>();\nmap.putIfAbsent("key", 1);\nmap.computeIfAbsent("key", k -> computeExpensive(k));\n\n// CopyOnWriteArrayList (snapshot iteration)\nCopyOnWriteArrayList<String> list = new CopyOnWriteArrayList<>();\n// Thread-safe iteration without ConcurrentModificationException\n\n// BlockingQueue\nBlockingQueue<Runnable> queue = new LinkedBlockingQueue<>(100);\n// put() blocks if full, take() blocks if empty\n\n// ConcurrentLinkedDeque (non-blocking)\nConcurrentLinkedDeque<String> deque = new ConcurrentLinkedDeque<>();', keyPoints: ['ConcurrentHashMap: high concurrency reads', 'CopyOnWriteArrayList: many reads, few writes', 'BlockingQueue: producer-consumer pattern', 'ConcurrentLinkedDeque: lock-free'] })
addC('java', 'Modern Java (8+)', 'Optional', 'Intermediate', 'Container object for possibly null values, reducing NullPointerExceptions', { codeExample: 'Optional<User> user = findUser(id);\nUser result = user.orElse(User.DEFAULT);\nUser result2 = user.orElseGet(() -> createDefault());\nuser.ifPresent(u -> System.out.println(u.getName()));\nUser found = user.orElseThrow(() -> new NotFoundException("User not found"));\nString name = user.map(User::getName).orElse("Unknown");', keyPoints: ['orElse/orElseGet for defaults', 'map/flatMap for chaining', 'filter for conditional', 'Avoid Optional.get() without isPresent() check'] })
addC('java', 'I/O & NIO', 'NIO.2 Channels & Buffers', 'Advanced', 'Non-blocking I/O with channels, buffers, and selectors', { codeExample: '// FileChannel for file I/O\nRandomAccessFile file = new RandomAccessFile("data.txt", "rw");\nFileChannel channel = file.getChannel();\nByteBuffer buffer = ByteBuffer.allocate(1024);\nint bytesRead = channel.read(buffer);\nbuffer.flip();\nwhile (buffer.hasRemaining()) System.out.print((char) buffer.get());\nbuffer.clear();\n\n// SocketChannel (non-blocking)\nSocketChannel socket = SocketChannel.open();\nsocket.configureBlocking(false);\nsocket.connect(new InetSocketAddress("host", 8080));\n\n// Selector for multiplexing\nSelector selector = Selector.open();\nsocket.register(selector, SelectionKey.OP_READ);\nselector.select(); // blocks until ready', keyPoints: ['Channel reads/writes to Buffer', 'Non-blocking mode for scalable I/O', 'Selector multiplexes multiple channels', 'Memory-mapped files with MappedByteBuffer'] })
addC('react', 'Core React', 'Refs (useRef, forwardRef)', 'Intermediate', 'Mutable references for DOM access, instance variables, and forwarded refs', { codeExample: 'function AutoFocus() {\n  const inputRef = useRef(null);\n  useEffect(() => inputRef.current?.focus(), []);\n  return <input ref={inputRef} />;\n}\n\nconst FancyButton = forwardRef((props, ref) => (\n  <button ref={ref} className="fancy">{props.children}</button>\n));\n\nfunction Parent() {\n  const btnRef = useRef(null);\n  return <FancyButton ref={btnRef}>Click</FancyButton>;\n}', keyPoints: ['useRef for DOM access and mutable values', 'forwardRef passes ref to child', 'Refs persist across renders, no re-render on change', 'Avoid overusing refs (prefer state)'] })
addC('react', 'Hooks', 'Custom Hooks', 'Intermediate', 'Extracting component logic into reusable hook functions', { codeExample: 'function useWindowSize() {\n  const [size, setSize] = useState({ width: window.innerWidth, height: window.innerHeight });\n  useEffect(() => {\n    const handler = () => setSize({ width: window.innerWidth, height: window.innerHeight });\n    window.addEventListener("resize", handler);\n    return () => window.removeEventListener("resize", handler);\n  }, []);\n  return size;\n}\n\nfunction App() {\n  const { width, height } = useWindowSize();\n  return <div>Window: {width}x{height}</div>;\n}', keyPoints: ['Hooks start with "use"', 'Compose built-in hooks inside custom hooks', 'Share stateful logic, not state', 'Each hook call has isolated state'] })
addC('react', 'State Management', 'Zustand', 'Intermediate', 'Simple state management with hooks-based API, no boilerplate', { codeExample: 'import { create } from "zustand";\n\nconst useStore = create((set) => ({\n  count: 0,\n  increment: () => set((state) => ({ count: state.count + 1 })),\n  reset: () => set({ count: 0 }),\n}));\n\nfunction Counter() {\n  const count = useStore((state) => state.count);\n  const increment = useStore((state) => state.increment);\n  return <button onClick={increment}>{count}</button>;\n}', keyPoints: ['Minimal boilerplate', 'Selectors prevent unnecessary re-renders', 'Works outside React components', 'Middleware: persist, devtools, immer'] })
addC('react', 'Testing', 'Testing Library (RTL)', 'Intermediate', 'Testing React components with user-centric queries', { codeExample: 'import { render, screen, fireEvent } from "@testing-library/react";\nimport userEvent from "@testing-library/user-event";\n\nit("submits form with name", async () => {\n  render(<UserForm />);\n  const input = screen.getByLabelText(/name/i);\n  await userEvent.type(input, "Alice");\n  fireEvent.click(screen.getByRole("button", { name: /submit/i }));\n  expect(screen.getByText(/success/i)).toBeInTheDocument();\n});', keyPoints: ['Queries by accessibility (getByRole, getByLabelText)', 'userEvent simulates real interactions better', 'Tests from user perspective', 'Avoid testing implementation details'] })
addC('sql', 'Advanced Queries', 'Common Table Expressions (CTE)', 'Intermediate', 'WITH clause for temporary named result sets in complex queries', { codeExample: 'WITH sales_by_region AS (\n  SELECT region, SUM(amount) total\n  FROM orders JOIN stores ON orders.store_id = stores.id\n  GROUP BY region\n),\ntop_regions AS (\n  SELECT region FROM sales_by_region ORDER BY total DESC LIMIT 5\n)\nSELECT * FROM sales_by_region WHERE region IN (SELECT region FROM top_regions);', keyPoints: ['WITH for readability', 'Multiple CTEs separated by commas', 'RECURSIVE for hierarchies', 'Not materialized by default'] })
addC('sql', 'Optimization & Indexing', 'Query Plan Analysis (EXPLAIN)', 'Intermediate', 'Reading execution plans to understand and optimize query performance', { codeExample: 'EXPLAIN SELECT u.name, COUNT(o.id)\nFROM users u LEFT JOIN orders o ON u.id = o.user_id\nWHERE u.created_at > "2024-01-01"\nGROUP BY u.id ORDER BY 2 DESC LIMIT 10;\n\n-- Look for:\n-- Seq Scan on large tables (missing index)\n-- Sort (can use index ordering)\n-- Nested Loop vs Hash Join vs Merge Join\n-- "rows" estimate vs actual\n\nEXPLAIN (ANALYZE, BUFFERS) -- runs the query!\nSELECT * FROM orders WHERE status = "pending";', keyPoints: ['EXPLAIN shows plan without running', 'EXPLAIN ANALYZE runs and shows actual timings', 'Red flags: sequential scans on big tables', 'Compare estimated vs actual rows'] })
addC('sql', 'Design & Schema', 'Database Normalization (1NF-3NF)', 'Intermediate', 'Systematic approach to reducing data redundancy', { codeExample: '-- 1NF: atomic columns, no repeating groups\n-- 2NF: 1NF + no partial dependencies (composite keys)\n-- 3NF: 2NF + no transitive dependencies\n\n-- Before normalization:\n-- orders(id, customer_name, customer_email, product1, product2, product1_qty)\n\n-- After 3NF:\n-- customers(id, name, email)\n-- products(id, name, price)\n-- orders(id, customer_id, order_date)\n-- order_items(id, order_id, product_id, quantity)', keyPoints: ['1NF: atomic values, no arrays', '2NF: full functional dependency on PK', '3NF: no transitive dependency on non-key', 'Denormalize for read-heavy workloads'] })
addC('html', 'Accessibility & SEO', 'ARIA Attributes', 'Intermediate', 'Accessible Rich Internet Applications for enhancing accessibility', { codeExample: '<div role="button" tabindex="0" aria-label="Close dialog" aria-pressed="false">X</div>\n\n<nav aria-label="Main navigation">\n  <ul role="menubar">\n    <li role="none"><a role="menuitem" href="/">Home</a></li>\n  </ul>\n</nav>\n\n<div role="alert" aria-live="assertive">Form submitted successfully</div>\n\n<progress role="progressbar" aria-valuenow="50" aria-valuemin="0" aria-valuemax="100">50%</progress>', keyPoints: ['ARIA supplements HTML semantics', 'First rule: use native HTML elements when possible', 'role, aria-label, aria-labelledby', 'aria-live for dynamic content updates'] })
addC('html', 'Modern HTML Features', 'Dialog Element', 'Intermediate', 'Native dialog/modal with built-in accessibility and focus management', { codeExample: '<dialog id="modal">\n  <form method="dialog">\n    <h2>Confirm</h2>\n    <p>Are you sure?</p>\n    <menu>\n      <button value="cancel">Cancel</button>\n      <button value="confirm">Confirm</button>\n    </menu>\n  </form>\n</dialog>\n\n<script>\n  const modal = document.getElementById("modal");\n  document.querySelector("#open-btn").onclick = () => modal.showModal();\n  modal.addEventListener("close", () => {\n    if (modal.returnValue === "confirm") doAction();\n  });\n</script>\n\n<style>\n  dialog::backdrop { background: rgba(0,0,0,0.5); }\n</style>', keyPoints: ['showModal() opens as modal', 'show() opens as non-modal', '::backdrop pseudo-element for styling', 'Escape key closes by default'] })
addC('css', 'Advanced CSS', 'Container Queries', 'Intermediate', 'Applying styles based on container size rather than viewport size', { codeExample: '.card-container {\n  container-type: inline-size;\n  container-name: card;\n}\n\n@container card (min-width: 400px) {\n  .card {\n    display: grid;\n    grid-template-columns: 1fr 2fr;\n  }\n  .card-title { font-size: 1.5rem; }\n}\n\n@container card (max-width: 399px) {\n  .card { display: block; }\n  .card-title { font-size: 1.2rem; }\n}', keyPoints: ['Component-level responsive design', 'container-type: inline-size/size', 'container-name for targeting', '@container queries like @media'] })
addC('css', 'Styling & Effects', 'CSS Masking & Clipping', 'Intermediate', 'Creating shapes by masking or clipping elements', { codeExample: '.circle-clip {\n  clip-path: circle(50%);\n}\n\n.polygon {\n  clip-path: polygon(50% 0%, 100% 100%, 0% 100%);\n}\n\n.mask-image {\n  mask-image: url(mask.png);\n  mask-size: cover;\n}\n\n.gradient-mask {\n  mask-image: linear-gradient(black 50%, transparent);\n}\n\n.animated-clip {\n  clip-path: inset(0);\n  transition: clip-path 0.3s;\n}\n.animated-clip:hover { clip-path: inset(10%); }', keyPoints: ['clip-path for geometric shapes', 'mask-image for image-based masks', 'Both support animations and transitions', 'GPU-accelerated'] })
addC('git', 'Version Control', 'Hooks (pre-commit, pre-push)', 'Intermediate', 'Scripts that run automatically on Git events for validation', { codeExample: '#!/bin/sh\n# .git/hooks/pre-commit\n# Run linter before commit\nnpm run lint\nif [ $? -ne 0 ]; then\n  echo "Lint failed, commit aborted"\n  exit 1\nfi\n\n# .git/hooks/pre-push\n# Run tests before push\nnpm test\n\n# Skip hooks with --no-verify\ngit commit --no-verify -m "WIP"\n\n# Client-side hooks: pre-commit, prepare-commit-msg, commit-msg, post-commit\n# Server-side: pre-receive, update, post-receive\n\n# Use Husky for managing hooks per project\n# npx husky add .husky/pre-commit "npm test"', keyPoints: ['pre-commit runs before commit message editor', 'pre-push runs before push', 'Exit code non-zero aborts the action', 'Husky manages hooks via package.json'] })
addC('git', 'Advanced Git', 'Submodules', 'Intermediate', 'Including other Git repositories as subdirectories in your project', { codeExample: '# Add submodule\ngit submodule add https://github.com/user/shared-lib.git lib/shared\n\n# Clone repo with submodules\ngit clone --recurse-submodules https://github.com/user/project.git\n\n# Update submodules\ngit submodule update --init --recursive\ngit submodule update --remote  # update to latest commit\n\n# Submodule status\ngit submodule status\n\n# Remove submodule\ngit submodule deinit lib/shared\ngit rm lib/shared\nrm -rf .git/modules/lib/shared\n\n# Alternative: subtree (merges subproject into repo)\ngit subtree add --prefix=lib/shared https://github.com/user/shared-lib.git main', keyPoints: ['Submodule points to specific commit', 'Parent repo tracks submodule commit hash', 'Submodules are separate repos', 'Consider subtree or monorepo as alternatives'] })
addC('docker', 'Containerization', 'Dockerfile Best Practices', 'Intermediate', 'Writing efficient, secure, and maintainable Dockerfiles', { codeExample: '# 1. Use specific tags (not latest)\nFROM node:20-alpine\n\n# 2. Combine RUN commands to reduce layers\nRUN apt-get update && apt-get install -y --no-install-recommends curl && rm -rf /var/lib/apt/lists/*\n\n# 3. Copy package.json separately for layer caching\nCOPY package*.json ./\nRUN npm ci --only=production\n\n# 4. Copy source after deps (cache bust)\nCOPY . .\n\n# 5. Use .dockerignore\n# node_modules, .git, *.md, .env\n\n# 6. Run as non-root\nRUN addgroup -S appgroup && adduser -S appuser -G appgroup\nUSER appuser\n\n# 7. Multi-stage build for smaller images\nFROM node:20-alpine AS builder\nCOPY . .\nRUN npm run build\n\nFROM nginx:alpine\nCOPY --from=builder /app/dist /usr/share/nginx/html\n\n# 8. Add HEALTHCHECK\nHEALTHCHECK CMD curl -f http://localhost:3000 || exit 1', keyPoints: ['Layer caching with order', '.dockerignore prevents context bloat', 'Non-root user for security', 'Multi-stage for minimal images'] })
addC('docker', 'Orchestration & Production', 'Docker Compose Profiles', 'Intermediate', 'Selective service startup with compose profiles', { codeExample: 'services:\n  app:\n    image: myapp:latest\n    ports:\n      - "3000:3000"\n\n  db:\n    image: postgres:15\n    profiles:\n      - dev\n      - staging\n\n  redis:\n    image: redis:alpine\n    profiles:\n      - dev\n\n  monitoring:\n    image: grafana/grafana\n    profiles:\n      - monitoring\n\n# Start only app + dev services\ndocker compose --profile dev up\n\n# Start with multiple profiles\ndocker compose --profile dev --profile monitoring up\n\n# Start specific services without profile\ndocker compose up app', keyPoints: ['Profiles group related services', 'Services without profile always start', 'Combine profiles with --profile flag', 'Useful: dev, staging, monitoring, testing profiles'] })
addC('dsa', 'Data Structures', 'Heap (Priority Queue)', 'Intermediate', 'Complete binary tree where parent is smaller (min-heap) or larger than children', { codeExample: 'class MinHeap {\n  constructor() { this.heap = []; }\n  parent(i) { return Math.floor((i - 1) / 2); }\n  left(i) { return 2 * i + 1; }\n  right(i) { return 2 * i + 2; }\n  push(val) { this.heap.push(val); this.bubbleUp(this.heap.length - 1); }\n  pop() {\n    if (this.heap.length === 1) return this.heap.pop();\n    const root = this.heap[0];\n    this.heap[0] = this.heap.pop();\n    this.sinkDown(0);\n    return root;\n  }\n  bubbleUp(i) {\n    while (i > 0 && this.heap[i] < this.heap[this.parent(i)]) {\n      [this.heap[i], this.heap[this.parent(i)]] = [this.heap[this.parent(i)], this.heap[i]];\n      i = this.parent(i);\n    }\n  }\n  sinkDown(i) {\n    while (this.left(i) < this.heap.length) {\n      let smallest = this.left(i);\n      if (this.right(i) < this.heap.length && this.heap[this.right(i)] < this.heap[smallest]) smallest = this.right(i);\n      if (this.heap[i] <= this.heap[smallest]) break;\n      [this.heap[i], this.heap[smallest]] = [this.heap[smallest], this.heap[i]];\n      i = smallest;\n    }\n  }\n}', keyPoints: ['O(log n) push and pop', 'O(1) peek (root)', 'Used in Dijkstra, Huffman, scheduling', 'JS arrays with manual heapify'] })
addC('dsa', 'Algorithms', 'Binary Search', 'Intermediate', 'Finding element in sorted array by dividing search space in half', { codeExample: 'function binarySearch(arr, target) {\n  let left = 0, right = arr.length - 1;\n  while (left <= right) {\n    const mid = Math.floor((left + right) / 2);\n    if (arr[mid] === target) return mid;\n    if (arr[mid] < target) left = mid + 1;\n    else right = mid - 1;\n  }\n  return -1;\n}\n\n// Lower bound (first >= target)\nfunction lowerBound(arr, target) {\n  let left = 0, right = arr.length;\n  while (left < right) {\n    const mid = Math.floor((left + right) / 2);\n    if (arr[mid] >= target) right = mid;\n    else left = mid + 1;\n  }\n  return left;\n}', keyPoints: ['O(log n) time complexity', 'Array must be sorted', 'left + Math.floor((right-left)/2) avoids overflow', 'Template for search in sorted space'] })
addC('dsa', 'Complexity Analysis', 'Big O Notation', 'Beginner', 'Describing algorithm efficiency as input size grows', { codeExample: '// O(1) - Constant: array access\narr[i]\n\n// O(log n) - Logarithmic: binary search\nwhile (left <= right) mid = Math.floor((left+right)/2)\n\n// O(n) - Linear: single loop\nfor (let i = 0; i < n; i++)\n\n// O(n log n) - Linearithmic: merge sort, quicksort avg\nfunction mergeSort(arr)\n\n// O(n^2) - Quadratic: nested loops\nfor (let i = 0; i < n; i++)\n  for (let j = 0; j < n; j++)\n\n// O(2^n) - Exponential: recursive subsets\nfunction fib(n) { if (n <= 1) return n; return fib(n-1) + fib(n-2); }\n\n// O(n!) - Factorial: permutations\nfunction permute(arr)', keyPoints: ['Describes worst-case growth rate', 'Drop constants and lower order terms', 'Space complexity considers memory', 'Time vs space trade-off common'] })
addC('cpp', 'Core C++', 'Constexpr & Consteval', 'Advanced', 'Compile-time evaluation for performance and safety', { codeExample: '// constexpr: maybe evaluated at compile time\nconstexpr int factorial(int n) {\n    return n <= 1 ? 1 : n * factorial(n - 1);\n}\nstatic_assert(factorial(5) == 120);  // compile-time\n\n// consteval: must be evaluated at compile time (C++20)\nconsteval int square(int n) { return n * n; }\nconstexpr int x = square(5);  // OK\n// int y = square(x);  // OK if x is constexpr, else error\n\n// constexpr vector and string (C++20)\nconstexpr std::vector<int> v = {1, 2, 3};\n\n// if constexpr (compile-time branching)\ntemplate<typename T>\nauto getValue(T t) {\n    if constexpr (std::is_pointer_v<T>) return *t;\n    else return t;\n}', keyPoints: ['constexpr functions can run at compile time', 'if constexpr eliminates dead branches', 'consteval forces compile-time', 'constexpr containers in C++20'] })
addC('cpp', 'Standard Library (STL)', 'Containers Overview (vector, map, set)', 'Intermediate', 'STL container selection guide for different use cases', { codeExample: '#include <vector>\n#include <map>\n#include <set>\n#include <unordered_map>\n\n// vector: dynamic array, contiguous memory\nstd::vector<int> v = {1, 2, 3};\nv.push_back(4);  // O(1) amortized\nv[2];  // O(1) random access\n\n// map: ordered key-value (red-black tree)\nstd::map<std::string, int> ages;\nages["Alice"] = 30;  // O(log n)\n\n// set: ordered unique elements\nstd::set<int> s = {3, 1, 2};  // {1, 2, 3}\n\n// unordered_map: hash table, O(1) average\nstd::unordered_map<std::string, int> um;\num.reserve(1000);  // pre-allocate\n\n// Container adapters\nstd::stack<int> st;  // LIFO\nstd::queue<int> q;   // FIFO\nstd::priority_queue<int> pq;  // max-heap', keyPoints: ['vector: default sequential container', 'map/set: ordered, O(log n)', 'unordered_map/set: O(1) average, requires hash', 'Choose based on access pattern'] })
addC('typescript', 'Type System', 'Enums & Union Types', 'Intermediate', 'Numeric enums, string enums, and discriminated unions', { codeExample: '// Numeric enum\nenum Direction {\n  Up, Down, Left, Right\n}\nconsole.log(Direction.Up);  // 0\nconsole.log(Direction[0]);  // "Up"\n\n// String enum\nenum Color {\n  Red = "RED", Green = "GREEN", Blue = "BLUE"\n}\n\n// Const enum (no runtime code)\nconst enum HttpStatus { OK = 200, NotFound = 404 }\n\n// Discriminated union (preferred over enum in many cases)\ntype Shape =\n  | { kind: "circle"; radius: number }\n  | { kind: "square"; size: number }\n  | { kind: "triangle"; base: number; height: number };\n\nfunction area(s: Shape): number {\n  switch (s.kind) {\n    case "circle": return Math.PI * s.radius ** 2;\n    case "square": return s.size ** 2;\n    case "triangle": return (s.base * s.height) / 2;\n  }\n}', keyPoints: ['Numeric enums auto-increment', 'String enums for meaningful values', 'const enum for zero overhead', 'Discriminated unions with switch exhaustiveness'] })
addC('typescript', 'Tooling & Configuration', 'tsconfig Options (strict, paths)', 'Intermediate', 'Important TypeScript compiler options for type safety', { codeExample: '{\n  "compilerOptions": {\n    // Strict checks\n    "strict": true,  // enables all strict checks\n    "noImplicitAny": true,\n    "strictNullChecks": true,\n    "strictFunctionTypes": true,\n    "strictBindCallApply": true,\n    "noUncheckedIndexedAccess": true,\n    "noImplicitReturns": true,\n    "noFallthroughCasesInSwitch": true,\n\n    // Module resolution\n    "moduleResolution": "node",\n    "baseUrl": ".",\n    "paths": {\n      "@/*": ["src/*"],\n      "@components/*": ["src/components/*"]\n    },\n\n    // Output\n    "target": "ES2022",\n    "module": "ESNext",\n    "outDir": "./dist",\n    "sourceMap": true,\n    "declaration": true\n  },\n  "include": ["src"],\n  "exclude": ["node_modules", "dist"]\n}', keyPoints: ['strict enables best practices', 'paths for clean imports', 'noUncheckedIndexedAccess for safer object access', 'strictNullChecks catches null/undefined errors'] })
addC('go', 'Concurrency', 'Select Statement', 'Intermediate', 'Waiting on multiple channel operations simultaneously', { codeExample: 'func main() {\n    ch1 := make(chan string)\n    ch2 := make(chan string)\n    timeout := time.After(2 * time.Second)\n\n    go func() { time.Sleep(1 * time.Second); ch1 <- "slow" }()\n    go func() { time.Sleep(2 * time.Second); ch2 <- "slower" }()\n\n    select {\n    case msg1 := <-ch1:\n        fmt.Println("Received:", msg1)\n    case msg2 := <-ch2:\n        fmt.Println("Received:", msg2)\n    case <-timeout:\n        fmt.Println("Timeout")\n    default:\n        fmt.Println("No channels ready")\n    }\n}', keyPoints: ['select blocks until one case ready', 'Multiple ready cases chosen at random', 'default for non-blocking', 'nil channel never ready'] })
addC('go', 'Language Features', 'Defer, Panic, Recover', 'Intermediate', 'Deferred function execution, panic for errors, recover for handling', { codeExample: 'func readFile(path string) (data []byte, err error) {\n    f, err := os.Open(path)\n    if err != nil { return nil, err }\n    defer f.Close()  // runs when function returns\n\n    return ioutil.ReadAll(f)\n}\n\n// Panic/Recover example\nfunc safeDivide(a, b int) (result int) {\n    defer func() {\n        if r := recover(); r != nil {\n            log.Println("Recovered:", r)\n            result = 0\n        }\n    }()\n    if b == 0 { panic("division by zero") }\n    return a / b\n}\n\n// Defer order: LIFO\nfunc example() {\n    defer fmt.Println("first")  // runs last\n    defer fmt.Println("second")\n    fmt.Println("hello")\n}\n// Output: hello second first', keyPoints: ['defer for cleanup (close, unlock)', 'panics propagate up the stack', 'recover only useful in deferred functions', 'Defer is LIFO (stack order)'] })
addC('rust', 'Ownership & Borrowing', 'RefCell & Interior Mutability', 'Advanced', 'Runtime borrowing with RefCell for interior mutability pattern', { codeExample: 'use std::cell::RefCell;\n\nstruct Messenger {\n    messages: RefCell<Vec<String>>,\n}\n\nimpl Messenger {\n    fn new() -> Self {\n        Messenger { messages: RefCell::new(vec![]) }\n    }\n    fn send(&self, msg: &str) {\n        self.messages.borrow_mut().push(String::from(msg));\n    }\n    fn count(&self) -> usize {\n        self.messages.borrow().len()\n    }\n}\n\nfn main() {\n    let m = Messenger::new();\n    m.send("hello");\n    m.send("world");\n    println!("{}", m.count());  // 2\n}\n\n// RefCell + Rc for multiple owners with mutation\nuse std::rc::Rc;\nlet shared = Rc::new(RefCell::new(42));\nlet c1 = Rc::clone(&shared);\n*c1.borrow_mut() += 1;\nprintln!("{}", shared.borrow());  // 43', keyPoints: ['borrow()/borrow_mut() at runtime', 'Panics on borrow violation', 'Use with Rc for shared mutable state', 'Prefer Cell for Copy types'] })
addC('rust', 'Language Features', 'Iterators & Closures', 'Intermediate', 'Composing transformations on collections with iterator adapters', { codeExample: 'fn main() {\n    let nums = vec![1, 2, 3, 4, 5, 6];\n\n    // Lazy iterator chain\n    let result: Vec<i32> = nums.iter()\n        .filter(|x| *x % 2 == 0)\n        .map(|x| x * 2)\n        .collect();\n    // result: [4, 8, 12]\n\n    // Closures capturing environment\n    let threshold = 3;\n    let above: Vec<_> = nums.into_iter()\n        .filter(|x| *x > threshold)\n        .collect();\n\n    // Custom iterator\n    struct Fibonacci {\n        curr: u64, next: u64,\n    }\n    impl Iterator for Fibonacci {\n        type Item = u64;\n        fn next(&mut self) -> Option<Self::Item> {\n            let new = self.curr + self.next;\n            self.curr = self.next;\n            self.next = new;\n            Some(self.curr)\n        }\n    }\n    let fib = Fibonacci { curr: 0, next: 1 };\n    let first_10: Vec<_> = fib.take(10).collect();\n}', keyPoints: ['Iterators are lazy (do nothing until consumed)', 'Adapter methods: map, filter, fold, take', 'collect() converts to collection', 'Closures can be Fn, FnMut, or FnOnce'] })
addC('rust', 'Ecosystem', 'Serde for Serialization', 'Intermediate', 'Serializing/deserializing Rust data structures with serde', { codeExample: 'use serde::{Serialize, Deserialize};\n\n#[derive(Serialize, Deserialize, Debug)]\nstruct User {\n    name: String,\n    age: u8,\n    #[serde(rename = "emailAddress")]\n    email: String,\n    #[serde(skip_serializing_if = "Option::is_none")]\n    phone: Option<String>,\n}\n\nfn main() -> Result<(), serde_json::Error> {\n    let user = User {\n        name: String::from("Alice"),\n        age: 30,\n        email: String::from("alice@test.com"),\n        phone: None,\n    };\n\n    let json = serde_json::to_string_pretty(&user)?;\n    println!("{}", json);\n\n    let parsed: User = serde_json::from_str(&json)?;\n    println!("{:?}", parsed);\n\n    // Also: serde_yaml, serde_xml, bincode, etc.\n    Ok(())\n}', keyPoints: ['#[derive(Serialize, Deserialize)] for auto-implementation', 'Attributes for renaming, skipping, defaults', 'serde_json, serde_yaml, bincode backends', 'Zero-cost abstraction'] })
addC('mysql', 'Database Design', 'Stored Procedures', 'Intermediate', 'Server-side SQL routines with parameters and control flow', { codeExample: 'DELIMITER //\nCREATE PROCEDURE GetUsersByStatus(\n    IN status_param VARCHAR(20),\n    OUT user_count INT\n)\nBEGIN\n    SELECT * FROM users WHERE status = status_param ORDER BY created_at DESC;\n    SELECT COUNT(*) INTO user_count FROM users WHERE status = status_param;\nEND //\nDELIMITER ;\n\nCALL GetUsersByStatus("active", @count);\nSELECT @count;\n\n-- Function (returns value)\nCREATE FUNCTION CalculateDiscount(price DECIMAL(10,2))\nRETURNS DECIMAL(10,2)\nDETERMINISTIC\nBEGIN\n    RETURN price * 0.9;\nEND;\n\nSELECT CalculateDiscount(100);', keyPoints: ['IN, OUT, INOUT parameters', 'Control flow: IF, CASE, LOOP, WHILE', 'Stored functions return values', 'Reduces network traffic between app and DB'] })
addC('linux', 'System Administration', 'Package Management (apt, yum)', 'Beginner', 'Installing, updating, and removing packages on Linux', { codeExample: '# Debian/Ubuntu (apt)\nsudo apt update\nsudo apt install nginx\nsudo apt remove nginx\nsudo apt autoremove\nsudo apt search nginx\nsudo apt show nginx\n\n# RHEL/CentOS (yum/dnf)\nsudo yum install nginx\nsudo yum remove nginx\nsudo yum update\nsudo dnf install nginx  # modern Fedora\n\n# Download only (no install)\napt download nginx\nyumdownloader nginx\n\n# List installed packages\ndpkg -l\nyum list installed\n\n# Which package owns a file\ndpkg -S /etc/nginx/nginx.conf\nrpm -qf /etc/nginx/nginx.conf', keyPoints: ['apt for Debian/Ubuntu', 'yum/dnf for RHEL/Fedora', 'Always update package index before install', 'sudo for system-wide operations'] })
addC('linux', 'Shell Scripting', 'Error Handling (set -e, traps)', 'Intermediate', 'Robust shell scripts with error handling and cleanup', { codeExample: '#!/bin/bash\nset -euo pipefail\n\ncleanup() {\n    echo "Cleaning up..."\n    rm -f /tmp/tempfile\n}\ntrap cleanup EXIT\n\ntrap "echo Script interrupted; exit 1" INT TERM\n\n# set -e: exit on error\n# set -u: error on undefined variable\n# set -o pipefail: fail on pipe error\n# set -x: print commands before execution (debug)\n\necho "Starting"\nfalse  # would exit due to -e\necho "This never runs"\n\n# Allow expected failures\nset +e\ncommand_that_might_fail\nset -e\necho "Continuing..."', keyPoints: ['set -euo pipefail for safety', 'trap for cleanup on exit/error', '__rerun_args__ for retry', 'set +e to temporarily allow failures'] })
addC('mongodb', 'CRUD Operations', 'Read Operations (find, sort, project)', 'Beginner', 'Querying documents with filters, sorting, projection, and pagination', { codeExample: 'db.users.find(\n  { age: { $gte: 18, $lte: 65 }, status: "active" },\n  { name: 1, email: 1, _id: 0 }\n).sort({ name: 1 }).skip(20).limit(10)\n\n// Common operators:\n// $eq, $ne, $gt, $gte, $lt, $lte\n// $in, $nin\n// $and, $or, $not, $nor\n// $exists, $type\n// $regex (pattern matching)\n\n// Count documents\ndb.users.countDocuments({ status: "active" })\n\n// Distinct values\ndb.products.distinct("category")\n\n// findOne\ndb.users.findOne({ email: "alice@test.com" })', keyPoints: ['First arg: filter, second: projection', 'sort, skip, limit for pagination', 'Projection 1=include, 0=exclude', 'Indexes speed up queries significantly'] })
addC('c', 'Memory Management', 'Dynamic Arrays (realloc)', 'Intermediate', 'Growing arrays at runtime with realloc for contiguous resizing', { codeExample: '#include <stdio.h>\n#include <stdlib.h>\n\nint main() {\n    int *arr = NULL;\n    int capacity = 0;\n    int count = 0;\n    int val;\n\n    while (scanf("%d", &val) == 1) {\n        if (count >= capacity) {\n            capacity = capacity == 0 ? 4 : capacity * 2;\n            int *temp = realloc(arr, capacity * sizeof(int));\n            if (!temp) { free(arr); return 1; }\n            arr = temp;\n        }\n        arr[count++] = val;\n    }\n\n    for (int i = 0; i < count; i++) {\n        printf("%d ", arr[i]);\n    }\n    printf("\\n");\n\n    free(arr);\n    return 0;\n}', keyPoints: ['realloc extends or shrinks memory', 'May move to new address', 'Always check return value for NULL', 'realloc(NULL, size) = malloc(size)'] })
addC('c', 'I/O & System', 'Standard I/O (printf, scanf, getchar)', 'Beginner', 'Formatted and character I/O in C', { codeExample: '#include <stdio.h>\n\nint main() {\n    // printf format specifiers\n    int n = 42;\n    float f = 3.14159;\n    char c = "A";\n    char str[] = "hello";\n\n    printf("Integer: %d, Hex: %x, Octal: %o\\n", n, n, n);\n    printf("Float: %.2f, Scientific: %e\\n", f, f);\n    printf("Char: %c, String: %s\\n", c, str);\n    printf("Pointer: %p\\n", (void*)&n);\n\n    // scanf\n    int age;\n    char name[50];\n    printf("Enter age and name: ");\n    scanf("%d %49s", &age, name);\n\n    // Character I/O\n    int ch;\n    while ((ch = getchar()) != EOF) {\n        putchar(ch);\n    }\n\n    return 0;\n}', keyPoints: ['%d, %f, %s, %c, %p format specifiers', 'scanf needs & for non-array variables', 'Be careful with buffer overflow in scanf', 'getchar returns int (not char for EOF)'] })
addC('csharp', 'Language Features', 'Pattern Matching', 'Intermediate', 'Expressive pattern matching with switch expressions and property patterns', { codeExample: 'object obj = 42;\nstring result = obj switch\n{\n    int i when i > 0 => $"Positive {i}",\n    int i when i < 0 => $"Negative {i}",\n    0 => "Zero",\n    string s => $"String: {s}",\n    null => "Null",\n    _ => "Unknown"\n};\n\n// Property pattern\ngetDiscount(Customer c) => c switch\n{\n    { IsPremium: true, OrderCount: > 10 } => 0.2m,\n    { IsPremium: true } => 0.15m,\n    { OrderCount: > 5 } => 0.1m,\n    _ => 0.0m\n};\n\n// Tuple pattern\n(Season, bool) GetSpecial(DateTime d) => d.Month switch\n{\n    12 or 1 or 2 => (Season.Winter, true),\n    6 or 7 or 8 => (Season.Summer, d.Day == 4),\n    _ => (Season.Other, false)\n};', keyPoints: ['Switch expressions (-> instead of case)', 'Property patterns for object matching', 'Tuple patterns for multiple values', 'Discard _ for default'] })
addC('csharp', 'Advanced Topics', 'AsyncEnumerable (IAsyncEnumerable)', 'Advanced', 'Asynchronous streaming with await foreach', { codeExample: 'async IAsyncEnumerable<int> GetNumbersAsync()\n{\n    for (int i = 0; i < 10; i++)\n    {\n        await Task.Delay(100);\n        yield return i;\n    }\n}\n\nawait foreach (var num in GetNumbersAsync())\n{\n    Console.WriteLine(num);\n}\n\n// With cancellation\nasync IAsyncEnumerable<int> GetAsync(CancellationToken ct)\n{\n    await foreach (var item in source.WithCancellation(ct))\n    {\n        yield return item;\n    }\n}\n\n// ConfigureAwait\nawait foreach (var item in source.ConfigureAwait(false))', keyPoints: ['yield return with async', 'await foreach for consumption', 'CancellationToken support', 'ConfigureAwait for library code'] })
addC('kotlin', 'Language Features', 'Null Safety', 'Intermediate', 'Kotlin type system eliminates NullPointerException at compile time', { codeExample: 'var name: String = "Alice"  // non-null\n// name = null  // compile error\n\nvar nickname: String? = null  // nullable\nprintln(nickname?.length)  // safe call -> null\nprintln(nickname?.length ?: 0)  // elvis -> 0\nprintln(nickname!!.length)  // not-null assertion (throws if null)\n\n// Smart cast\nif (nickname != null) {\n    println(nickname.length)  // auto-cast to non-null\n}\n\n// let with nullable\nnickname?.let { println("Name: $it") }\n\n// Safe casts\nval x: Any = "hello"\nval y: String? = x as? String  // safe cast, returns null if fails', keyPoints: ['? makes type nullable', '?. safe call operator', '?: Elvis operator for defaults', '!! throws on null (avoid)'] })
addC('kotlin', 'Language Features', 'Flow (Coroutine Flows)', 'Intermediate', 'Cold asynchronous data streams for reactive programming', { codeExample: 'fun fetchUsers(): Flow<User> = flow {\n    val users = api.getUsers()\n    for (user in users) {\n        emit(user)  // emit each user\n    }\n}.flowOn(Dispatchers.IO)  // upstream on IO thread\n\n// Collect\nlifecycleScope.launch {\n    fetchUsers()\n        .catch { e -> println("Error: $e") }\n        .collect { user ->\n            println(user)\n        }\n}\n\n// Operators\nflowOf(1, 2, 3, 4, 5)\n    .map { it * 2 }\n    .filter { it > 5 }\n    .collect { println(it) }\n\n// StateFlow (hot, state holder)\nval state = MutableStateFlow("initial")\nstate.value = "updated"', keyPoints: ['flow builder emits values', 'Operators: map, filter, catch, flatMapConcat', 'flowOn for thread switching', 'StateFlow/SharedFlow for UI state'] })
addC('swift', 'Language Features', 'Error Handling (throws, try, do-catch)', 'Intermediate', 'Structured error handling with error types and propagation', { codeExample: 'enum NetworkError: Error {\n    case badURL\n    case timeout(seconds: Int)\n    case serverError(code: Int, message: String)\n}\n\nfunc fetchUser(id: Int) throws -> User {\n    guard id > 0 else { throw NetworkError.badURL }\n    // ... network call\n    throw NetworkError.timeout(seconds: 30)\n}\n\n// Propagating error\ndo {\n    let user = try fetchUser(id: 42)\n    print(user)\n} catch NetworkError.badURL {\n    print("Invalid URL")\n} catch NetworkError.timeout(let sec) {\n    print("Timed out after \\(sec)s")\n} catch {\n    print("Other error: \\(error)")\n}\n\n// try? (optional, nil on error)\nif let user = try? fetchUser(id: 42) { }\n\n// try! (runtime crash on error)\nlet user = try! fetchUser(id: 42)\n\n// rethrows (function that accepts throwing closure)\nfunc handle<R>(_ fn: () throws -> R) rethrows -> R { try fn() }', keyPoints: ['Error protocol defines throwable types', 'throws on function, try at call site', 'do-catch for handling', 'try? for optional, try! for assert'] })
addC('swift', 'iOS-Specific', 'SwiftUI State Management', 'Intermediate', 'State, Binding, ObservedObject, and StateObject for SwiftUI', { codeExample: 'struct CounterView: View {\n    @State private var count = 0  // local state\n\n    var body: some View {\n        VStack {\n            Text("Count: \\(count)")\n            Button("Increment") { count += 1 }\n        }\n    }\n}\n\n// ObservableObject (reference type)\nclass UserViewModel: ObservableObject {\n    @Published var name = "Alice"\n    @Published var age = 30\n}\n\nstruct ProfileView: View {\n    @StateObject private var vm = UserViewModel()  // owns\n    // @ObservedObject for injected\n\n    var body: some View {\n        Text("\\(vm.name), \\(vm.age)")\n    }\n}\n\n// @Binding (two-way connection)\nstruct EditView: View {\n    @Binding var name: String\n    var body: some View { TextField("Name", text: $name) }\n}', keyPoints: ['@State for local view state', '@StateObject creates observable', '@ObservedObject for injected dependencies', '@Binding for two-way connections'] })
addC('pandas', 'Data Operations', 'Filtering & Conditional Selection', 'Beginner', 'Filtering DataFrames with boolean conditions', { codeExample: 'import pandas as pd\ndf = pd.DataFrame({\n    "name": ["Alice","Bob","Charlie"],\n    "age": [25, 30, 35],\n    "salary": [50000, 60000, 70000]\n})\n\n# Boolean indexing\nfiltered = df[df["age"] > 28]\n\n# Multiple conditions\ndf[(df["age"] > 25) & (df["salary"] > 55000)]\n\n# isin\nfiltered = df[df["name"].isin(["Alice", "Charlie"])]\n\n# String methods\nfiltered = df[df["name"].str.startswith("A")]\n\n# Query (string expression)\ndf.query("age > 28 and salary > 55000")\n\n# Between\ndf[df["age"].between(25, 32)]', keyPoints: ['Condition inside brackets for filtering', 'Use & | ~ for and/or/not, not and/or/not', 'isin for membership check', 'query for string expression syntax'] })
addC('pandas', 'Data Operations', 'Apply & Vectorized Operations', 'Intermediate', 'Applying functions with apply, map, and vectorized operations', { codeExample: 'df = pd.DataFrame({"a": [1, 2, 3], "b": [4, 5, 6]})\n\n# Vectorized (fastest)\ndf["c"] = df["a"] * 2 + df["b"]\n\n# apply on column\ndf["a"].apply(lambda x: x ** 2)\n\n# apply on DataFrame (row-wise)\ndf.apply(lambda row: row["a"] + row["b"], axis=1)\n\n# map for Series\ndf["a"].map({1: "one", 2: "two", 3: "three"})\n\n# applymap (element-wise, deprecated for map)\ndf.map(lambda x: str(x))  # pandas 2.1+\n\n# transform (same shape as input)\ndf.groupby("category")["value"].transform("mean")\n\n# pipe for method chaining\n(df.pipe(clean)\n    .pipe(transform)\n    .pipe(validate))', keyPoints: ['Vectorized ops are fastest', 'apply is flexible but slower', 'map for Series element-wise', 'transform for groupby same-shape results'] })
addC('security', 'Cryptography', 'Hashing vs Encryption', 'Beginner', 'Difference between one-way hashing and reversible encryption', { codeExample: '# Hashing (one-way, for passwords, integrity)\nimport hashlib\nhash = hashlib.sha256(b"password").hexdigest()\n# Use bcrypt/argon2 for passwords\nimport bcrypt\nhashed = bcrypt.hashpw(b"password", bcrypt.gensalt())\nbcrypt.checkpw(b"password", hashed)  # True\n\n# Encryption (reversible)\nfrom cryptography.fernet import Fernet\nkey = Fernet.generate_key()\ncipher = Fernet(key)\nencrypted = cipher.encrypt(b"secret data")\ndecrypted = cipher.decrypt(encrypted)\n\n# Key differences:\n# Hash: deterministic, cannot reverse, fixed length\n# Encrypt: reversible with key, output same length as input\n# Hashing: integrity verification\n# Encryption: confidentiality', keyPoints: ['Hashes are one-way (can\'t reverse)', 'Encryption is two-way (decrypt with key)', 'Use bcrypt/argon2/scrypt for passwords', 'Encryption: AES (symmetric), RSA (asymmetric)'] })
addC('security', 'Network Security', 'TLS/SSL Handshake', 'Intermediate', 'How TLS establishes encrypted connections between client and server', { codeExample: 'TLS 1.3 Handshake:\n1. ClientHello: TLS version, cipher suites, key share\n2. ServerHello: chosen cipher suite, server key share, certificate\n3. Server finishes: CertificateVerify + Finished\n4. Client finishes: CertificateVerify + Finished\n5. Encrypted data exchange\n\n# Key concepts:\n# - Asymmetric crypto for key exchange (ECDHE)\n# - Digital certificates prove server identity\n# - Session tickets for resumption (0-RTT)\n# - Perfect forward secrecy with ephemeral keys\n\n# Tools:\n# openssl s_client -connect example.com:443 -tls1_3\n# curl -v https://example.com\n# ssllabs.com/ssltest for grading\n\n# Certificate chain:\n# Root CA -> Intermediate CA -> Server cert\n# Each cert signed by the next level up', keyPoints: ['TLS 1.3: 1-RTT (0-RTT for resumed)', 'Certificate chain validation', 'Cipher suites: TLS_AES_256_GCM_SHA384', 'Perfect forward secrecy via ECDHE'] })
addC('dbms', 'Data Modeling', 'Entity-Relationship (ER) Modeling', 'Beginner', 'Conceptual data modeling with entities, attributes, and relationships', { codeExample: '-- Conceptual ER Model\n-- Entity: Customer(id, name, email, phone)\n-- Entity: Order(id, date, total, customer_id)\n-- Relationship: Customer 1---* Order (one-to-many)\n\n-- Converting to relational schema:\nCREATE TABLE customers (\n    id INT PRIMARY KEY AUTO_INCREMENT,\n    name VARCHAR(100) NOT NULL,\n    email VARCHAR(255) UNIQUE NOT NULL,\n    phone VARCHAR(20)\n);\n\nCREATE TABLE orders (\n    id INT PRIMARY KEY AUTO_INCREMENT,\n    order_date DATE NOT NULL,\n    total DECIMAL(10,2) NOT NULL,\n    customer_id INT NOT NULL,\n    FOREIGN KEY (customer_id) REFERENCES customers(id)\n);\n\n-- Relationship types:\n-- 1:1 (one-to-one): Person --- Passport\n-- 1:N (one-to-many): Customer --- Orders\n-- M:N (many-to-many): Student --- Course (via enrollment table)', keyPoints: ['Entities become tables, attributes become columns', 'Primary keys uniquely identify rows', 'Foreign keys implement relationships', 'Many-to-many requires junction table'] })
addC('dbms', 'Transactions & Concurrency', 'Isolation Levels', 'Intermediate', 'Defining how transaction changes are visible to other transactions', { codeExample: 'SET TRANSACTION ISOLATION LEVEL READ UNCOMMITTED;\n-- Problems: dirty reads, non-repeatable reads, phantoms\n\nSET TRANSACTION ISOLATION LEVEL READ COMMITTED;\n-- Prevents: dirty reads\n-- Allows: non-repeatable reads, phantoms\n\nSET TRANSACTION ISOLATION LEVEL REPEATABLE READ;\n-- Prevents: dirty reads, non-repeatable reads\n-- Allows: phantoms (MySQL default)\n\nSET TRANSACTION ISOLATION LEVEL SERIALIZABLE;\n-- Prevents: all (dirty, non-repeatable, phantom)\n-- Worst concurrency, range locks\n\n-- Snapshot Isolation (MVCC-based)\n-- Readers see snapshot at transaction start\n-- Writers dont block readers\n-- Used by PostgreSQL, Oracle, SQL Server', keyPoints: ['Lower isolation = higher concurrency, more anomalies', 'Dirty read: read uncommitted data', 'Non-repeatable read: same row changes between reads', 'Phantom: new rows appear between reads'] })
addC('oop', 'Principles', 'Encapsulation', 'Beginner', 'Bundling data and methods, restricting direct access to internal state', { codeExample: 'class BankAccount {\n  #balance;  // private field (ES2022)\n  constructor(initial) { this.#balance = initial; }\n  getBalance() { return this.#balance; }\n  deposit(amount) {\n    if (amount <= 0) throw new Error("Invalid");\n    this.#balance += amount;\n  }\n  withdraw(amount) {\n    if (amount > this.#balance) throw new Error("Insufficient");\n    this.#balance -= amount;\n  }\n}\n\nconst acc = new BankAccount(1000);\nacc.deposit(500);\n// acc.#balance  // SyntaxError!\nconsole.log(acc.getBalance());  // 1500', keyPoints: ['Private fields hide internal state', 'Public methods provide controlled access', 'Reduces coupling and complexity', 'Supports invariants (validation)'] })
addC('oop', 'Principles', 'Abstraction', 'Beginner', 'Hiding complex implementation details behind simple interfaces', { codeExample: '// Abstract class (Java)\nabstract class Database {\n    abstract void connect();\n    abstract void query(String sql);\n    abstract void disconnect();\n    \n    public void executeQuery(String sql) {\n        connect();\n        query(sql);\n        disconnect();\n    }\n}\n\nclass MySQLDatabase extends Database {\n    void connect() { /* MySQL-specific connection */ }\n    void query(String sql) { /* MySQL query execution */ }\n    void disconnect() { /* MySQL cleanup */ }\n}\n\n// Usage\nDatabase db = new MySQLDatabase();\ndb.executeQuery("SELECT * FROM users");\n// User doesn\'t need to know about MySQL details', keyPoints: ['Focus on what, not how', 'Abstract classes define contracts', 'Interfaces provide pure abstraction', 'Reduces complexity for callers'] })
addC('os', 'Processes & Threads', 'Inter-Process Communication (IPC)', 'Intermediate', 'Mechanisms for processes to communicate: pipes, shared memory, sockets', { codeExample: '// Pipes (unidirectional)\npipe(fd);  // fd[0] read, fd[1] write\nwrite(fd[1], "hello", 5);\nread(fd[0], buf, 5);\n\n// Named pipes (FIFO)\nmkfifo("myfifo", 0666);\n// Process A: write(fd, "data", 4);\n// Process B: read(fd, buf, 4);\n\n// Shared memory (POSIX)\nshm_fd = shm_open("/myshm", O_CREAT | O_RDWR, 0666);\nftruncate(shm_fd, 4096);\nptr = mmap(0, 4096, PROT_WRITE, MAP_SHARED, shm_fd, 0);\nsprintf(ptr, "shared data");\n\n// Message queues (POSIX)\nmqd_t mq = mq_open("/myqueue", O_CREAT | O_WRONLY, 0644, NULL);\nmq_send(mq, "hello", 5, 0);\n\n// Sockets (bidirectional, network capable)\nint sock = socket(AF_UNIX, SOCK_STREAM, 0);', keyPoints: ['Pipes: parent-child communication', 'Shared memory: fastest, needs sync', 'Message queues: structured messages', 'Sockets: network-capable IPC'] })
addC('os', 'Storage', 'File System Types (NTFS, ext4, FAT)', 'Intermediate', 'Comparison of file system features across platforms', { codeExample: 'NTFS (Windows):\n- Journaling: logs changes before commit\n- ACL: fine-grained permissions per file\n- Compression, encryption (EFS)\n- Max file size: 16 EB\n- Max filename: 255 chars\n\next4 (Linux):\n- Journaling\n- Extents for large files\n- Delayed allocation\n- Max file size: 16 TB\n- Max filename: 255 bytes\n\nFAT32 (compatible):\n- No journaling\n- Max file size: 4 GB\n- Max volume: 2 TB\n- No permissions\n- Max filename: 8.3 chars\n\nexFAT:\n- No journaling\n- Max file size: 16 EB\n- Good for USB drives, SD cards', keyPoints: ['NTFS: journaling, permissions, Windows', 'ext4: journaling, Linux default', 'FAT32: universal but limited', 'exFAT: modern cross-platform for removable media'] })
addC('networks', 'Application Layer', 'REST API Design Principles', 'Intermediate', 'Designing RESTful APIs with proper resource naming and HTTP methods', { codeExample: 'GET    /users          # List users\nGET    /users/:id      # Get single user\nPOST   /users          # Create user\nPUT    /users/:id      # Replace user\nPATCH  /users/:id      # Partial update\nDELETE /users/:id      # Delete user\n\nGET    /users/:id/orders    # User orders (sub-resource)\nGET    /users/:id/orders/:oid  # Specific order\n\n# Status codes\n200 OK\n201 Created (POST)\n204 No Content (DELETE)\n400 Bad Request\n401 Unauthorized\n403 Forbidden\n404 Not Found\n409 Conflict\n422 Unprocessable Entity\n500 Internal Server Error\n\n# Pagination\nGET /users?page=1&limit=20\nLink: <https://api.com/users?page=2>; rel="next"\n\n# Versioning\n/api/v1/users\nAccept: application/vnd.api+json; version=1', keyPoints: ['Resources as nouns, not verbs', 'HTTP methods as actions', 'Proper status codes', 'Pagination, filtering, sorting'] })
addC('networks', 'Application Layer', 'gRPC Basics', 'Intermediate', 'High-performance RPC framework using Protocol Buffers and HTTP/2', { codeExample: '// service.proto\nservice UserService {\n  rpc GetUser (GetUserRequest) returns (User);\n  rpc ListUsers (ListRequest) returns (stream User);\n  rpc UpdateUsers (stream User) returns (UpdateSummary);\n  rpc Chat (stream ChatMsg) returns (stream ChatMsg);\n}\n\nmessage User {\n  int32 id = 1;\n  string name = 2;\n  string email = 3;\n}\n\nmessage GetUserRequest { int32 id = 1; }\n\n// Key features:\n// - HTTP/2 multiplexing\n// - Binary protocol (small, fast)\n// - Strong typing via .proto\n// - Built-in streaming\n// - Code generation for many languages\n\n// gRPC vs REST:\n// Binary vs Text (JSON)\n// HTTP/2 vs HTTP/1.1\n// Strongly typed vs flexible\n// Streaming vs request/response', keyPoints: ['Protocol Buffers for serialization', 'HTTP/2 for multiplexing', 'Unary, server-streaming, client-streaming, bidirectional', 'Generated client/server stubs'] })
addC('system-design', 'Architecture', 'Event-Driven Architecture', 'Intermediate', 'Asynchronous communication via events for decoupled microservices', { codeExample: '// Event-driven vs Request-driven\n\n// Request-driven (synchronous):\n// Order Service -> POST /payment -> Payment Service\n// Order Service -> POST /inventory -> Inventory Service\n// Order Service -> POST /notification -> Notification Service\n// - Tight coupling, cascade failures\n// - Latency = sum of all services\n\n// Event-driven (asynchronous):\n// Order Service -> publish OrderPlaced event\n// Payment Service -> subscribe to OrderPlaced\n// Inventory Service -> subscribe to OrderPlaced\n// Notification Service -> subscribe to OrderPlaced\n// - Loose coupling\n// - Each service processes independently\n// - Eventual consistency\n\n// Event types:\n// - Domain events (meaningful in business)\n// - Integration events (between services)\n// - Event sourcing (persist events as truth)\n\n// Brokers:\n// Kafka: durable, replayable, high throughput\n// RabbitMQ: flexible routing, reliable\n// AWS SNS/SQS: managed pub/sub + queues', keyPoints: ['Decoupled services via events', 'Eventual consistency model', 'Kafka for high-throughput event streaming', 'Sagas for coordinating distributed transactions'] })
addC('system-design', 'Architecture', 'CQRS (Command Query Responsibility Segregation)', 'Advanced', 'Separating read and write models for optimized query performance', { codeExample: '// CQRS separates commands (writes) from queries (reads)\n\n// Command Model (for writes):\n// - Handles CREATE, UPDATE, DELETE\n// - Domain logic + validation\n// - Writes to write database (normalized)\nclass CreateOrderHandler {\n  handle(command) {\n    // Validate, apply domain logic\n    // Write to orders_write DB\n    // Publish OrderCreated event\n  }\n}\n\n// Query Model (for reads):\n// - Handles SELECT, GET operations\n// - Optimized denormalized projections\n// - Reads from read database (denormalized)\nclass GetOrderQueryHandler {\n  handle(query) {\n    // Directly return denormalized data\n    // No domain logic, just data retrieval\n  }\n}\n\n// Sync between models:\n// - Eventual consistency via events\n// - Event bus: write -> event -> sync -> read\n// - Can use different DB types per model\n\n// When to use:\n// - Complex domain logic\n// - Different read/write performance needs\n// - Reporting queries on transactional data\n// Not for: CRUD apps without complex logic', keyPoints: ['Separate read/write models', 'Optimize read model for queries', 'Eventual consistency between models', 'Event bus keeps models in sync'] })
